    {2143,"Unholy Empowerment",136194,2,0,2,{"wago"},"A Wailing Guardsman attempts to empower Commander Springvale. If the spell is successfully cast, Commander Springvale is healed for $93844s2% of his maximum health and gains one charge of Unholy Power.",2,0,0,64,98,2144,6,2142,0},
    {2144,"Screams of the Past",136164,2,0,2,{"wago"},"The Wailing Guardman emits a terrible scream, interrupting nearby enemy spellcasting within $7074A1 yards. Interrupted enemies cannot cast spells of the same spell school for $7074d.",2,0,0,0,98,2145,7,2142,0},
    {2145,"Mortal Strike",132355,2,0,2,{"wago"},"The Wailing Guardsman instantly attacks his enemy, inflicting $91801s1% of their normal weapon damage and leaving the enemy wounded. This mortal wound reduces the effectiveness of any healing on the target by $91801s2%.",2,0,0,0,98,0,8,2142,0},
