    {2147,"Unholy Empowerment",136194,2,0,2,{"wago"},"A Tormented Officer attempts to empower Commander Springvale. If the spell is successfully cast, Commander Springvale is healed for $93844s2% of his maximum health and gains one charge of Unholy Power.",2,0,0,64,98,2148,10,2146,0},
    {2148,"Shield Wall",132362,2,0,2,{"wago"},"When a Tormented Officer is below 20% health, he will raise his shield defensively. This reduces all damage taken by $91463s1% for $91463d.",2,0,0,0,98,2149,11,2146,0},
