    {2899,"Stage One: Welcome to the Great Show!",0,0,0,3,{"wago"},"Jin'do fights players alone, dropping Deadzones on the ground to protect himself and calling upon the Spirit of Hakkar to empower his weapon with shadow lightning.",-2,2900,0,0,185,2902,1,0,0},
