    {3127,"Stage Two: We Will Handle Them!",0,0,0,1,{"wago"},"Once either Feludius or Ignacious reaches 25% health, both Councillors retreat. Arion and Terrastra then descend from above to carry on the fight.",-1,3128,0,0,158,3144,21,0,0},
    {3128,"Arion",0,0,0,0,{"wago"},"Ascendant Councillor of Air",-1,3129,0,0,158,3135,22,3127,0},
    {3129,"Call Winds",136018,2,0,0,{"wago"},"Arion focuses and agitates the nearby air into a violent cyclone. This cyclone wanders randomly around the room for $83491d before dissipating.  The cyclones knock upwards any player who touches them and inflict the Swirling Winds effect on that player.",-1,3152,0,0,158,3130,23,3128,0},
    {3130,"Thundershock",136050,2,0,0,{"wago"},"Arion unleashes a massive electrical storm that fills the room with crackling lightning, inflicting $83067s1 Nature damage to all players. Players with the Grounded effect take greatly reduced damage.",-1,0,0,32,158,3131,25,3128,0},
    {3131,"Lightning Rod",237443,2,0,0,{"wago"},"Arion marks a random player as a target for a forthcoming Chain Lightning attack.$[!4,6\n\n\n\nIn 25 player raids Arion marks three random players as targets.$]",-1,3132,0,0,158,3133,26,3128,0},
    {3132,"Chain Lightning",136015,2,0,0,{"wago"},"Arion fires an arcing pulse of lightning at all players marked as Lightning Rods, inflicting $83282s1 Nature damage and bouncing to additional nearby players within 15 yards. The damage inflicted by Chain Lightning increases as the pulse bounces to additional players.",-1,0,0,0,158,0,27,3131,0},
    {3133,"Disperse",132845,2,0,0,{"wago"},"Arion dissolves into swirling wind and materializes elsewhere in the room, then casts Lightning Blast.",-1,3134,0,1,158,0,28,3128,0},
