    {3213,"Corrupting Crash",136181,2,0,0,{"wago"},"The Corrupting Adherent lobs a shadow missile at the ground beneath a random player, inflicting $81689s1 Shadow damage to all players within $81689a1 yards of the impact. Players hit by the Corrupting Crash gain Corruption.",-1,0,0,0,167,3214,18,3161,0},
    {3214,"Spilled Blood of the Old God",252178,2,0,0,{"wago"},"When Cho'gall casts Fester Blood, corpses of Corrupting Adherents dissolve into pools of black bile. Any players in contact with these pools suffer $81761s1 Shadow damage per $81757t1 sec. and gain Corruption.",-1,0,0,0,167,0,19,3161,0},
    {3215,"Festering Blood",136123,2,0,0,{"wago"},"When Cho'gall uses Fester Blood, the dark blood of any living Corrupting Adherents sprays out from their bodies, inflicting $82919s1 Shadow damage every $82914t1 sec to all players within $82919A1 yards.  Players damaged by this ability will gain Corruption.",-1,0,0,0,167,3216,21,3163,0},
