    {4091,"Drain Essence",136169,2,0,2,{"wago"},"At 60% remaining health, Peroth'arn stuns all enemies and inflicts Shadow damage every second for $104905d.",-2,0,0,0,290,4092,5,0,0},
    {4092,"The Eyes of Peroth'arn",0,0,0,3,{"wago"},"After Illidan interrupts Drain Essence, Peroth'arn returns to the shadows to ambush the heroes. Peroth'arn unleashes his Eyes of Peroth'arn to search for the players. Players gain the protection of their Shadowcloaks to help them avoid the detection range of the Eyes.\n\n\n\nIf players avoid detection for 40 seconds, Peroth'arn becomes visible and weakened with the Enfeebled effect.\n\n\n\nIf an Eye of Peroth'arn discovers a player, Peroth'arn marks the player with Easy Prey, leaps out of the shadows, and attacks the discovered player.",-2,4225,0,32,290,4100,6,0,0},
    {4100,"Endless Frenzy",132344,2,0,2,{"wago"},"At 20% remaining health, Peroth'arn frenzies and increases his damage by $105521s1%.",-2,0,0,0,290,0,10,0,0},
    {4102,"Cataclysm",575535,2,0,0,{"wago"},"Deathwing attempts to finish the job he started by bringing forth a second Cataclysm, inflicting $%106523s1 Fire damage to all players.",-1,0,0,16,333,4106,3,4040,0},
    {4103,"Blistering Tentacle",0,1,0,0,{"wago"},"At 75%, 50%, and 25% remaining health the Limb Tentacle sprouts several Blistering Tentacles that are immune to Area of Effect abilities.",-1,4104,39347,0,333,4105,15,4038,0},
    {4104,"Blistering Heat",236305,2,0,0,{"wago"},"The Blistering Heat inflicts $%105445s1 Fire damage every $105444t1 sec, and increases its damage by $105445s2% for $105445d. This effect stacks.",-1,0,0,0,333,0,16,4103,0},
    {4105,"Agonizing Pain",135860,2,0,0,{"wago"},"The pain from severing Deathwing's limb interrupts his concentration, stunning him and inflicting $106548s1% of his health in damage.",-1,0,0,0,333,0,17,4038,0},
    {4106,"Elementium Bolt",135821,2,0,0,{"wago"},"Deathwing creates an Elementium Bolt, sending it to the target platform.",-1,4107,0,0,333,4347,4,4040,0},
