    {6280,"Sik'thik Swarmer",0,1,0,0,{"wago"},"Lightly armored and well trained, the Sik'thik Swarmers are a key part of the Vo'jak's forces.",-1,0,42193,0,738,6281,4,6279,0},
    {6281,"Sik'thik Amberwing",0,1,0,0,{"wago"},"The Sik'thik Amberwing flies to the top of the platform and bombards the players.",-1,6289,43955,0,738,6282,5,6279,0},
