    {6285,"Rising Speed",460953,2,0,0,{"wago"},"Commander Vo'jak focuses his will and determination, increasing his attack speed by $120758s1% every $120757t sec. This effect stacks.",-1,0,0,0,738,6286,11,6284,0},
    {6286,"Dashing Strike",132337,2,0,0,{"wago"},"Commander Vo'jak charges a random enemy player, inflicting $120807m1 Physical damage to all enemies passed through. The Strike also knocks back his current target, inflicting an additional $120800m2 Physical damage.",-1,0,0,0,738,6287,12,6284,0},
    {6287,"Thousand Blades",132369,2,0,0,{"wago"},"Immediately after using Dashing Strike, Commander Vo'jak begins to spin around and send blades outward, inflicting Physical damage to all targets within $120760A1 yards.\n\n\n\nThousand Blades also removes the Caustic Tar effect.",-1,0,0,0,738,0,13,6284,0},
