    {6290,"Unstable Blast",136173,2,0,1,{"wago"},"The Sik'thik Demolisher carries unstable explosives and explodes when damaged or killed, inflicting $121981m1 to all targets within $121981A1 yards.",-1,0,0,32,738,0,8,6282,0},
