    {6320,"Unstable Sha",0,1,0,0,{"wago"},"Unstable Sha appear around Tsulong and then move towards him, inflicting massive Shadow damage to Tsulong if they reach him.",-1,6321,41677,0,742,6323,12,6315,0},
    {6321,"Unstable Bolt",136181,2,0,0,{"wago"},"The Unstable Sha unleashes shadowy energy at a random player, inflicting $122881s1 Shadow damage on the target. The Unstable Bolt also damages the Unstable Sha for $122907s1% of its maximum health.",-1,0,0,0,742,6322,13,6320,0},
