    {7178,"Stage One: Thunderstruck!",0,0,0,1,{"wago"},"Lei Shen equips his Axe, Thunder, which he can throw with deadly accuracy and cause lightning to strike the ground wherever it lands. Lei Shen will charge any Conduit that he is near.",-1,7179,0,0,832,7186,8,0,0},
