    {7677,"Gore",132141,2,0,0,{"wago"},"The Ferocious Rhino gores a player, inflicting Physical damage and additional Physical damage every second for $48130d.",-1,0,0,0,642,7678,5,7671,0},
    {7678,"Stomp",132368,2,0,0,{"wago"},"The Ferocious Rhino stomps the ground, inflicting Physical damage to all players within $48131A1 yards, stunning them for $48131d.",-1,0,0,0,642,0,6,7671,0},
    {7679,"Mortal Wound",132109,2,0,0,{"wago"},"The Frenzied Worgen mortally wounds a player, inflicting Physical damage and reducing the effectiveness of all healing received by $48137s2% for $48137d. This effect stacks up to $48137U times.",-1,0,0,0,642,7680,8,7672,0},
