    {7687,"Chain Lightning",136015,2,0,0,{"wago"},"The Ravenous Furbolg strikes a player with a bolt of lightning that arcs to another nearby player, inflicting Nature damage to each of them. Chain Lightning can affect up to $48140x1 targets.",-1,0,0,0,642,0,18,7674,0},
    {7688,"Withering Roar",132091,2,0,0,{"wago"},"Gortok Palehoof unleashes a roar, inflicting Physical damage to all players and lowering their maximum health. This effect lasts for $48256d., and stacks up to $48256U times.",-1,0,0,0,642,7689,20,7675,0},
