    {7693,"Harpoon Launcher",514302,2,0,0,{"wago"},"Players who possess a harpoon can use the Harpoon Launchers found near Grauf to inflict Physical damage to him when he is within range of the launcher.\n\n\n\nHarpoons are obtained by killing Ymirjar Harpooners.",-1,0,0,0,643,7694,3,7691,0},
