    {7857,"Primal Nutriment",655706,2,0,0,{"wago"},"Successfully catching one of Ji-Kun's food globules mid-air increases the player's damage by $140741s2% and healing by $140741s1% for $140741d. Primal Nutriment increases damage and healing by an additional 10% each time it is applied, up to a maximum of 200%.",-1,0,0,0,828,0,18,7354,0},
    {7858,"Mind Daggers",610679,2,0,0,{"wago"},"Any currently active eyes other than the Cross-Eye will inflict $139107s1 Arcane damage to random players in the raid.\n\n\n\n$[!3,5 In 10-Player difficulties 1 player is chosen at random.$]$[!4,6,7 In 25-Player difficulties 3 players are chosen at random.$]",-1,0,0,4,818,0,8,6882,0},
