    {7861,"Frozen Resilience",132123,2,0,2,{"wago"},"Dam'ren is protected with a sheen of ice which reflects $135144s2% of damage taken back at the attacker.",15,0,0,0,817,7862,23,6867,0},
    {7862,"Frozen Resilience",132123,2,0,2,{"wago"},"Dam'ren is protected with a sheen of ice which reflects $135144s3% of damage taken back at the attacker.",16,0,0,0,817,6915,24,6867,0},
