    {8123,"Rend",132155,2,0,0,{"wago"},"Viciously rends a player, causing them to bleed for $144304s1 Physical damage every $144304t1 sec. for $144304d. This effect stacks.",-1,0,0,0,856,0,9,8121,0},
    {8124,"Totems",0,0,0,0,{"wago"},"The Dark Shaman will drop Totems during the fight that grant them new abilities.",-1,8125,0,0,856,8128,10,0,0},
