    {8359,"Lightweight Crate of Goods",0,0,0,0,{"wago"},"These small crates of goods carry front-line enemy forces. A small amount of Titan Energy fuels their creation and can be defeated with fewer players.",-1,8434,0,0,870,8366,39,0,0},
    {8360,"Animated Stone Mogu",0,1,0,0,{"wago"},nil,-1,8379,48814,0,870,8361,41,8434,0},
    {8361,"Burial Urn",0,1,0,0,{"wago"},nil,-1,8380,48872,0,870,8362,44,8434,0},
