    {9373,"Cruelfang's Swiftness",930077,2,161294,1,{"wago"},nil,-1,0,0,32,1122,0,15,9301,0},
    {9374,"Dreadwing's Flame",943739,2,161291,1,{"wago"},nil,-1,0,0,32,1122,0,21,9302,0},
