    {9707,"Overview",0,3,0,0,{"wago"},"At 60% health, Nitrogg Thundertower retreats to his Assault Cannon at the far end of the train car. Players must reclaim Blackrock Munitions from soldiers that pour into the area, and use them destroy Nitrogg's cannon, after which they may dispatch Nitrogg directly.",-1,10326,0,0,1163,10620,1,0,0},
    {9708,"Blackrock Munitions",0,0,0,1,{"wago"},"Defeated Blackrock weapons specialists will leave behind munitions, which players may picked up and use against Nitrogg and his soldiers.",-1,9710,0,0,1163,9713,11,0,0},
