    {9975,"Crumbling Roar",348539,2,173192,0,{"wago"},nil,-1,0,0,0,1161,9687,6,0,0},
    {9976,"Overview",0,3,0,1,{"wago"},"Brackenspore emerges from the infested waters beneath the cliffs of Highmaul, spreading fungal growth that will engulf the beach if left unchecked. Players must use available Flamethrowers to keep Creeping Moss in check, while defeating hostile fungi that Brackenspore creates in his wake.",-1,9977,0,0,1196,9982,1,0,0},
    {9977,"Tanks",0,3,0,1,{"wago"},"$bullet;Grab the attention of Fungal Flesh-Eaters as they stream in from the sea.\n\n$bullet;Interrupt |cFF2959D3|Hspell:160013|h[Decay]|h|r which is cast by the Fungal Flesh-Eaters.",-1,0,0,1,1196,9979,2,9976,0},
    {9978,"Healers",0,3,0,1,{"wago"},"$bullet;Heal friendly mushrooms to full to gain their effects. Once they are healed to full they will begin to wither and die at an increasing rate. Keep them healed in order to maintain their beneficial effects.\n\n$bullet;Heal Living Mushrooms to full to gain |cFF2959D3|Hspell:159463|h[Living Spores]|h|r in order to survive the damage caused by |cFF2959D3|Hspell:163242|h[Infesting Spores]|h|r.",-1,0,0,4,1196,0,4,9976,0},
    {9979,"Damage Dealers",0,3,0,1,{"wago"},"$bullet;Interrupt |cFF2959D3|Hspell:160013|h[Decay]|h|r which is cast by the Fungal Flesh-Eaters.\n\n$bullet;Intercept the damage from |cFF2959D3|Hspell:160180|h[Spore Shot]|h|r away from other players, to avoid splashing the damage.",-1,0,0,2,1196,9978,3,9976,0},
    {9980,"Blackfuse Company 9000",0,0,0,0,{"wago"},"Players may use this weapon to burn away Creeping Moss.",-1,9981,0,0,1196,0,27,0,0},
