    {10088,"Tectonic Upheaval",0,2,162475,0,{"wago"},nil,-1,0,0,0,1195,0,27,10064,0},
    {10089,"Environmental Threats",0,0,0,0,{"wago"},"The battle takes place admist an active Blackrock processing line, which poses many dangers to the unaware player.",-1,9851,0,32,1155,9857,5,0,0},
    {10090,"Overview",0,3,0,0,{"wago"},"Witherbark grows increasingly dehydrated as he attacks the group, consuming his stores of Aqueous Energy. When his Energy is depleted, he roots himself in the soil and calls globules of water from the nearby lake to restore his vitality. Players may destroy those Globules before they reach him to prolong this phase.",-1,10091,0,0,1214,10095,1,0,0},
    {10091,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Lead |cFF2959D3|Hspell:164294|h[Unchecked Growth]|h|r away from your allies.\n\n$bullet;Destroy Aqueous Globules before they can reach Witherbark.",-1,0,0,2,1214,10092,2,10090,0},
    {10092,"Healers",0,3,0,0,{"wago"},"$bullet;Lead |cFF2959D3|Hspell:164294|h[Unchecked Growth]|h|r away from your allies.\n\n$bullet;|cFF2959D3|Hspell:164538|h[Aqueous Burst]|h|r inflicts damage to all party members when a globule is killed.",-1,0,0,4,1214,10093,3,10090,0},
    {10093,"Tanks",0,3,0,0,{"wago"},"$bullet;Face Witherbark away from players during |cFF2959D3|Hspell:164357|h[Parched Gasp]|h|r.\n\n$bullet;Position Witherbark so that Aqueous Globules are unlikely to pass over |cFF2959D3|Hspell:164294|h[Unchecked Growth]|h|r.\n\n$bullet;Be prepared to pick up and tank any |cFF2959D3|Hspell:164556|h[Unchecked Growth]|h|r that animate.",-1,0,0,1,1214,0,4,10090,0},
    {10095,"Brittle Bark",443393,2,164275,0,{"wago"},nil,-1,0,0,0,1214,10096,5,0,0},
    {10096,"Parched Gasp",796638,2,164357,0,{"wago"},nil,-1,0,0,0,1214,10097,6,0,0},
    {10097,"Unchecked Growth",136030,2,164294,1,{"wago"},"$[!2\n\nIn Heroic difficulty, Witherbark can continue to cast Unchecked Growth even while affected by Brittle Bark.$]",-1,10098,0,0,1214,10599,7,0,0},
    {10098,"Unchecked Growth",0,1,0,1,{"wago"},"When touched by the life giving power of an Aqueous Globule, the Unchecked Growth uproots itself and attacks nearby players.",-1,0,28531,32,1214,0,8,10097,0},
    {10100,"Aqueous Globules",893777,0,0,0,{"wago"},"Spheres of pure water form from the nearby lake and move in a line towards Witherbark. Each Aqueous Globule that reaches Witherbark restores 25 Energy.",-1,10101,0,0,1214,0,10,0,0},
    {10101,"Aqueous Burst",893779,2,164538,0,{"wago"},nil,-1,0,0,0,1214,0,11,10100,0},
    {10102,"Overview",0,3,0,0,{"wago"},"Azzakel alternates between engaging players directly in combat and summoning reinforcements from the demon world Argus. While summoning reinforcements, Azzakel cannot be attacked and players should focus on quickly defeating the reinforcements that emerge from the portal, so that they are not overwhelmed as more demons invade.",-1,10103,0,0,1216,10119,1,0,0},
    {10103,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Do not stand too close to Blazing Tricksters to avoid |cFF2959D3|Hspell:154018|h[Conflagration]|h|r.\n\n$bullet;Interrupt |cFF2959D3|Hspell:154221|h[Felblast]|h|r or kill Cackling Pyromaniacs before they finish casting it.\n\n$bullet;Do not stand near other players while affected by |cFF2959D3|Hspell153396|h[Curtain of Flame]|h|r.",-1,0,0,2,1216,10104,2,10102,0},
    {10104,"Healers",0,3,0,0,{"wago"},"$bullet;Do not stand too close to Blazing Tricksters to avoid |cFF2959D3|Hspell:154018|h[Conflagration]|h|r.\n\n$bullet;Do not stand near other players while affected by |cFF2959D3|Hspell153396|h[Curtain of Flame]|h|r.",-1,0,0,4,1216,10105,3,10102,0},
    {10105,"Tanks",0,3,0,0,{"wago"},"$bullet;The Felguards summoned while Azzakel channels |cFF2959D3|Hspell:153764|h[Claws of Argus]|h|r inflict heavy melee damage and must be tanked.\n\n$bullet;Do not stand near players affected by |cFF2959D3|Hspell153396|h[Curtain of Flame]|h|r.\n\n$bullet;Do not stand too close to Blazing Tricksters to avoid |cFF2959D3|Hspell:154018|h[Conflagration]|h|r.",-1,0,0,1,1216,0,4,10102,0},
    {10119,"Azzakel",0,1,0,1,{"wago"},nil,-1,10120,52964,0,1216,0,5,0,0},
    {10120,"Fel Lash",0,2,153234,0,{"wago"},nil,-1,0,0,1,1216,10121,6,10119,0},
    {10121,"Curtain of Flame",0,2,153396,0,{"wago"},nil,-1,0,0,16,1216,10122,7,10119,0},
    {10122,"Claws of Argus",0,2,153764,1,{"wago"},nil,-1,10123,0,0,1216,10129,8,10119,0},
    {10123,"Blazing Trickster",0,1,0,0,{"wago"},nil,-1,10126,53112,0,1216,10125,9,10122,0},
