    {10491,"Section 1",0,2,169218,0,{"wago"},nil,-1,0,0,16,1209,10493,13,10492,0},
    {10492,"Toxic Spiderling",0,1,0,0,{"wago"},nil,-1,10491,283,0,1209,10502,12,0,0},
    {10493,"Section 2",0,2,169224,0,{"wago"},nil,-1,0,0,32,1209,0,14,10492,0},
