    {10659,"Overview",0,3,0,0,{"wago"},"The massive magnaron smashes the earth, causing a horde of goren to burrow up from beneath the earth and sow chaos among his foes.",-1,10737,0,0,1291,10653,1,0,0},
    {10660,"Section 18",0,2,427512,0,{"wago"},"$[!8,23\n\n\n\nOn Mythic difficulty, globs of Noxious Discharge are also launched toward all other players.$]",-1,28163,0,1,1207,0,14,10417,0},
