    {10669,"Section 9",0,2,176004,0,{"wago"},nil,-1,0,0,128,1211,0,13,0,0},
    {10670,"Overview",0,3,0,0,{"wago"},"Tarlna attacks players with |cFF2959D3|Hspell:175973|h[Colossal Blow]|h|r and |cFF2959D3|Hspell:176001|h[Savage Vines]|h|r.\n\n\n\nHe will periodically summon sproutlings and grow them into Giant Lashers with |cFF2959D3|Hspell:175979|h[Genesis]|h|r.",-1,10671,0,0,1211,10661,1,0,0},
    {10671,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Quickly defeat Untamed Mandragoras to prevent them from overwhelming your group.\n\n$bullet;|cFF2959D3|Hspell:175986|h[Trample]|h|r sprouting lashers before |cFF2959D3|Hspell:175979|h[Genesis]|h|r completes to prevent Giant Lashers from spawning.",-1,0,0,2,1211,10672,2,10670,0},
    {10672,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:175973|h[Colossal Blow]|h|r inflicts heavy group-wide damage.\n\n$bullet;|cFF2959D3|Hspell:176001|h[Savage Vines]|h|r root players in place.",-1,0,0,4,1211,10673,3,10670,0},
    {10673,"Tanks",0,3,0,0,{"wago"},"$bullet;Untamed Madragora and Giant Lashers spawn periodically and must be tanked.\n\n$bullet;|cFF2959D3|Hspell:175973|h[Colossal Blow]|h|r inflicts lethal damage to enemies in front of Tarlna.",-1,0,0,1,1211,0,4,10670,0},
    {10674,"Section 25",0,2,161029,0,{"wago"},nil,-1,0,0,0,1155,10675,23,9860,0},
