    {11163,"Ancient Harbinger",0,1,0,0,{"wago"},"At 60% health, Tyrant Velhari calls forth an Ancient Harbinger to assist her in combat.",-1,11177,62472,0,1394,0,24,11158,0},
    {11165,"Section 25",0,2,180025,0,{"wago"},nil,-1,0,0,192,1394,11722,26,11163,0},
    {11166,"Stage Three: Malice",0,0,0,0,{"wago"},nil,-1,11167,0,0,1394,0,28,0,0},
    {11167,"Aura of Malice",0,2,179991,1,{"wago"},nil,-1,0,0,32,1394,11168,29,11166,0},
    {11168,"Bulwark of the Tyrant",0,2,180600,0,{"wago"},nil,-1,11175,0,0,1394,11169,30,11166,0},
    {11169,"Gavel of the Tyrant",0,2,180608,0,{"wago"},nil,-1,0,0,0,1394,11170,32,11166,0},
    {11170,"Ancient Sovereign",0,1,0,0,{"wago"},"At 30% health, Tyrant Velhari calls forth an Ancient Sovereign to assist her in combat.",-1,11178,62473,0,1394,0,33,11166,0},
    {11172,"Section 27",0,2,180040,0,{"wago"},nil,-1,0,0,0,1394,0,35,11170,0},
