    {11583,"Section 11",0,2,183864,0,{"wago"},nil,-1,0,0,0,1438,0,11,11582,0},
    {11585,"Demonic Art: Desecration",0,0,0,1,{"wago"},"When Archimonde reaches 85% health remaining, he summons corruption that erupts from the ground.",-1,11586,0,0,1438,0,12,11577,0},
    {11586,"Section 14",0,2,185590,0,{"wago"},nil,-1,0,0,0,1438,11588,13,11585,0},
