    {11748,"Overview",0,3,0,1,{"wago"},"At 66% and 33% health remaining, Supreme Lord Kazzak summons Twisted Reflections from players. Any Twisted Reflections that reach Supreme Lord Kazzak heal him significantly.",-1,11749,0,0,1452,11752,1,0,0},
    {11749,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Stay away from allies when afflicted with |cFF2959D3|Hspell:187667|h[Mark of Kazzak]|h|r!\n\n$bullet;Avoid being in front of Supreme Lord Kazzak to avoid damage from |cFF2959D3|Hspell:187664|h[Fel Breath]|h|r.\n\n$bullet;When Supreme Lord Kazzak reaches 66% and 33% health, kill the |cFF2959D3|Hspell:187702|h[Twisted Reflections]|h|r.",-1,0,0,2,1452,11750,2,11748,0},
    {11750,"Healers",0,3,0,0,{"wago"},"$bullet;Stay away from allies when afflicted with |cFF2959D3|Hspell:187667|h[Mark of Kazzak]|h|r!\n\n$bullet;Avoid being in front of Supreme Lord Kazzak to avoid damage from |cFF2959D3|Hspell:187664|h[Fel Breath]|h|r.\n\n$bullet;Heal allies to full that are afflicted with |cFF2959D3|Hspell:187466|h[Supreme Doom]|h|r.",-1,0,0,4,1452,11751,3,11748,0},
    {11751,"Tanks",0,3,0,0,{"wago"},"$bullet;Facing Supreme Lord Kazzak away from your allies to avoid damage from |cFF2959D3|Hspell:187664|h[Fel Breath]|h|r.\n\n$bullet;Stay away from allies when afflicted with |cFF2959D3|Hspell:187667|h[Mark of Kazzak]|h|r!\n\n$bullet;When Supreme Lord Kazzak reaches 66% and 33% health, kill the |cFF2959D3|Hspell:187702|h[Twisted Reflections]|h|r.",-1,0,0,1,1452,0,4,11748,0},
