    {12075,"Demon Form: Havoc",0,0,0,0,{"wago"},"Tirathon metamorphoses into a Havoc demon. He gains the ability to focus his hatred as a beam of fel energy and he periodically Immolates the entire party.",-1,12082,0,0,1467,12080,11,0,0},
    {12077,"Section 11",0,2,190836,0,{"wago"},nil,-1,0,0,0,1467,12081,13,12075,0},
    {12080,"Demon Form: Vengeance",0,0,0,0,{"wago"},"Tirathon metamorphoses into a Vengeance demon. He looses his glaives to fly about the arena with a Fel Chain between them. In addition, Furious Blast is replaced with Fel Mortar.",-1,12083,0,0,1467,0,15,0,0},
