    {12128,"Overview",0,3,0,0,{"wago"},"God-King Skovald battles the party for control of the Aegis of Aggramar. Players may wrest the Aegis from Skovald's grasp, and use it to defend against his ultimate attacks.",-1,12129,0,0,1488,13774,1,0,0},
    {12129,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid standing too close to allies while Skovald casts |cFF2959D3|Hspell:193660|h[Felblaze Rush]|h|r.\n\n$bullet;Rely on the protective shield of the |cFF2959D3|Hspell:193765|h[Aegis of Aggramar]|h|r to survive |cFF2959D3|Hspell:193827|h[Ragnarok]|h|r.",-1,0,0,2,1488,12130,2,12128,0},
