    {12144,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Be aware of the knockback from |cFF2959D3|Hspell:193977|h[Winds of Northrend]|h|r.\n\n$bullet;Move away from Ymiron to avoid |cFF2959D3|Hspell:193364|h[Screams of the Dead]|h|r.",1,0,0,2,1502,13898,2,12143,0},
