    {12187,"Overview",0,3,0,0,{"wago"},"Corstilax guards the Nightwell breach, attempting to limit players' exposure to |cFF2959D3|Hspell:195362|h[Nightwell Energy]|h|r. Players must free their allies from |cFF2959D3|Hspell:195791|h[Quarantine]|h|r and avoid direct damage from |cFF2959D3|Hspell:196070|h[Suppression Protocol]|h|r.",-1,12188,0,0,1498,12191,1,0,0},
    {12188,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:195362|h[Nightwell Energy]|h|r significantly increases haste but will cause |cFF2959D3|Hspell:196115|h[Cleansing Force]|h|r to stun you.",-1,0,0,2,1498,12189,2,12187,0},
    {12189,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:196070|h[Suppression Protocol]|h|r inflicts moderate group wide damage.",-1,0,0,4,1498,12190,3,12187,0},
    {12190,"Tanks",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:196142|h[Exterminate]|h|r inflicts heavy damage and stuns players within $196142A1 yards when |cFF2959D3|Hspell:196115|h[Cleansing Force]|h|r ends if they have |cFF2959D3|Hspell:195362|h[Nightwell Energy]|h|r.",-1,0,0,1,1498,0,4,12187,0},
