    {12207,"Overview",0,3,0,0,{"wago"},"Harbaron calls upon soul magic to wreak havok on players, fragmenting their soul into pieces or summoning fallen Vrykul minions.",-1,12208,0,0,1512,12214,1,0,0},
    {12208,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Interrupt |cFF2959D3|Hspell:194266|h[Void Snap]|h|r and defeat summoned Shackled Servitors.\n\n$bullet;Defeat Soul Fragments created by |cFF2959D3|Hspell:194325|h[Fragment]|h|r.",-1,0,0,2,1512,12209,2,12207,0},
