    {12238,"Overview",0,3,0,0,{"wago"},"The Amalgam of Souls battles players until reaching 50% health, at which point it ruptures, splitting into the tortured souls of the Ravencrest ancestors.",-1,12239,0,0,1518,12241,1,0,0},
    {12239,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Keep moving and avoid other players while afflicted with |cFF2959D3|Hspell:194960|h[Soul Echoes]|h|r.\n\n$bullet;When targeted by |cFF2959D3|Hspell:195254|h[Swirling Scythe]|h|r or |cFF2959D3|Hspell:196916|h[Glaive Toss]|h|r, move to avoid placing it in an inconvenient location.",-1,0,0,2,1518,12240,2,12238,0},
    {12240,"Healer",0,3,0,0,{"wago"},"$bullet;Keep moving and avoid other players while afflicted with |cFF2959D3|Hspell:194960|h[Soul Echoes]|h|r.\n\n$bullet;When targeted by |cFF2959D3|Hspell:195254|h[Swirling Scythe]|h|r or |cFF2959D3|Hspell:196916|h[Glaive Toss]|h|r, move to avoid placing it in an inconvenient location.\n\n$bullet;|cFF2959D3|Hspell:194956|h[Reap Soul]|h|r will deal high damage to the tank if it hits.",-1,0,0,4,1518,12246,3,12238,0},
