    {12284,"Overview",0,3,0,0,{"wago"},"Fenryr leaps and shreds his enemies, eventually retreating to his den after becoming wounded.",-1,12285,0,0,1487,12289,1,0,0},
    {12285,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid standing near allies targeted with |cFF2959D3|Hspell:196495|h[Ravenous Leap]|h|r.\n\n$bullet;Run away from Fenryr when affected with |cFF2959D3|Hspell:196838|h[Scent of Blood]|h|r.\n\n$bullet;Melee damage dealers should help split the damage of |cFF2959D3|Hspell:196512|h[Claw Frenzy]|h|r.",-1,0,0,2,1487,12286,2,12284,0},
    {12286,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid standing near allies targeted with |cFF2959D3|Hspell:196495|h[Ravenous Leap]|h|r.\n\n$bullet;Run away from Fenryr when affected with |cFF2959D3|Hspell:196838|h[Scent of Blood]|h|r.",-1,0,0,4,1487,12287,3,12284,0},
