    {12293,"Overview",0,3,0,0,{"wago"},"Archdruid Glaidalis is a master shapeshifter, transforming into bear and cat forms with ease as he calls down corrupted starshards to bombard his foes.",-1,12294,0,0,1654,12427,1,0,0},
    {12294,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid being in front of Archdruid Glaidalis when he is casting |cFF2959D3|Hspell:198360|h[Primal Rampage]|h|r.",-1,0,0,2,1654,12295,2,12293,0},
    {12295,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid being in front of Archdruid Glaidalis when he is casting |cFF2959D3|Hspell:198360|h[Primal Rampage]|h|r.\n\n$bullet;Quickly heal targets affected by |cFF2959D3|Hspell:196376|h[Grevious Tear]|h|r to above 90% of their maximum health.",-1,0,0,4,1654,12296,3,12293,0},
    {12296,"Tanks",0,3,0,0,{"wago"},"$bullet;Position Archdruid Glaidalis so that |cFF2959D3|Hspell:198360|h[Primal Rampage]|h|r does not run over other players.",-1,0,0,1,1654,0,4,12293,0},
    {12298,"Debilitating Fixation",237566,2,196348,0,{"wago"},nil,-1,12395,0,4,1654,0,8,0,0},
    {12299,"Overview",0,3,0,0,{"wago"},"Oakheart is a devastating brute that pummels the players with powerful physical attacks and |cFF2959D3|Hspell:204667|h[Nightmare Breath]|h|r. Beware the |cFF2959D3|Hspell:199051|h[Strangling Roots]|h|r erupting from the ground during the fight.",-1,12300,0,0,1655,12303,1,0,0},
    {12300,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Avoid being in front of Oakheart when he is casting |cFF2959D3|Hspell:204667|h[Nightmare Breath]|h|r.",-1,0,0,2,1655,12301,2,12299,0},
    {12301,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid being in front of Oakheart when he is casting |cFF2959D3|Hspell:204667|h[Nightmare Breath]|h|r.\n\n$bullet;|cFF2959D3|Hspell:204611|h[Crushing Grip]|h|r deals significant damage.",-1,0,0,4,1655,12302,3,12299,0},
    {12302,"Tanks",0,3,0,0,{"wago"},"$bullet;Face Oakheart away from allies so allies are not hit by |cFF2959D3|Hspell:204667|h[Nightmare Breath]|h|r.\n\n$bullet;|cFF2959D3|Hspell:204611|h[Crushing Grip]|h|r deals significant damage.",-1,0,0,1,1655,0,4,12299,0},
    {12303,"Oakheart",0,1,0,1,{"wago"},nil,-1,13084,68127,0,1655,0,5,0,0},
    {12307,"Overview",0,3,0,0,{"wago"},"Dresaron engages the players amidst of a clutch of corrupted dragon eggs. Occasionally during the fight Dresaron will use |cFF2959D3|Hspell:199345|h[Down Draft]|h|r to push the players back into the eggs, spawning whelplings.",-1,12308,0,0,1656,12311,1,0,0},
    {12308,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid disturbing Nightmare Eggs and triggering |cFF2959D3|Hspell:199313|h[Hatch Whelpling]|h|r.",-1,0,0,2,1656,12309,2,12307,0},
