    {12331,"Overview",0,3,0,0,{"wago"},"Odyn challenges players to honorable combat. When a player would die, they are instead removed from the fight by Odyn's val'kyr. Upon being reduced to 80% of his life, Odyn is convince of players' worth and ends the fight.",-1,12332,0,0,1489,13986,1,0,0},
    {12332,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;When affected by |cFF2959D3|Hspell:197961|h[Runic Brand]|h|r look at the floor and run to the matching rune.\n\n$bullet;Avoid |cFF2959D3|Hspell:198072|h[Spear of Light]|h|r and |cFF2959D3|Hspell:198088|h[Glowing Fragments]|h|r.\n\n$bullet;Run away from Odyn to avoid |cFF2959D3|Hspell:198263|h[Radiant Tempest]|h|r.",-1,0,0,2,1489,12333,2,12331,0},
    {12333,"Healers",0,3,0,0,{"wago"},"$bullet;When affected by |cFF2959D3|Hspell:197961|h[Runic Brand]|h|r look at the floor and run to the matching rune.\n\n$bullet;Avoid |cFF2959D3|Hspell:198072|h[Spear of Light]|h|r and |cFF2959D3|Hspell:198088|h[Glowing Fragments]|h|r.\n\n$bullet;Run away from Odyn to avoid |cFF2959D3|Hspell:198263|h[Radiant Tempest]|h|r.",-1,0,0,4,1489,12334,3,12331,0},
