    {12430,"Call of the Felbat",0,0,0,0,{"wago"},"Smashspite calls down a Felbat. The frequency of this ability increases as the encounter continues.",-1,12431,0,0,1664,0,10,0,0},
    {12431,"Section 10",0,2,198446,0,{"wago"},nil,-1,12432,0,0,1664,0,11,12430,0},
    {12432,"Section 11",0,2,198501,0,{"wago"},nil,-1,0,0,0,1664,0,12,12431,0},
    {12433,"Overview",0,3,0,1,{"wago"},"Ularogg Cragshaper summons Bellowing Idols that cause |cFF2959D3|Hspell:193267|h[Falling Debris]|h|r to damage the party until destroyed. \n\n\n\nThroughout the fight, Ularogg hides himself inside a Bellowing Idol during |cFF2959D3|Hspell:198510|h[Stance of the Mountain]|h|r, inflicting increasing damage until the idol hiding Ularogg is destroyed.",-1,12434,0,0,1665,12438,1,0,0},
    {12434,"Damage Dealers",0,3,0,1,{"wago"},"$bullet;Destroy Bellowing Idols to stop damage from |cFF2959D3|Hspell:193267|h[Falling Debris]|h|r.",-1,0,0,2,1665,12435,2,12433,0},
    {12435,"Healers",0,3,0,1,{"wago"},"$bullet;Damage to the party increases the longer |cFF2959D3|Hspell:198510|h[Stance of the Mountain]|h|r lasts.\n\n$bullet;Ularogg inflicts massive damage to the tank with his |cFF2959D3|Hspell:198496|h[Sunder]|h|r ability.",-1,0,0,4,1665,12436,3,12433,0},
    {12436,"Tanks",0,3,0,1,{"wago"},"$bullet;Ularogg inflicts massive damage with his |cFF2959D3|Hspell:198496|h[Sunder]|h|r ability.",-1,0,0,1,1665,0,4,12433,0},
    {12438,"Section 6",0,2,198510,0,{"wago"},nil,-1,0,0,32,1665,12439,5,0,0},
