    {12440,"Bellowing Idols",0,1,0,0,{"wago"},"Idols that cause falling debris to damage the party.",-1,12441,64690,0,1665,0,7,12439,0},
    {12441,"Section 9",0,2,193267,0,{"wago"},nil,-1,0,0,0,1665,0,8,12440,0},
