    {12445,"Section 1",0,2,197776,0,{"wago"},nil,-1,13271,0,0,1499,12486,5,0,0},
    {12459,"Overview",0,3,0,0,{"wago"},"Ursoc tramples his enemies with |cFF2959D3|Hspell:198109|h[Barreling Impact]|h|r and periodically roars for a |cFF2959D3|Hspell:197969|h[Roaring Cacophany]|h|r.$[!16\n\n\n\nIn Mythic difficulty, Nightmare Images periodically animate and attack players.$]",-1,12460,0,0,1667,12463,1,0,0},
    {12460,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;When not afflicted with |cFF2959D3|Hspell:198108|h[Momentum]|h|r, stand in Ursoc's path when he uses |cFF2959D3|Hspell:198006|h[Focused Gaze]|h|r to reduce the amount of damage |cFF2959D3|Hspell:198109|h[Barreling Impact]|h|r inflicts.\n\n$bullet;Get as far away from Ursoc as possible when the target of |cFF2959D3|Hspell:198006|h[Focused Gaze]|h|r to reduce the damage taken from |cFF2959D3|Hspell:199237|h[Trampling Slam]|h|r.",-1,0,0,2,1667,12461,2,12459,0},
    {12461,"Healers",0,3,0,0,{"wago"},"$bullet;When not afflicted with |cFF2959D3|Hspell:198108|h[Momentum]|h|r, stand in Ursoc's path when he uses |cFF2959D3|Hspell:198006|h[Focused Gaze]|h|r to reduce the amount of damage |cFF2959D3|Hspell:198109|h[Barreling Impact]|h|r inflicts.\n\n$bullet;Get as far away from Ursoc as possible when the target of |cFF2959D3|Hspell:198006|h[Focused Gaze]|h|r to reduce the damage taken from |cFF2959D3|Hspell:199237|h[Trampling Slam]|h|r.",-1,0,0,4,1667,13886,3,12459,0},
    {12462,"Tanks",0,3,0,2,{"wago"},"$bullet;Ensure that no tank overlaps the effects of both |cFF2959D3|Hspell:197943|h[Overwhelm]|h|r and |cFF2959D3|Hspell:197942|h[Rend Flesh]|h|r at the same time, taunting when necessary.\n\n$bullet;Switch off which tank holds Ursoc's attention for |cFF2959D3|Hspell:197943|h[Overwhelm]|h|r and |cFF2959D3|Hspell:197942|h[Rend Flesh]|h|r each time he charges.",0,0,0,1,1667,0,5,12459,0},
    {12463,"Section 6",0,2,197943,0,{"wago"},nil,-1,0,0,1,1667,12464,6,0,0},
