    {12575,"Overview",0,3,0,0,{"wago"},"Mindflayer Kaahrj attacks the party with his Shadow Crash and Hysteria spells. At 80% and 40% health, Mindflayer Kaahrj casts Eternal Darkness, ushering in a swathe of Faceless Tendrils to repeatedly damage party members.",-1,12576,0,0,1686,12579,1,0,0},
    {12576,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:197783|h[Shadow Crash]|h|r.\n\n$bullet;Defeat Faceless Tendrils summoned by |cFF2959D3|Hspell:201153|h[Eternal Darkness]|h|r.",-1,0,0,2,1686,12577,2,12575,0},
    {12577,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:197783|h[Shadow Crash]|h|r.\n\n$bullet;Be aware that tanks take significant damage from |cFF2959D3|Hspell:201148|h[Doom]|h|r.",-1,0,0,4,1686,12578,3,12575,0},
    {12578,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:197783|h[Shadow Crash]|h|r.\n\n$bullet;|cFF2959D3|Hspell:201148|h[Doom]|h|r inflicts significant damage.",-1,0,0,1,1686,0,4,12575,0},
