    {12607,"Overview",0,3,0,0,{"wago"},"Once released from her magical prison cell, Millificent Manastorm uses her technological gadgets to overpower her enemies.",-1,12608,0,0,1688,12612,1,0,0},
    {12608,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Disarm the |cFF2959D3|Hspell:201240|h[Elementium Squirrel Bombs]|h|r so that they don't explode.\n\n$bullet;Destroy the unarmored |cFF2959D3|Hspell:201392|h[Thorium Rocket Chickens]|h|r to prevent them from overwhelming the party with rockets.",-1,0,0,2,1688,12609,2,12607,0},
    {12609,"Healers",0,3,0,0,{"wago"},"$bullet;Disarm the |cFF2959D3|Hspell:201240|h[Elementium Squirrel Bombs]|h|r so that they don't explode.\n\n$bullet;Avoid |cFF2959D3|Hspell:201369|h[Rocket Chicken Rockets]|h|r to prevent being knocked around.",-1,0,0,4,1688,12610,3,12607,0},
    {12610,"Tanks",0,3,0,0,{"wago"},"$bullet;Disarm the |cFF2959D3|Hspell:201240|h[Elementium Squirrel Bombs]|h|r so that they don't explode.\n\n$bullet;Destroy the unarmored |cFF2959D3|Hspell:201392|h[Thorium Rocket Chickens]|h|r to prevent them from overwhelming the party with rockets.",-1,0,0,1,1688,0,4,12607,0},
