    {12649,"Section 10",0,2,201715,0,{"wago"},"$[!2,23\n\n\n\nIn Heroic or Mythic difficulty, each Congealed Goo that is consumed removes 20 energy from Festerface.$]",-1,0,0,0,1693,12650,10,12644,0},
