    {12682,"Spitting Scarab",0,1,0,0,{"wago"},nil,-1,12683,12151,0,1696,0,8,12681,0},
    {12683,"Section 9",0,2,202300,0,{"wago"},nil,-1,0,0,0,1696,0,9,12682,0},
    {12684,"Blistering Beetle",0,1,0,2,{"wago"},"On Heroic difficulty, Blistering Beetles will burrow into the fight, fixating on nearby players. When they come into contact with a player or die, they will explode, creating a pool of Blistering Ooze.",2,12685,35106,8,1696,0,10,0,0},
