    {12686,"Gaseous Explosion",893778,2,0,2,{"wago"},"The erupting Gaseous Bubble inflicts Frost damage to all enemies equal to the absorb shield amount remaining on Gaseous Bubbles.",2,0,0,24,1491,0,8,12170,0},
