    {12692,"Overview",0,3,0,0,{"wago"},"Nal'tira weakens her enemies and attempts to draw them into her |cFF2959D3|Hspell:200227|h[Tangled Web]|h|r.",-1,12693,0,0,1500,12687,1,0,0},
    {12693,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:200024|h[Nether Venom]|h|r pools.\n\n$bullet;Break |cFF2959D3|Hspell:200227|h[Tangled Web]|h|r by moving away from the player you are tethered to.",-1,0,0,2,1500,12694,2,12692,0},
    {12694,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:200024|h[Nether Venom]|h|r pools.\n\n$bullet;Break |cFF2959D3|Hspell:200227|h[Tangled Web]|h|r by moving away from the player you are tethered to.",-1,0,0,4,1500,12695,3,12692,0},
    {12695,"Tanks",0,3,0,0,{"wago"},"$bullet;Break |cFF2959D3|Hspell:200227|h[Tangled Web]|h|r by moving away from the player you are tethered to.",-1,0,0,1,1500,0,4,12692,0},
    {12696,"Overview",0,3,0,0,{"wago"},"Sael'orn pulls her enemies close to her while attacking them with viscious short ranged attacks. Periodically, her invulnerable phase spider guardians join the fight, attacking enemies foolish enough to turn their backs.",-1,12697,0,0,1697,12700,1,0,0},
    {12697,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Face any Phase Spider that targets you with |cFF2959D3|Hspell:202306|h[Creeping Slaughter]|h|r to stop them from approaching.",-1,0,0,2,1697,12698,2,12696,0},
