    {12749,"Eternal Hunger",0,2,203462,2,{"wago"},nil,2,0,0,8,1702,0,14,12748,0},
    {12750,"Overview",0,3,0,0,{"wago"},"Advisor Vandros uses the power of the Nightwell to influence time. He frequently summons |cFF2959D3|Hspell:203254|h[Chrono Shards]|h|r and attempts to erase players from existence with |cFF2959D3|Hspell:203882|h[Banish In Time]|h|r.",-1,12751,0,0,1501,12754,1,0,0},
    {12751,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Interrupt |cFF2959D3|Hspell:203176|h[Accelerating Blast]|h|r to prevent it from stacking.\n\n$bullet;Quickly defeat Timeless Wraiths while |cFF2959D3|Hspell:203882|h[Banished In Time]|h|r.",-1,0,0,2,1501,12752,2,12750,0},
    {12752,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:202974|h[Force Bombs]|h|r inflict heavy damage to the entire group.\n\n$bullet;Timeless Wraiths use |cFF2959D3|Hspell:203952|h[Breach]|h|r to inflict damage to all nearby players.",-1,0,0,4,1501,12753,3,12750,0},
    {12753,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid standing near |cFF2959D3|Hspell:203254|h[Chrono Shards]|h|r.\n\n$bullet;Position the boss away from |cFF2959D3|Hspell:202974|h[Force Bombs]|h|r.",-1,0,0,1,1501,0,4,12750,0},
