    {12820,"Tanks",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:204531|h[Arcane Tethers]|h|r accrue during |cFF2959D3|Hspell:204275|h[Arcanoslash]|h|r, and need to be broken to reduce damage taken.\n\n$bullet;Take shelter behind |cFF2959D3|Hspell:204292|h[Crystaline Fragments]|h|r to protect yourself from |cFF2959D3|Hspell:204316|h[Shockwave]|h|r.",-1,0,0,1,1706,0,4,12817,0},
