    {12870,"Overview",0,3,0,0,{"wago"},"Fel Lord Betrug periodically sends players flying to the extreme sides of the Violet Hold. One of these players is chosen for Execution and must be freed or else they will die.",-1,12871,0,0,1711,12874,1,0,0},
    {12871,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Stay away from players that are targeted with |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r.\n\n$bullet;If you are the target of |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r position yourself to not hit your allies.\n\n$bullet;When Fel Lord Betrug begins executing one of your allies, hurry to cross the room and free them.",-1,0,0,2,1711,12872,2,12870,0},
    {12872,"Healers",0,3,0,0,{"wago"},"$bullet;Stay away from players that are targeted with |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r.\n\n$bullet;If you are the target of |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r, position yourself to not hit your allies.\n\n$bullet;When Fel Lord Betrug begins executing one of your allies, hurry to cross the room and free them.",-1,0,0,4,1711,12873,3,12870,0},
    {12873,"Tanks",0,3,0,0,{"wago"},"$bullet;Stay away from players that are targeted with |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r.\n\n$bullet;If you are the target of |cFF2959D3|Hspell:203641|h[Fel Slash]|h|r position yourself to not hit your allies.\n\n$bullet;When Fel Lord Betrug begins executing one of your allies, hurry to cross the room and free them.",-1,0,0,1,1711,0,4,12870,0},
