    {12880,"Open Prisons",0,0,0,0,{"wago"},"Inquisitor opens groups of prison cells during the encounter.",-1,12881,0,0,1695,0,8,0,0},
    {12881,"Cellblock 3-3x468",0,0,0,0,{"wago"},nil,-1,12882,0,0,1695,12892,9,12880,0},
    {12882,"Felguard Annihilator",0,1,0,0,{"wago"},"Will clear threat and charge to random enemies.  Deals a high amount of physical damage.",-1,12889,18342,1,1695,12883,10,12881,0},
    {12883,"Shadowmoon Technician",0,1,0,0,{"wago"},"Throws dynamite at random enemies and lays mines on the ground.  Also periodically silences a random caster.",-1,12890,17147,0,1695,12884,12,12881,0},
    {12884,"Shadowmoon Warlock",0,1,0,0,{"wago"},"Will empower allied demons to do significantly more damage.",-1,12891,17137,0,1695,0,14,12881,0},
    {12885,"Cellblock 3-4x8-5x02",0,0,0,0,{"wago"},nil,-1,12888,0,0,1695,0,26,12880,0},
    {12888,"Mogu'shan Secret Keeper",0,1,0,0,{"wago"},"Slowly turns all enemies to stone.",-1,12903,41841,0,1695,12898,27,12885,0},
    {12889,"Section 20",132307,2,206319,0,{"wago"},nil,-1,0,0,0,1695,0,11,12882,0},
    {12890,"Section 21",135975,2,6726,0,{"wago"},nil,-1,0,0,0,1695,0,13,12883,0},
