    {12893,"Faceless Voidcaster",0,1,0,0,{"wago"},"Periodically fires a Shadow Crash at the location of a random enemy.",-1,12899,31671,0,1695,12894,17,12892,0},
    {12894,"Void-Touched Juggernaught",0,1,0,0,{"wago"},"Has a frontal cleave attack and fears all nearby enemies periodically.",-1,12900,67182,1,1695,12895,19,12892,0},
    {12895,"Deranged Mindflayer",0,1,0,0,{"wago"},"Inflicts a high amount of Shadow damage to a random enemy and all targets within 10 yards of that enemy.",-1,12901,32708,0,1695,0,21,12892,0},
    {12896,"Cellblock 3-2x024",0,0,0,0,{"wago"},nil,-1,12897,0,0,1695,12885,23,12880,0},
    {12897,"Lingering Corruption",0,1,0,0,{"wago"},"Upon death will afflict a random enemy with an aura that creates an explosion when it expires.",-1,12902,50919,4,1695,0,24,12896,0},
    {12898,"Enormous Stone Quilen",0,1,0,0,{"wago"},"Inflicts a high amount of Physical damage to its target.",-1,12904,41155,1,1695,0,29,12885,0},
