    {13192,"Stage Two: The Heart of Corruption",0,0,0,0,{"wago"},"When the Eye of Il'gynoth is destroyed, the chamber holding Il'gynoth's beating heart is revealed.",-1,13193,0,0,1738,0,28,0,0},
    {13193,"The Heart of Il'gynoth",0,1,0,0,{"wago"},nil,-1,13502,69115,0,1738,13570,29,13192,0},
