    {13242,"Section 27",0,2,210984,0,{"wago"},"$[!17\n\n\n\nOn Raid Finder difficulty, Eye of Fate only affects the Nightmare Horror's current target.$]",-1,0,0,1,1738,13202,18,13188,0},
    {13243,"Section 26",0,2,215143,0,{"wago"},nil,-1,0,0,0,1738,13321,31,13193,0},
    {13244,"Section 28",0,2,210931,0,{"wago"},nil,-1,0,0,0,1738,0,11,13185,0},
