    {13421,"Section 13",236209,2,213568,2,{"wago"},nil,0,0,0,16,1751,0,35,13420,0},
    {13422,"Overview",0,3,0,0,{"wago"},"Over the course of the encounter, each of the Soultakers gains energy. As each Soultaker reaches 100 energy, they unleash a devastating attack.",-1,13423,0,0,1756,13426,1,0,0},
    {13423,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid being caught between Reaver Jdorn and his target during |cFF2959D3|Hspell:213590|h[Seadog's Scuttle]|h|r.\n\n$bullet;Quickly kill the |cFF2959D3|Hspell:213522|h[Cursed Crewmen]|h|r before Captain Hring completes the cast of |cFF2959D3|Hspell:213533|h[Shatter Crewman]|h|r.\n\n$bullet;Do not stand in the rifts opened by Soultrapper Mevra during |cFF2959D3|Hspell:213611|h[Soul Rend]|h|r.",-1,0,0,2,1756,13424,2,13422,0},
    {13424,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid being caught between Reaver Jdorn and his target during |cFF2959D3|Hspell:213590|h[Seadog's Scuttle]|h|r.\n\n$bullet;Do not stand in the rifts opened by Soultrapper Mevra during |cFF2959D3|Hspell:213611|h[Soul Rend]|h|r.",-1,0,0,4,1756,13425,3,13422,0},
    {13425,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid being caught between Reaver Jdorn and his target during |cFF2959D3|Hspell:213590|h[Seadog's Scuttle]|h|r.\n\n$bullet;Quickly gain threat on all of the |cFF2959D3|Hspell:213522|h[Cursed Crewmen]|h|r after they are summoned.\n\n$bullet;Do not stand in the rifts opened by Soultrapper Mevra during |cFF2959D3|Hspell:213611|h[Soul Rend]|h|r.",-1,0,0,1,1756,0,4,13422,0},
