    {13500,"Dreadlords of the Twisting Nether",0,0,0,1,{"wago"},nil,-1,13142,0,0,1737,0,79,13312,0},
    {13501,"Section 33",0,2,215761,2,{"wago"},nil,0,13649,0,4144,1738,13185,7,13184,0},
    {13502,"Section 33",0,2,210781,0,{"wago"},nil,-1,0,0,48,1738,13243,30,13193,0},
    {13503,"Section 12",0,2,215929,2,{"wago"},nil,2,0,0,8,1662,0,12,12347,0},
    {13504,"Overview",0,3,0,1,{"wago"},"Tichondrius wields foul carrion magic, unleashing waves of chaos and pestilence to assault the raid. \n\n\n\nAs the fight progresses, Tichondrius periodically uses |cFF2959D3|Hspell:206311|h[Illusionary Night]|h|r to trap all players in an illusion, within which they may find some respite if they can endure his |cFF2959D3|Hspell:215988|h[Carrion Nightmare]|h|r assault for $206311d.",-1,13893,0,0,1762,13552,1,0,0},
    {13505,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Carefully position to avoid spreading |cFF2959D3|Hspell:206480|h[Carrion Plague]|h|r.\n\n$bullet;Quickly kill Phantasmal Bloodfangs and obtain |cFF2959D3|Hspell:206466|h[Essence of Night]|h|r while trapped in the |cFF2959D3|Hspell:206365|h[Illusionary Night]|h|r.",0,0,0,2,1762,13506,3,13504,0},
    {13506,"Healers",0,3,0,0,{"wago"},"$bullet;Players with |cFF2959D3|Hspell:206480|h[Carrion Plague]|h|r take sustained damage until the debuff can fade during |cFF2959D3|Hspell:206365|h[Illusionary Night]|h|r.\n\n$bullet;Position for and quickly dispel |cFF2959D3|Hspell:216040|h[Burning Soul]|h|r.\n\n$bullet;Tanks suffer significant damage from Tichondrius' nightborne allies.",-1,0,0,4,1762,13507,4,13504,0},
    {13507,"Tanks",0,3,0,0,{"wago"},"$bullet;Position nightborne and Legion minions outside of |cFF2959D3|Hspell:206893|h[Vampiric Aura]|h|r.\n\n$bullet;Avoid taking multiple stacks of |cFF2959D3|Hspell:208230|h[Feast of Blood]|h|r.",-1,0,0,1,1762,0,5,13504,0},
    {13508,"Section 5",0,2,212997,0,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, this effect increases the damage taken from Seeker Swarm by 1,000%.$]",-1,0,0,0,1762,13509,7,13552,0},
    {13509,"Section 6",0,2,213238,0,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, this effect only hits the player closest to Tichondrius in the path of Seeker Swarm.$]",-1,0,0,0,1762,13510,8,13552,0},
    {13510,"Section 7",0,2,212794,2,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, Flames of Argus erupt under each player that triggers Brand of Argus.$]",0,13581,0,0,1762,13512,9,13552,0},
    {13511,"Section 8",0,2,208230,0,{"wago"},nil,-1,13583,0,1,1762,13513,12,13552,0},
    {13512,"Section 9",0,2,206893,0,{"wago"},nil,-1,0,0,0,1762,13511,11,13552,0},
