    {13514,"Section 11",0,2,206365,1,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, players without the Essence of Night when Illusionary Night ends are instantly killed.$]",-1,13527,0,0,1762,0,16,13553,0},
