    {13528,"Phantasmal Bloodfang",0,1,0,0,{"wago"},"Phantasmal Bloodfangs continuously form in the illusion at an increasing rate.",-1,13529,63345,0,1762,0,18,13514,0},
    {13529,"Section 26",0,2,206466,1,{"wago"},nil,-1,0,0,0,1762,0,19,13528,0},
    {13530,"Overview",0,3,0,0,{"wago"},"While fighting Shar'thos, positioning is very important. Avoid standing behind or directly in front of Shar'thos, as it will leave you vulnerable to |cFF2959D3|Hspell:215821|h[Nightmare Breath]|h|r or |cFF2959D3|Hspell:215806|h[Tail Lash]|h|r.",-1,13531,0,0,1763,13535,1,0,0},
    {13531,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Stay spread to decrease chaining damage from |cFF2959D3|Hspell:216043|h[Dread Flame]|h|r.",-1,0,0,2,1763,13532,2,13530,0},
    {13532,"Healers",0,3,0,0,{"wago"},"$bullet;Stay spread to decrease chaining damage from |cFF2959D3|Hspell:216043|h[Dread Flame]|h|r.",-1,0,0,4,1763,13533,3,13530,0},
    {13533,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid moving Shar'thos erratically to avoid exposing allies to |cFF2959D3|Hspell:215821|h[Nightmare Breath]|h|r or |cFF2959D3|Hspell:215806|h[Tail Lash]|h|r.",-1,0,0,1,1763,0,4,13530,0},
