    {13585,"Overview",0,3,0,0,{"wago"},"All of Humongris's attacks deal area damage. Try to remain spread to decrease his overall damage.",-1,13586,0,0,1770,13590,1,0,0},
    {13586,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Stay spread so less allies are effected by splash damage dealt by |cFF2959D3|Hspell:216429|h[Fire Boom]|h|r and |cFF2959D3|Hspell:216432|h[Ice Fist]|h|r.",-1,0,0,2,1770,13587,2,13585,0},
    {13587,"Healers",0,3,0,0,{"wago"},"$bullet;Stay spread so less allies are affected by splash damage dealt by |cFF2959D3|Hspell:216429|h[Fire Boom]|h|r and |cFF2959D3|Hspell:216432|h[Ice Fist]|h|r.",-1,0,0,4,1770,13588,3,13585,0},
    {13588,"Tanks",0,3,0,0,{"wago"},"$bullet;Move away from allies if you are affected by |cFF2959D3|Hspell:216822|h[You Go Bang!]|h|r.",-1,0,0,1,1770,0,4,13585,0},
