    {13633,"Section 10",0,2,217362,0,{"wago"},nil,-1,0,0,128,1769,13606,9,0,0},
    {13635,"Overview",0,3,0,0,{"wago"},"Calamir shifts between using |cFF2959D3|Hspell:217563|h[Ancient Rage: Fire]|h|r, |cFF2959D3|Hspell:217831|h[Ancient Rage: Frost]|h|r, and |cFF2959D3|Hspell:217834|h[Ancient Rage: Arcane]|h|r to pummel its foes. Be careful, as each of the schools provide very different threats!",-1,13636,0,0,1774,13639,1,0,0},
    {13636,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Back away while Calamir casts |cFF2959D3|Hspell:217966|h[Howling Gale]|h|r to avoid taking unnecessary damage.\n\n$bullet;Move away from other players while afflicted with |cFF2959D3|Hspell:217877|h[Burning Bomb]|h|r to avoid blowing them up.",-1,0,0,2,1774,13637,2,13635,0},
    {13637,"Healers",0,3,0,0,{"wago"},"$bullet;Dispel players afflicted by |cFF2959D3|Hspell:217877|h[Burning Bomb]|h|r to prevent them from blowing up others.\n\n$bullet;Avoid |cFF2959D3|Hspell:218012|h[Arcanopulse]|h|r to not get stunned.",-1,0,0,4,1774,13638,3,13635,0},
    {13638,"Tanks",0,3,0,0,{"wago"},"$bullet;Back away while Calamir casts |cFF2959D3|Hspell:217966|h[Howling Gale]|h|r to avoid taking unnecessary damage.\n\n$bullet;Avoid |cFF2959D3|Hspell:218012|h[Arcanopulse]|h|r to not get stunned.",-1,0,0,1,1774,0,4,13635,0},
    {13639,"Section 5",0,2,217563,1,{"wago"},nil,-1,13642,0,0,1774,13640,5,0,0},
