    {13648,"Section 37",0,2,217987,2,{"wago"},nil,0,0,0,0,1726,0,23,12972,0},
    {13649,"Section 46",0,2,215845,2,{"wago"},nil,0,0,0,0,1738,0,8,13501,0},
    {13650,"Section 11",0,2,192305,0,{"wago"},nil,-1,0,0,0,1486,12056,7,12055,0},
    {13675,"Overview",0,3,0,1,{"wago"},"High Botanist Tel'arn uses Arcane, Nature, and Solar magic to defend his garden. When he reaches 75% and 50% health remaining he divides his energy, creating empowered forms that focus in a particular school of magic. This division removes High Botanist Tel'arn's access to that school of magic, but the empowered form gains new abilities.",-1,13676,0,0,1761,13679,1,0,0},
    {13676,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Move away from targets of |cFF2959D3|Hspell:218424|h[Parasitic Fetter]|h|r and quickly kill Parasitic Lashers.\n\n$bullet;Damage |cFF2959D3|Hspell:218774|h[Plasma Spheres]|h|r so that they die at least $218780d apart from one another to avoid lethal damage from |cFF2959D3|Hspell:218780|h[Plasma Explosion]|h|r. \n\n$bullet;Avoid |cFF2959D3|Hspell:218438|h[Controlled Chaos]|h|r and |cFF2959D3|Hspell:218148|h[Solar Collapse]|h|r.",-1,0,0,2,1761,13677,2,13675,0},
    {13677,"Tanks",0,3,0,0,{"wago"},"$bullet;Take turns tanking Tel'arn to manage the application of |cFF2959D3|Hspell:218502|h[Recursive Strikes]|h|r.\n\n$bullet;Position Naturalist Tel'arn away from his allies and quickly move him out of |cFF2959D3|Hspell:218927|h[Grace of Nature]|h|r.\n\n$bullet;High Botanist Tel'arn splits into images that must be tanked at 75% and 50% health remaining.",-1,0,0,1,1761,13678,3,13675,0},
    {13678,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:218780|h[Plasma Explosion]|h|r inflicts significant damage to all players.\n\n$bullet;Dispel |cFF2959D3|Hspell:218424|h[Parasitic Fetter]|h|r when your allies have moved far enough away to avoid Parasitic Lashers.\n\n$bullet;|cFF2959D3|Hspell:218438|h[Controlled Chaos]|h|r inflicts moderate damage to all players with each explosion.",-1,0,0,4,1761,0,4,13675,0},
    {13679,"Stage One: The High Botanist",0,0,0,3,{"wago"},nil,0,13680,0,0,1761,13681,5,0,0},
    {13680,"Section 8",0,2,218502,0,{"wago"},nil,-1,0,0,1,1761,13685,6,13679,0},
    {13681,"Stage Two: Nightosis",0,0,0,3,{"wago"},"When High Botanist Tel'arn reaches 75% health remaining, he sacrifices his ability to cast Solar magic to create an empowered Solar image of himself.",0,13682,0,0,1761,13683,12,0,0},
    {13682,"Solarist Tel'arn",0,1,0,0,{"wago"},nil,-1,13688,70822,0,1761,0,13,13681,0},
    {13683,"Stage Three: Pure Forms",0,0,0,3,{"wago"},"When High Botanist Tel'arn reaches 50% health remaining, he divides his remaining power into an empowered Nature and empowered Arcane image.",0,13684,0,0,1761,13824,18,0,0},
