    {13735,"Overview",0,3,0,1,{"wago"},"Ana-Mouz uses various area-denial abilities to limit where enemies can safely stand. Additionally, she summons Lesser Minions.",-1,13736,0,0,1790,13739,1,0,0},
    {13736,"Damage Dealers",0,3,0,1,{"wago"},"$bullet;Avoid standing in |cFF2959D3|Hspell:218823|h[Fel Geysers]|h|r.\n\n$bullet;Do not stand in front of the boss during |cFF2959D3|Hspell:218888|h[Impish Flames]|h|r.\n\n$bullet;Kill Lesser Minions summoned by |cFF2959D3|Hspell:219255|h[Gaseous Breath]|h|r.",-1,0,0,2,1790,13737,2,13735,0},
    {13737,"Tanks",0,3,0,1,{"wago"},"$bullet;Face Ana-Mouz away from allies to avoid hitting them with |cFF2959D3|Hspell:218888|h[Impish Flames]|h|r.\n\n$bullet;Avoid standing in |cFF2959D3|Hspell:218823|h[Fel Geysers]|h|r.",-1,0,0,1,1790,13738,3,13735,0},
    {13738,"Healers",0,3,0,1,{"wago"},"$bullet;Avoid standing in |cFF2959D3|Hspell:218823|h[Fel Geysers]|h|r.\n\n$bullet;Do not stand in front of the boss during |cFF2959D3|Hspell:218888|h[Impish Flames]|h|r.\n\n$bullet;Dispel |cFF2959D3|Hspell:219045|h[Mother's Embrace]|h|r to prevent your allies from being charmed.",-1,0,0,4,1790,0,4,13735,0},
