    {13854,"Infernal Imp",0,1,0,2,{"wago"},"Infernal Eruptions cause the ground to crack open, spilling forth an Infernal Imp.",0,13855,17035,4098,1719,0,8,13071,0},
    {13855,"Section 16",0,2,224374,0,{"wago"},nil,-1,0,0,0,1719,13856,9,13854,0},
    {13856,"Section 17",0,2,224377,0,{"wago"},nil,-1,0,0,0,1719,0,10,13854,0},
    {13857,"Overview",0,3,0,0,{"wago"},"Withered J'im himself is frail, but those in his presence gain Withered Presence, reducing their damage by $223599s2%. Withered J'im draws power from an Unstable Manashard nearby, creating volatile gouts of arcane energy and leverages that energy to create copies of himself.",-1,13858,0,0,1796,13866,1,0,0},
    {13858,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid getting hit by |cFF2959D3|Hspell:223623|h[Nightshifted Bolts]|h|r.\n\n$bullet;Defeat |cFF2959D3|Hspell:223689|h[Nightstable Energy]|h|r to reduce area denial.\n\n$bullet;Avoid attacking J'im when he is afflicted with |cFF2959D3|Hspell:223614|h[Resonance]|h|r.",-1,0,0,2,1796,13859,2,13857,0},
    {13859,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid getting hit by |cFF2959D3|Hspell:223623|h[Nightshifted Bolts]|h|r.",-1,0,0,4,1796,13860,3,13857,0},
    {13860,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid getting hit by |cFF2959D3|Hspell:223623|h[Nightshifted Bolts]|h|r.\n\n$bullet;Be aware, J'im's |cFF2959D3|Hspell:223614|h[Resonance]|h|r can create many additional enemies.",-1,0,0,1,1796,0,4,13857,0},
