    {13927,"Section 48",0,2,226821,2,{"wago"},"$[!16 \n\n\n\n In Mythic difficulty, the Nightmare Ancient will cast Desiccating Stomp twice in rapid succession. $]",0,13928,0,0,1750,0,22,13350,0},
    {13928,"Section 49",0,2,211156,2,{"wago"},nil,0,0,0,0,1750,0,23,13927,0},
    {13929,"Section 50",0,2,226713,2,{"wago"},nil,0,0,0,4096,1750,0,18,13348,0},
    {13930,"Section 30",0,2,209549,2,{"wago"},nil,0,0,0,1,1743,13227,10,13226,0},
    {13932,"Section 12",0,2,203816,0,{"wago"},nil,-1,0,0,8,1502,0,12,12152,0},
    {13969,"Section 10",0,2,227178,1,{"wago"},nil,-1,0,0,32,1686,0,6,12579,0},
    {13982,"Intermission: Submerged",0,0,0,0,{"wago"},"After several of Helya's tentacles are defeated, Helya submerges under the waves and assaults the Naglfar from below. On subsequent phases Helya periodically submerges.",-1,12370,0,0,1663,12367,19,0,0},
