    {14045,"Overview",0,3,0,0,{"wago"},"Avoid Galindre's |cFF2959D3|Hspell:227346|h[Magic Magnificent]|h|r by using the vortices left over from Elfyra's |cFF2959D3|Hspell:227405|h[Defy Gravity]|h|r.",-1,14046,0,0,1820,14550,1,0,0},
    {14046,"Tanks",0,3,0,0,{"wago"},"$bullet;Move out of |cFF2959D3|Hspell:227410|h[Wondrous Radiance]|h|r when it appears below you.",-1,0,0,1,1820,14047,2,14045,0},
    {14047,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Kill off Winged Assistants summoned by |cFF2959D3|Hspell:227477|h[Summon Assistants]|h|r to avoid being overrun.",-1,0,0,2,1820,14048,3,14045,0},
    {14048,"Healers",0,3,0,0,{"wago"},"$bullet;Expect a spike in healing needed if the tank does not avoid |cFF2959D3|Hspell:227410|h[Wondrous Radiance]|h|r.\n\n$bullet;While there are Winged Assistants alive, the entire party will be taking damage and need healing.",-1,0,0,4,1820,0,4,14045,0},
    {14062,"Stage One: The Ritual of Aman'Thul",0,0,0,2,{"wago"},"Gul'dan, taking no chances, leaps into the fray, harnessing the power of the Fel to bolster his frail frame, periodically summoning his demonic lieutenants and utilizing the active Eye of Aman'Thul, expanding the potency of his abilities.",0,14063,0,0,1737,13133,43,0,0},
