    {14113,"Overview",0,3,0,1,{"wago"},"The Defias Brotherhood and The Fins attack separately, culminating in a finale with Toe Knee and Mrrgria.",-1,14114,0,0,1826,14117,1,0,0},
    {14114,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Defeat the Gang Ruffians and Shoreline Tidespeakers first to reduce the danger to your party.\n\n$bullet;Move away from other party members when |cFF2959D3|Hspell:227780|h[Thunder Ritual]|h|r is about to expire.",-1,0,0,2,1826,14115,2,14113,0},
    {14115,"Healers",0,3,0,0,{"wago"},"$bullet;Players struck by |cFF2959D3|Hspell:227325|h[Poisonous Shank]|h|r will require extra attention.\n\n$bullet;Move away from other party members when |cFF2959D3|Hspell:227780|h[Thunder Ritual]|h|r is about to expire.",-1,0,0,4,1826,14116,3,14113,0},
    {14116,"Tanks",0,3,0,0,{"wago"},"$bullet;Back up when Toe Knee casts |cFF2959D3|Hspell:227568|h[Burning Leg Sweep]|h|r to avoid being stunned.\n\n$bullet;Move away from other party members when |cFF2959D3|Hspell:227780|h[Thunder Ritual]|h|r is about to expire.",-1,0,0,1,1826,0,4,14113,0},
