    {14138,"Overview",0,3,0,1,{"wago"},"Coggleston, along with the other castle servants, protects Bella and prevents any would-be interlopers from obstructing true love.",-1,14139,0,0,1827,14307,1,0,0},
    {14139,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Interrupt Luminore's |cFF2959D3|Hspell:228025|h[Heat Wave]|h|r to help the party's survivability.\n\n$bullet;Try not to lead Babblet through |cFF2959D3|Hspell:228200|h[Burning Blaze]|h|r to prevent her from gaining |cFF2959D3|Hspell:228225|h[Sultry Heat]|h|r.\n\n$bullet;Use |cFF2959D3|Hspell:228013|h[Drenched]|h|r to clear up |cFF2959D3|Hspell:228200|h[Burning Blaze]|h|r if it gets out of hand.",-1,0,0,2,1827,14140,2,14138,0},
    {14140,"Healers",0,3,0,0,{"wago"},"$bullet;Try not to lead Babblet through |cFF2959D3|Hspell:228200|h[Burning Blaze]|h|r to prevent her from gaining |cFF2959D3|Hspell:228225|h[Sultry Heat]|h|r.\n\n$bullet;Use |cFF2959D3|Hspell:228013|h[Drenched]|h|r to clear up |cFF2959D3|Hspell:228200|h[Burning Blaze]|h|r if it gets out of hand.",-1,0,0,4,1827,14141,3,14138,0},
    {14141,"Tanks",0,3,0,0,{"wago"},"$bullet;Be careful when Coggleston uses |cFF2959D3|Hspell:227985|h[Dent Armor]|h|r, as it can be very dangerous.\n\n$bullet;Interrupt Coggleston's |cFF2959D3|Hspell:227987|h[Dinner Bell!]|h|r whenever possible.",-1,0,0,1,1827,0,4,14138,0},
    {14142,"Coggleston",0,1,0,1,{"wago"},"The most loyal of castle denizens, Coggleston has been cursed into the form of a stove by an evil witch.",-1,14564,73202,1,1827,0,16,0,0},
