    {14222,"Stage Two: From the Mists",0,0,0,1,{"wago"},"Upon reaching 65% health, Helya departs beneath the sea, assaulting the raid from afar with her denizens of Helheim or ocean waves from the Maw of Souls. Defeating Helya's tentacles wounds her, causing her to return to the shore.",-1,14270,0,0,1829,14224,18,0,0},
    {14223,"Decaying Minion",0,1,0,0,{"wago"},nil,-1,14744,66184,0,1829,0,61,14224,0},
    {14224,"Stage Three: Helheim's Last Stand",0,0,0,1,{"wago"},"Helya orders the last stand of Helheim, invoking both the minions of Helheim and her supernatural powers until her defeat.",-1,14225,0,0,1829,0,41,0,0},
    {14225,"Helya",0,1,0,1,{"wago"},nil,-1,14226,65043,0,1829,14560,42,14224,0},
