    {14304,"Fighting on Foot",0,0,0,0,{"wago"},"When Midnight has her health reduced, Attumen dismounts and fights on foot until Midnight's health regenerates.",-1,14305,0,0,1835,0,9,0,0},
    {14305,"Section 9",0,2,227339,0,{"wago"},nil,-1,0,0,16,1835,14306,10,14304,0},
