    {14307,"Section 18",0,2,228729,1,{"wago"},nil,-1,0,0,32,1827,14145,5,0,0},
    {14309,"Gripping Tentacle",0,1,0,0,{"wago"},"Helya grips the landmass, allowing her to command the waves of the sea and attack players from relative safety. Defeating these wound her, eventually forcing her back ashore.",-1,0,73534,0,1829,0,24,14270,0},
    {14311,"Decaying Minion",0,1,0,0,{"wago"},nil,-1,14743,66184,0,1829,0,37,14222,0},
    {14312,"Section 24",0,2,228121,1,{"wago"},nil,-1,0,0,0,1829,14773,39,14311,0},
    {14318,"Overview",0,3,0,0,{"wago"},"The Curator loses mana as it casts spells to strike its foes. When it reaches 10% mana, it will cease attacking and rapidly regenerate its mana. While it does so, it is very vulnerable to player attacks.",-1,14319,0,0,1836,14323,1,0,0},
    {14319,"Tanks",0,3,0,0,{"wago"},"$bullet;The Curator targets you with |cFF2959D3|Hspell:227465|h[Power Discharge]|h|r. Place damaging area effects strategically.",-1,0,0,1,1836,14320,2,14318,0},
    {14320,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Focus fire Volatile Energy before its |cFF2959D3|Hspell:227270|h[Arc Lightning]|h|r becomes unmanageable for healers.\n\n$bullet;The Curator is at its most vulnerable when it casts |cFF2959D3|Hspell:227254|h[Evocation]|h|r.",-1,0,0,2,1836,14321,3,14318,0},
    {14321,"Healers",0,3,0,0,{"wago"},"$bullet;The Curator inflicts heavy damage with |cFF2959D3|Hspell:227257|h[Overload]|h|r after finishing |cFF2959D3|Hspell:227254|h[Evocation]|h|r.",-1,0,0,4,1836,0,4,14318,0},
