    {14484,"Flare",135807,2,0,2,{"wago"},"Solarist Tel'arn blasts a player, inflicting $218806s1 Fire damage and applies Parasitic Fetter to them and all players within $218806A1 yards.",0,14521,0,0,1761,14497,84,14482,0},
    {14485,"Recursive Strikes",1387356,2,0,2,{"wago"},"High Botanist Tel'arn inflicts $218508s1% of his melee attack damage to all players with Recursive Strikes each time he melee attacks.\n\n\n\nThis effect is applied to Tel'arn's primary target each time he melee attacks for $218503d. Each additional stack increases the damage taken from Recursive Strikes by $218508s1%.\n\n\n\nIn addition, this effect creates Plasma Spheres when it expires.",0,14516,0,1,1761,14489,77,14481,0},
    {14486,"Section 61",0,2,223034,0,{"wago"},nil,-1,14488,0,0,1761,14506,57,14473,0},
