    {14587,"Overview",0,3,0,0,{"wago"},"Handpicked to watch over the flooded passageways, Mistress Sassz'ine stands ready to retrieve the Tidestone from those foolish enough to enter her domain.",-1,16187,0,0,1861,15092,1,0,0},
    {14588,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Avoid being struck by |cFF2959D3|Hspell:232722|h[Slicing Tornado]|h|r to prevent unnecessary damage.\n\n$bullet;Bring |cFF2959D3|Hspell:232913|h[Befouling Ink]|h|r to Sarukel, The Unending Hunger when he opens his |cFF2959D3|Hspell:234621|h[Devouring Maw]|h|r.",0,0,0,2,1861,16188,3,14587,0},
