    {14673,"Time Layer 1",0,0,0,0,{"wago"},"While in this Time Layer Grand Magistrix Elisande will use her |cFF2959D3|Hspell:209168|hSpanning Singularity|h|r and |cFF2959D3|Hspell:208807|hArcanetic Ring|h|r abilities.",-1,14674,0,0,1872,14677,15,0,0},
    {14674,"Section 6",0,2,228877,0,{"wago"},"$[!14,15,16,17\n\n\n\nThis ability echoes.$]\n\n$[!16\n\n\n\nIn Mythic Difficulty, the Arcanetic Ring expands to the outside of the room after collapsing.$]",-1,0,0,16,1872,14675,16,14673,0},
    {14675,"Section 10",0,2,209168,0,{"wago"},"$[!14,15,16,17\n\n\n\nSpanning Singularities appear at the same time and place in successive Time Layers.$]",-1,0,0,32,1872,14676,17,14673,0},
    {14676,"Section 23",0,2,209615,0,{"wago"},nil,-1,0,0,1,1872,0,18,14673,0},
