    {14678,"Epochera",0,2,210022,0,{"wago"},"$[!14,15,16,17\n\n\n\nThis ability echoes.$]\n\n$[!16\n\n\n\nIn Mythic difficulty, players catching the Orbs are afflicted with Epocheric Vulnerability.$]",-1,0,0,16,1872,14679,20,14677,0},
