    {14719,"Stage Two: An Avatar Awakened",0,0,0,1,{"wago"},"Upon reaching 100 Energy the Avatar shatters his bonds, destroying the platform and dropping players deeper into the Tomb of Sargeras.",-1,15134,0,0,1873,0,27,0,0},
    {14721,"Fragmented Time Particle",0,1,0,0,{"wago"},"Fragmented Time Particles continually Warp the Nightwell until they are defeated.",-1,0,55561,0,1725,0,20,13286,0},
    {14722,"Razorjaw Gladiator",0,1,0,2,{"wago"},nil,0,15266,5306,0,1856,0,15,14636,0},
