    {14752,"Section 18",0,2,239132,0,{"wago"},nil,-1,0,0,16,1873,14751,11,14709,0},
    {14759,"Overview",0,3,0,0,{"wago"},"Mephistroth uses shadow magic to attack the party until he reaches 100% energy. Once his energy is full, Mephistroth fades away and strikes at the heroes from the shadows. During this, Illidan must be protected with the Aegis of Aggramar long enough for him to pull the dreadlord back into the light.\n\n\n\n$[!23\n\nOn Mythic difficulty, fel bats fly in through the windows during Shadow Fade and assault the heroes with Fel Blaze.$]",-1,14760,0,0,1878,14769,1,0,0},
    {14760,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Move away from your allies when targeted by |cFF2959D3|Hspell:233196|h[Demonic Upheaval]|h|r.\n\n$bullet;Defeat Shadows of Mephistroth during |cFF2959D3|Hspell:233206|h[Shadow Fade]|h|r.",-1,0,0,2,1878,14761,2,14759,0},
    {14761,"Healers",0,3,0,0,{"wago"},"$bullet;Allies take increasing damage from |cFF2959D3|Hspell:234382|h[Creeping Shadows]|h|r while Mephistroth is hidden.",-1,0,0,4,1878,14762,3,14759,0},
    {14762,"Tanks",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:233155|h[Carrion Swarm]|h|r is a heavy attack that needs to be faced away from the party.\n\n$bullet;During |cFF2959D3|Hspell:233206|h[Shadow Fade]|h|r, face the Aegis of Agrammar towards Shadows Orbs to protect Illidan.",-1,0,0,1,1878,0,4,14759,0},
    {14763,"Section 5",0,2,233155,0,{"wago"},nil,-1,0,0,1,1878,14764,7,14949,0},
