    {14791,"Overview",0,3,0,0,{"wago"},"Brutallus' |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r is devastating unless its damage is shared between many enemies.\n\n\n\nAvoid taking damage from |cFF2959D3|Hspell:233519|h[Crashing Embers]|h|r, especially when affected by |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r.",-1,14794,0,0,1883,14796,1,0,0},
    {14792,"Healers",0,3,0,0,{"wago"},"$bullet;Stand near your allies when Brutallus casts |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r.\n\n$bullet;Prioritize allies affected by |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r for heavy healing if they are affected by |cFF2959D3|Hspell:233519|h[Crashing Embers]|h|r.",-1,0,0,4,1883,0,4,14791,0},
    {14793,"Meteor Slash",0,2,234394,0,{"wago"},nil,-1,0,0,0,1883,0,7,0,0},
    {14794,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Stand near your allies when Brutallus casts |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r.\n\n$bullet;Avoid taking damage from |cFF2959D3|Hspell:233519|h[Crashing Embers]|h|r, especially when affected by |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r.",-1,0,0,2,1883,14795,2,14791,0},
    {14795,"Tanks",0,3,0,0,{"wago"},"$bullet;Face Brutallus toward a large group of allies when he casts |cFF2959D3|Hspell:233484|h[Meteor Slash]|h|r.",-1,0,0,1,1883,14792,3,14791,0},
    {14796,"Meteor Slash",0,2,233484,0,{"wago"},nil,-1,0,0,0,1883,14797,5,0,0},
    {14797,"Meteor Slash",0,2,233519,0,{"wago"},nil,-1,0,0,0,1883,14793,6,0,0},
    {14798,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid standing in pools of |cFF2959D3|Hspell:233850|h[Virulent Infection]|h|r.\n\n$bullet;Avoid enemies who are fleeing due to |cFF2959D3|Hspell:233568|h[Incite Panic]|h|r.",-1,0,0,4,1884,0,4,14802,0},
    {14799,"Section 2",0,2,234452,0,{"wago"},nil,-1,0,0,0,1884,14800,5,0,0},
