    {14802,"Overview",0,3,0,0,{"wago"},"Players affected by |cFF2959D3|Hspell:233568|h[Incite Panic]|h|r will spread |cFF2959D3|Hspell:233568|h[Incite Panic]|h|r to nearby allies.",-1,14803,0,0,1884,14799,1,0,0},
    {14803,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid standing in pools of |cFF2959D3|Hspell:233850|h[Virulent Infection]|h|r.\n\n$bullet;Avoid enemies who are fleeing due to |cFF2959D3|Hspell:233568|h[Incite Panic]|h|r.",-1,0,0,2,1884,14804,2,14802,0},
    {14804,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid enemies who are fleeing due to |cFF2959D3|Hspell:233568|h[Incite Panic]|h|r.",-1,0,0,1,1884,14798,3,14802,0},
    {14805,"Overview",0,3,0,0,{"wago"},"|cFF2959D3|Hspell:233971|h[Tidal Wave]|h|r is slow moving, but massive. It cannot be avoided by moving at the last minute.",-1,14806,0,0,1885,14811,1,0,0},
    {14806,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Dodge |cFF2959D3|Hspell:233971|h[Tidal Wave]|h|r by watching the sea for incoming waves.\n\n$bullet;Avoid |cFF2959D3|Hspell:234231|h[Submerge]|h|r stuns, especially as waves crash over the beach.",-1,0,0,2,1885,14808,2,14805,0},
    {14807,"Healers",0,3,0,0,{"wago"},"$bullet;Dodge |cFF2959D3|Hspell:233971|h[Tidal Wave]|h|r by watching the sea for incoming waves.",-1,0,0,4,1885,0,4,14805,0},
