    {14848,"Section 18",0,2,235230,0,{"wago"},nil,-1,0,0,32,1867,0,19,14646,0},
    {14851,"Overview",0,3,0,0,{"wago"},"The Engine of Souls exists within the corporeal realm while the corrupted soul of High Priestess Dejahna controls the Spirit Realm. Both share health and call upon the spirits and the undead to serve the Legion.$[!14,15,16\n\n\n\nAt 30% health remaining, the Engine of Souls lurches forward and ejects The Desolate Host, a fearsome amalgamation of the corrupted dead.$]$[!16\n\n\n\nIn Mythic difficulty, players are only able to voluntarily switch realms while under 50% health.$]",-1,14852,0,0,1896,15095,1,0,0},
    {14852,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;If afflicted with |cFF2959D3|Hspell:236449|h[Soulbind]|h|r, quickly move to another similarly afflicted player in the opposing realm.\n\n$bullet;Manage the final explosion from |cFF2959D3|Hspell:236515|h[Shattering Scream]|h|r to ensure it removes applications of |cFF2959D3|Hspell:236513|h[Bonecage Armor]|h|r.",-1,0,0,2,1896,14853,2,14851,0},
    {14853,"Healers",0,3,0,0,{"wago"},"$bullet;Players in the Spirit Realm will require large amounts of healing while |cFF2959D3|Hspell:236072|h[Wailing Souls]|h|r is occurring.\n\n$bullet;If afflicted with |cFF2959D3|Hspell:236449|h[Soulbind]|h|r, quickly move to another similarly afflicted player in the opposing realm.",-1,0,0,4,1896,15326,3,14851,0},
    {14856,"Corporeal Realm",0,0,0,1,{"wago"},"In the realm of the living, the Engine of Souls siphons fallen Night Elf spirits for the Burning Legion.",-1,14931,0,0,1896,14857,6,0,0},
    {14857,"Spirit Realm",0,0,0,1,{"wago"},"In the realm of the dead, High Priestess Dejahna's soul has been corrupted into dark servitude.",-1,14934,0,0,1896,14970,22,0,0},
    {14868,"Infusions",1122135,2,235271,2,{"wago"},nil,0,14869,0,32,1897,15297,29,14975,0},
