    {14871,"Hammers",1580740,2,0,2,{"wago"},"The Maiden imbues her hammer with either Holy or Fel energy and strikes the ground with tremendous force.",0,14872,0,1,1897,15039,19,14974,0},
    {14872,"Hammer of Creation",135875,2,235569,0,{"wago"},nil,-1,15077,0,0,1897,14873,20,14871,0},
