    {14878,"Titanic Bulwark",135874,2,235028,0,{"wago"},nil,-1,0,0,32,1897,14879,33,14975,0},
    {14879,"Wrath of the Creators",135874,2,234891,0,{"wago"},nil,-1,15273,0,64,1897,15274,34,14975,0},
    {14880,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Use |cFF2959D3|Hspell:210339|h[Time Dilation]|h|r to increase damage at opportune moments or cover distances quickly.\n\n$bullet;Assist |cFF2959D3|Hspell:206222|h[Bonds of Fel]|h|r-afflicted allies in order to reduce the damage to manageable levels.\n\n$bullet;Move away from others when afflicted with |cFF2959D3|Hspell:209270|h[Eye of Gul'dan]|h|r or |cFF2959D3|Hspell:211152|h[Empowered Eye of Gul'dan]|h|r.\n\n$bullet;Absorb |cFF2959D3|Hspell:208802|h[Soul Corrosion]|h|r inside the |cFF2959D3|Hspell:206939|h[Well of Souls]|h|r in order to reduce raidwide damage taken from |cFF2959D3|Hspell:206744|h[Black Harvest]|h|r.",0,0,0,2,1737,14881,3,13107,0},
    {14881,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Use |cFF2959D3|Hspell:210339|h[Time Dilation]|h|r to increase damage at opportune moments or cover distances quickly.\n\n$bullet;Interrupt |cFF2959D3|Hspell:208672|h[Carrion Wave]|h|r.\n\n$bullet;Assist |cFF2959D3|Hspell:206222|h[Bonds of Fel]|h|r-afflicted allies in order to reduce the damage to manageable levels.\n\n$bullet;Absorb |cFF2959D3|Hspell:208802|h[Soul Corrosion]|h|r inside the |cFF2959D3|Hspell:206939|h[Well of Souls]|h|r in order to reduce raidwide damage taken from |cFF2959D3|Hspell:206744|h[Black Harvest]|h|r.",0,0,0,2,1737,13109,4,13107,0},
    {14882,"Healers",0,3,0,2,{"wago"},"$bullet;Use |cFF2959D3|Hspell:217830|h[Scattering Field]|h|r to absorb nearby allies' Fire damage taken at opportune moments.\n\n$bullet;Fel Lord Kuraz'mal's |cFF2959D3|Hspell:206675|h[Shatter Essence]|h|r inflicts high damage.\n\n$bullet;Assist |cFF2959D3|Hspell:206222|h[Bonds of Fel]|h|r-afflicted allies in order to reduce the damage to manageable levels.\n\n$bullet;|cFF2959D3|Hspell:206744|h[Black Harvest]|h|r inflicts high raidwide damage.",0,0,0,4,1737,14883,6,13107,0},
    {14883,"Healers",0,3,0,2,{"wago"},"$bullet;Use |cFF2959D3|Hspell:217830|h[Scattering Field]|h|r to absorb nearby allies' Fire damage taken at opportune moments.\n\n$bullet;Coordinate use of damage-reduction abilities to help tanks with Fel Lord Kuraz'mal's |cFF2959D3|Hspell:206675|h[Shatter Essence]|h|r.\n\n$bullet;Dispel Inquisitor Vethriz's |cFF2959D3|Hspell:212568|h[Drain]|h|r.\n\n$bullet;|cFF2959D3|Hspell:206744|h[Black Harvest]|h|r inflicts high raidwide damage.",0,0,0,4,1737,14884,7,13107,0},
    {14884,"Tanks",0,3,0,2,{"wago"},"$bullet;While fighting Fel Lord Kuraz'mal, be prepared for |cFF2959D3|Hspell:206675|h[Shatter Essence]|h|r.\n\n$bullet;D'zorykx the Trapper will throw |cFF2959D3|Hspell:206883|h[Soul Vortex]|h|r at his current target, increasing their damage taken.",0,0,0,1,1737,13110,8,13107,0},
    {14885,"Stage One: The Council of Elders",0,0,0,2,{"wago"},"Gul'dan locks himself inside the active Eye of Aman'Thul, summoning his demonic lieutenants. However, proximity to the active Eye of Aman'thul bestows equally powerful abilities to players, based on their role.",0,14886,0,0,1737,14062,23,0,0},
