    {14974,"Stage One: Divide and Conquer",0,0,0,1,{"wago"},"The Maiden of Vigilance infuses and hammers her enemies with both Holy and Fel magic.",-1,16395,0,0,1897,14975,15,0,0},
    {14975,"Stage Two: Watcher's Wrath",0,0,0,1,{"wago"},"The Maiden of Vigilance jumps away, shields herself, and buffets the raid with Fragments of Creation and Obliteration.",-1,14868,0,0,1897,0,28,0,0},
