    {15588,"Overview",0,3,0,0,{"wago"},"The gatekeeper Supremus cycles between striking a primary target while creating rivers of fel flame, and fixating on random players while littering the area with volcanic geysers.",-1,15589,0,0,1583,15592,1,0,0},
    {15589,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:40265|h[Molten Flame]|h|r caused by |cFF2959D3|Hspell:40126|h[Molten Punch]|h|r.\n\n$bullet;Run from Supremus when you are |cFF2959D3|Hspell:41951|h[Fixated]|h|r.",-1,0,0,2,1583,15590,2,15588,0},
    {15590,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:40265|h[Molten Flame]|h|r caused by |cFF2959D3|Hspell:40126|h[Molten Punch]|h|r.\n\n$bullet;Run from Supremus when you are |cFF2959D3|Hspell:41951|h[Fixated]|h|r.",-1,0,0,4,1583,15591,3,15588,0},
