    {15645,"Overview",0,3,0,0,{"wago"},"As the fight progresses, the Gurtogg swaps between two modes that determine which abilities he uses. In one mode, he afflicts distant targets with deadly maladies, while in the other he fixates on a random player with his full might.",-1,15646,0,0,1586,15649,1,0,0},
    {15646,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Coordinate your positioning with group members to avoid getting too many stacks of |cFF2959D3|Hspell:42005|h[Blood Boil]|h|r.",-1,0,0,2,1586,15647,2,15645,0},
    {15647,"Healers",0,3,0,0,{"wago"},"$bullet;Coordinate your positioning with group members to avoid getting too many stacks of |cFF2959D3|Hspell:42005|h[Blood Boil]|h|r.\n\n$bullet;Heal the ally that is targeted with |cFF2959D3|Hspell:40604|h[Fel Rage]|h|r.",-1,0,0,4,1586,15648,3,15645,0},
    {15648,"Tanks",0,3,0,0,{"wago"},"$bullet;Take turns tanking Gurtogg to keep the application of |cFF2959D3|Hspell:40484|h[Acidic Wound]|h|r in check.",-1,0,0,1,1586,0,4,15645,0},
