    {15687,"Overview",0,3,0,0,{"wago"},"Mother Shahraz will link allies together with |cFF2959D3|Hspell:41001|h[Fatal Attraction]|h|r while also dealing heavy damage to the raid with her Beams.",-1,15688,0,0,1588,15691,1,0,0},
    {15688,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Break the demonic link of |cFF2959D3|Hspell:41001|h[Fatal Attraction]|h|r by running away from allies.\n\n$bullet;Avoid |cFF2959D3|Hspell: 40823|h[Interrupting Shriek]|h|r by staying away from Mother Shahraz.",-1,0,0,18,1588,15689,2,15687,0},
    {15689,"Healers",0,3,0,0,{"wago"},"$bullet;Tanks will take heavy damage from |cFF2959D3|Hspell:40810|h[Saber Lash]|h|r.\n\n$bullet;Break the demonic link of |cFF2959D3|Hspell:41001|h[Fatal Attraction]|h|r by running away from allies.\n\n$bullet;Avoid |cFF2959D3|Hspell: 40823|h[Interrupting Shriek]|h|r by staying away from Mother Shahraz.",-1,0,0,4,1588,15690,3,15687,0},
