    {15700,"Overview",0,3,0,0,{"wago"},"The Illidari Council consists of a powerful paladin, rogue, mage, and priest. They share health and bring their iconic abilities to bear against their foes.",-1,15701,0,0,1589,15704,1,0,0},
    {15701,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Melee damage dealers should avoid striking High Nethermancer Zerevor due to his |cFF2959D3|Hspell:41524|h[Arcane Explosion]|h|r.\n\n$bullet;Interrupt Lady Malande's |cFF2959D3|Hspell:41455|h[Circle of Healing]|h|r.",-1,0,0,2,1589,15702,2,15700,0},
    {15702,"Healers",0,3,0,0,{"wago"},"$bullet;Allies afflicted with Veras's |cFF2959D3|Hspell:41487|h[Envenom]|h|r require urgent healing attention.",-1,0,0,4,1589,15703,3,15700,0},
    {15703,"Tanks",0,3,0,0,{"wago"},"$bullet;Hold the attention of Gathios the Shatterer and Veras Darkshadow.\n\n$bullet;Keep Gathios the Shatterer away from the other members of the council to avoid buffing them with |cFF2959D3|Hspell:41452|h[Devotion Aura]|h|r.",-1,0,0,1,1589,0,4,15700,0},
