    {15775,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Position |cFF2959D3|Hspell:244042|h[Marked Prey]|h|r to avoid being knocked out of range of your allies.\n\n$bullet;Avoid spreading |cFF2959D3|Hspell:244093|h[Necrotic Embrace]|h|r to multiple allies.",0,0,0,2,1983,15776,3,15825,0},
