    {15777,"Tanks",0,3,0,2,{"wago"},"$bullet;Avoid being hit by |cFF2959D3|Hspell:243960|h[Shadow Strike]|h|r while not tanking.",0,0,0,1,1983,16375,6,15825,0},
    {15778,"Torments of the Shivarra",0,0,0,1,{"wago"},"The Coven of Shivarra designed Varimathras' cell to torture him for all time.",-1,15779,0,0,1983,15783,8,0,0},
    {15779,"Section 5",0,2,243967,0,{"wago"},nil,-1,0,0,0,1983,15780,9,15778,0},
