    {16157,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Move away from |cFF2959D3|Hspell:243983|h[Collapsing World]|h|r to prevent being knocked off the platforms.\n\n$bullet;Interrupt and slay demons pouring forth from the |cFF2959D3|Hspell:244677|h[Transport Portal]|h|r when it is opened.",0,0,0,2,1985,15796,2,15803,0},
    {16158,"Healers",0,3,0,2,{"wago"},"$bullet;Allies will suffer high damage when |cFF2959D3|Hspell:244016|h[Reality Tear]|h|r expires.\n\n$bullet;Players within |cFF2959D3|Hspell:245240|h[Oppressive Gloom]|h|r cannot be healed unless they are near an |cFF2959D3|Hspell:245157|h[Everburning Light]|h|r.",0,0,0,4,1985,15797,4,15803,0},
