    {16406,"Overview",0,3,0,0,{"wago"},"Upon reaching 100 Energy, Yazma's calls forth the souls of players affected with |cFF2959D3|Hspell:249924|h[Soulrend]|h|r, creating a |cFF2959D3|Hspell:249926|h[Soulspawn]|h|r that moves towards her.",-1,16407,0,0,2030,17277,1,0,0},
    {16407,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Move away from |cFF2959D3|Hspell:250050|h[Echoes of Shadra]|h|r.\n\n$bullet;Move away from Yazma while affected with |cFF2959D3|Hspell:249924|h[Soulrend]|h|r.\n\n$bullet;Kill Soulspawns before they have a chance to reach Yazma.",-1,0,0,2,2030,16408,2,16406,0},
    {16408,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:250050|h[Echoes of Shadra]|h|r.\n\n$bullet;Move away from Yazma while affected with |cFF2959D3|Hspell:249924|h[Soulrend]|h|r.",-1,0,0,4,2030,16409,3,16406,0},
    {16409,"Tanks",0,3,0,0,{"wago"},"$bullet;Move away from |cFF2959D3|Hspell:250050|h[Echoes of Shadra]|h|r.\n\n$bullet;Consider using damage mitigation when Yazma casts |cFF2959D3|Hspell:249919|h[Skewer]|h|r.",-1,0,0,1,2030,0,4,16406,0},
