    {16564,"Paraxis Inquisitor",0,1,0,2,{"wago"},"The Paraxis Inquisitor controls access to the various control devices aboard the Paraxis. Defeat him to be able to interact with the devices and interrupt the Paraxis' Final Doom attack.",0,16565,63525,4128,2025,0,32,16345,0},
