    {16956,"Stage Two: The Protector Redeemed",0,0,0,0,{"wago"},"When Argus reaches 70% health, Golganneth begins to cast |cFF2959D3|Hspell:256674|h[Golganneth's Wrath]|h|r, clearing away any |cFF2959D3|Hspell:248290|h[Death Fog]|h|r on the platform.",-1,16957,0,0,2031,17069,19,0,0},
    {16957,"Section 21",0,2,252280,0,{"wago"},nil,-1,16958,0,0,2031,16962,20,16956,0},
    {16958,"Section 22",0,2,250669,0,{"wago"},nil,-1,16959,0,0,2031,16960,21,16957,0},
    {16959,"Section 23",0,2,251572,0,{"wago"},"$[14\n\n\n\nOn Normal difficulty, Soulburst Detonation inflicts up to $251572s1 Shadow damage to all players. This amount is reduced the further away players are from the blast, up to a maximum of 35 yards. $]$[15,16\n\n\n\nOn Heroic difficulty and above, Soulburst Detonation inflicts up to $251572s1 Shadow damage to all players. This amount is reduced the further away players are from the blast, up to a maximum of 45 yards. $]",-1,0,0,0,2031,0,22,16958,0},
    {16960,"Section 24",0,2,251570,0,{"wago"},nil,-1,16961,0,16,2031,0,23,16957,0},
    {16961,"Section 25",0,2,251571,0,{"wago"},"$[14,15,16\n\n\n\nOn Normal difficulty, Soulbomb Detonation inflicts up to $251571s1 Shadow damage to all players. This amount is reduced the further away players are from the blast, up to a maximum of 35 yards. $]$[15,16\n\n\n\nOn Heroic difficulty and above, Soulbomb Detonation inflicts up to $251571s1 Shadow damage to all players. This amount is reduced the further away players are from the blast, up to a maximum of 45 yards.$]",-1,0,0,0,2031,0,24,16960,0},
    {16962,"Section 26",0,2,251815,0,{"wago"},nil,-1,0,0,0,2031,16937,25,16956,0},
