    {17067,"Section 33",0,2,249458,2,{"wago"},nil,0,0,0,4096,2004,0,15,16403,0},
    {17068,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Avoid standing next to allies when afflicted with |cFF2959D3|Hspell:246763|h[Fury of Golganneth]|h|r.\n\n$bullet;Defeat Torments of Aman'Thul before they finish casting |cFF2959D3|Hspell:250095|h[Machinations of Aman'Thul]|h|r and are restored to full health.\n\n$bullet;Use abilities to slow the movement of Torments of Norgannon until they are no longer affected by |cFF2959D3|Hspell:249863|h[Visage of the Titan]|h|r.",0,0,0,2,1986,15827,2,15826,0},
    {17069,"Stage Three: The Arcane Masters",0,0,0,2,{"wago"},"When Argus reaches 40% health, he is sufficiently weakened such that Aman'Thul is able to subdue him with a |cFF2959D3|Hspell:257645|h[Temporal Blast]|h|r. However, the players must then contend with Argus' Constellar Designates.",0,17070,0,0,2031,16971,30,0,0},
