    {17157,"Overview",0,3,0,0,{"wago"},"Trothak, the Champion of the Ring of Booty, enters battle using the two sharks strapped to his arms as weapons. Alternating between swinging sharks at nearby enemies and throwing sharks at far away enemies, Trothak is a danger to anyone in his arena.",-1,17158,0,0,2094,17161,1,0,0},
    {17158,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid standing between Trothak and loose sharks to evade taking damage from |cFF2959D3|Hspell:256706|h[Rearm]|h|r.\n\n$bullet;|cFF2959D3|Hspell:256552|h[Flailing Shark]|h|r will move towards its nearest target.",-1,0,0,2,2094,17159,2,17157,0},
