    {17182,"Overview",0,3,0,0,{"wago"},"The Flame Leviathan will target and pursue after random Siege Vehicles and quickly destroy any vehicle that it catches! Use the Vehicles supplied by the Explorers' League to avoid and ensare the Flame Leviathan.",-1,17184,0,0,1637,17186,1,0,0},
    {17183,"Demolisher",0,3,0,0,{"wago"},"$bullet;All Siege Vehicles should flee when Pursued by the Flame Leviathan.\n\n$bullet;Demolisher Drivers can light allied |cFF2959D3|Hspell:62286|h[Tar]|h|r on fire.\n\n$bullet;Demolisher Passengers can also |cFF2959D3|Hspell:64414|h[Load Into Catapult]|h|r, allowing their driver to hurl them on top of the Flame Leviathan.",-1,0,0,0,1637,17185,3,17182,0},
    {17184,"Siege Engine",0,3,0,0,{"wago"},"$bullet;All Siege Vehicles should flee when Pursued by the Flame Leviathan.\n\n$bullet;Siege Engine Drivers should interrupt |cFF2959D3|Hspell:62396|h[Flame Vents]|h|r using |cFF2959D3|Hspell:62522|h[Electroshock]|h|r.\n\n$bullet;Siege Engine Passengers should shoot down Pyrite Ammo from overhead to resupply allies.",-1,0,0,0,1637,17183,2,17182,0},
