    {17330,"Overview",0,3,0,0,{"wago"},"Kologarn's arms can be destroyed, restricting his ability to use abilities. When Kologarn's Right or Left arm are destroyed Rubble will appear.",-1,17331,0,0,1642,17338,1,0,0},
    {17331,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Quickly attack the Right Arm when it casts |cFF2959D3|Hspell:64290|h[Stone Grip]|h|r to free your allies.\n\n$bullet;Flee when targeted with |cFF2959D3|Hspell:63346|h[Focused Eyebeam]|h|r to avoid heavy damage.",-1,0,0,2,1642,17332,2,17330,0},
    {17332,"Healers",0,3,0,0,{"wago"},"$bullet;Flee when targeted with |cFF2959D3|Hspell:63346|h[Focused Eyebeam]|h|r to avoid heavy damage.\n\n$bullet;Expect heavy damage on your allies afflicted with |cFF2959D3|Hspell:64290|h[Stone Grip]|h|r.",-1,0,0,4,1642,17333,3,17330,0},
    {17333,"Tanks",0,3,0,0,{"wago"},"$bullet;Quickly gain the attention of the Rubble that spawn when an Arm of Kologarn is destroyed.\n\n$bullet;|cFF2959D3|Hspell:63356|h[Overhead Smash]|h|r inflicts heavy Physical damage and applies |cFF2959D3|Hspell:63355|h[Crunch Armor]|h|r.",-1,0,0,1,1642,0,4,17330,0},
