    {17475,"Overview",0,3,0,0,{"wago"},"|cFF2959D3|Hspell:259830|h[Boundless Rot]|h|r summons spore pods throughout the area. Upon reacing 100 Energy, Zancha casts |cFF2959D3|Hspell:259732|h[Festering Harvest]|h|r destroying any remaining spore pods and applying the effects of |cFF2959D3|Hspell:273226|h[Decaying Spores]|h|r to all players.",-1,17476,0,0,2130,17490,1,0,0},
    {17476,"Healers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:259714|h[Rotting Spores]|h|r inflicts direct damage and significant damage over time.\n\n$bullet; |cFF2959D3|Hspell:259718|h[Upheaval] |h|r inflicts substantial damage.",-1,0,0,4,2130,17477,2,17475,0},
