    {17579,"Overview",0,3,0,0,{"wago"},"Mimiron engages his enemies with inventions rather than directly in combat. The Leviathan MK II is a deadly vehicle that assaults the Tank with powerful attacks, the VX-001 which strikes enemies with rocket blasts and laser barrages, the Aerial Command Unit which engages enemies from the skies, and finally the V0-L7R-0N unit, which combines the might of all of his inventions.",-1,17580,0,0,1647,17583,1,0,0},
    {17580,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid the Leviathan Mk II's |cFF2959D3|Hspell:63016|h[Proximity Mines]|h|r when fleeing from |cFF2959D3|Hspell:63631|h[Shock Blast]|h|r.\n\n$bullet;Be spread apart to avoid the Leviathan Mk II's |cFF2959D3|Hspell:63666|h[Napalm Shell]|h|r.\n\n$bullet;Rotate away from VX-001's |cFF2959D3|Hspell:63293|h[P3Wx2 Laser Barrage]|h|r ability.\n\n$bullet;Use the Magnetic Core dropped by the Assault Bot to ground the Aerial Command Unit.",-1,0,0,2,1647,17581,2,17579,0},
    {17581,"Healers",0,3,0,0,{"wago"},"$bullet;Be spread apart to avoid the Leviathan Mk II's |cFF2959D3|Hspell:63666|h[Napalm Shell]|h|r.\n\n$bullet;Prepare for heavy damage on the Tank when the Leviathan Mk II casts |cFF2959D3|Hspell:62997|h[Plasma Blast]|h|r.\n\n$bullet;Rotate away from VX-001's |cFF2959D3|Hspell:63293|h[P3Wx2 Laser Barrage]|h|r ability.",-1,0,0,4,1647,17582,3,17579,0},
    {17582,"Tanks",0,3,0,0,{"wago"},"$bullet;Prepare for heavy damage when the Leviathan Mk II casts |cFF2959D3|Hspell:62997|h[Plasma Blast]|h|r.\n\n$bullet;Rotate away from VX-001's |cFF2959D3|Hspell:63293|h[P3Wx2 Laser Barrage]|h|r ability.\n\n$bullet;Use the Magnetic Core dropped by the Assault Bot to ground the Aerial Command Unit.",-1,0,0,1,1647,0,4,17579,0},
