    {17636,"Section 9",0,2,259940,0,{"wago"},nil,-1,0,0,0,2115,0,9,0,0},
    {17637,"Overview",0,3,0,0,{"wago"},"General Vezax inflicts all healers with |cFF2959D3|Hspell:62692|h[Aura of Despair]|h|r, removing all mana regeneration. Mana can be restored by utilizing the |cFF2959D3|Hspell:63338|h[Saronite Vapors ]|h|r that coalesce on the ground in the area.",-1,17638,0,0,1648,17641,1,0,0},
    {17638,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Interrupt |cFF2959D3|Hspell:62661|h[Searing Flames]|h|r to avoid heavy damage.\n\n$bullet;Avoid damaging allies while afflicted with |cFF2959D3|Hspell:63276|h[Mark of the Faceless]|h|r.",-1,0,0,2,1648,17639,2,17637,0},
    {17639,"Healers",0,3,0,0,{"wago"},"$bullet;Avoid damaging allies while afflicted with |cFF2959D3|Hspell:63276|h[Mark of the Faceless]|h|r.\n\n$bullet;Use |cFF2959D3|Hspell:63338|h[Saronite Vapors ]|h|r to regenerate Mana.",-1,0,0,4,1648,17640,3,17637,0},
    {17640,"Tanks",0,3,0,0,{"wago"},"$bullet;Flee when Vezax gains |cFF2959D3|Hspell:62662|h[Surge of Darkness]|h|r to avoid heavy damage.",-1,0,0,1,1648,0,4,17637,0},
