    {17713,"Immortal Guardian",0,1,0,0,{"wago"},"Immortal Guardians can only be killed by Thorim's |cFF2959D3|Hspell:64171|h[Titanic Storm]|h|r.",-1,17714,29024,0,1649,0,58,17707,0},
    {17714,"Section 59",0,2,65294,0,{"wago"},nil,-1,0,0,0,1649,0,59,17713,0},
    {17715,"Hard Mode",0,0,0,0,{"wago"},"Battling Yogg-Saron without the aid of some or all of the Keepers of Ulduar for assistance is possible, but extremely dangerous.",-1,17733,0,0,1649,0,60,0,0},
    {17716,"Section 61",0,2,64189,0,{"wago"},nil,-1,0,0,0,1649,0,62,17733,0},
    {17717,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Kill Irontide forces.\n\n$bullet;When the target of |cFF2959D3|Hspell:257459|h[On the Hook]|h|r, run away.",-1,0,0,2,2132,17718,2,17708,0},
    {17718,"Healers",0,3,0,0,{"wago"},"$bullet;Irontide Powdershots inflict damage to everyone in the party.\n\n$bullet;If |cFF2959D3|Hspell:273716|h[Heavy Ordnance]|h|r explodes it does massive damage to the party.\n\n$bullet;When the target of |cFF2959D3|Hspell:257459|h[On the Hook]|h|r, run away.",-1,0,0,4,2132,17719,3,17708,0},
    {17719,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid being in melee range with Chopper Redhook due to |cFF2959D3|Hspell:256867|h[Heavy Hitter]|h|r.\n\n$bullet;Face Irontide Cleaver's |cFF2959D3|Hspell:257292|h[Heavy Slash]|h|r away from the party.\n\n$bullet;Run over |cFF2959D3|Hspell:273716|h[Heavy Ordnance]|h|r to prevent them from damaging the party.",-1,0,0,1,2132,0,4,17708,0},
    {17720,"Section 5",0,2,256867,2,{"wago"},nil,2,0,0,32,2132,17721,5,0,0},
