    {17726,"Section 11",0,2,257292,2,{"wago"},nil,2,0,0,0,2132,0,15,17725,0},
    {17727,"Irontide Powdershot",0,1,0,2,{"wago"},"An Irontide marksman capable of inflicting damage to the party.",2,17728,79070,0,2132,18873,16,0,0},
