    {17762,"Kul Tiran Vanguard",0,1,0,2,{"wago"},"A bruiser with a heavy melee attack.",2,17763,82441,1,2133,17764,12,0,0},
    {17763,"Section 14",0,2,257292,2,{"wago"},nil,2,0,0,0,2133,0,13,17762,0},
    {17764,"Kul Tiran Marksman",0,1,0,2,{"wago"},"An marksman capable of inflicting damage to the party.",2,17765,81746,0,2133,18870,14,0,0},
    {17765,"Section 16",0,2,257641,2,{"wago"},nil,2,0,0,0,2133,0,15,17764,0},
    {17769,"Overview",0,3,0,0,{"wago"},"Lord Waycrest engages the party directly, with Lady Waycrest assisting by using her organ to attack. When Lord Waycrest is defeated, Lady Waycrest casts |cFF2959D3|Hspell:261446|h[Vitality Transfer]|h|r to bring him back at the cost of her own life. At 10% remaining health, Lady Waycrest joins the fight.",-1,17770,0,0,2128,17773,1,0,0},
    {17770,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:261439|h[Virulent Pathogen]|h|r can be cleansed off party members.\n\n$bullet;Move to avoid |cFF2959D3|Hspell:268306|h[Discordant Cadenza]|h|r.",-1,0,0,4,2128,17771,2,17769,0},
    {17771,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Focus damage on Lord Waycrest until Lady Waycrest enters the fight.\n\n$bullet;Move away from your party to avoid spreading |cFF2959D3|Hspell:261439|h[Virulent Pathogen]|h|r.\n\n$bullet;Move to avoid |cFF2959D3|Hspell:268306|h[Discordant Cadenza]|h|r.",-1,0,0,2,2128,17772,3,17769,0},
    {17772,"Tanks",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:261447|h[Putrid Vitality]|h|r increases Lord Waycrest's damage over the course of the fight.\n\n$bullet;Move to avoid |cFF2959D3|Hspell:268306|h[Discordant Cadenza]|h|r.",-1,0,0,1,2128,0,4,17769,0},
    {17773,"Lady Waycrest",0,1,0,1,{"wago"},nil,-1,17774,87188,0,2128,17777,5,0,0},
    {17774,"Section 6",0,2,268271,0,{"wago"},nil,-1,0,0,0,2128,17775,6,17773,0},
    {17775,"Section 7",0,2,268306,0,{"wago"},nil,-1,0,0,32,2128,17776,7,17773,0},
    {17776,"Section 11",0,2,261446,0,{"wago"},nil,-1,0,0,0,2128,0,8,17773,0},
    {17777,"Lord Waycrest",0,1,0,1,{"wago"},nil,-1,17778,23136,0,2128,0,9,0,0},
