    {17970,"Galecaller Faye",0,1,0,1,{"wago"},nil,-1,18149,83273,0,2154,18154,5,0,0},
    {17971,"Ability",0,2,267034,0,{"wago"},nil,-1,0,0,128,2156,18241,7,0,0},
    {17972,"Ability",0,2,268347,0,{"wago"},nil,-1,0,0,64,2155,18235,5,0,0},
