    {17976,"Ability",0,2,269185,1,{"wago"},nil,-1,18312,0,32,2158,18314,5,0,0},
    {17989,"Overview",0,3,0,0,{"wago"},"The Golden Serpent spits gold at party members, who then leave it behind in the form of |cFF2959D3|Hspell:265914|h[Molten Gold]|h|r. The Golden Serpent will later animate these pools of gold with |cFF2959D3|Hspell:265923|h[Lucre's Call]|h|r. Kill the animated molten gold before it reaches him to avoid having it empower him with |cFF2959D3|Hspell:265991|h[Luster]|h|r.",-1,17990,0,0,2165,17993,1,0,0},
    {17990,"Tank",0,3,0,0,{"wago"},"$bullet;When The Golden Serpent uses |cFF2959D3|Hspell:265923|h[Lucre's Call]|h|r, move it away from pools of gold to give players a chance to kill Animated Gold before they reach the boss.\n\n$bullet;|cFF2959D3|Hspell:265908|h[Tail Thrash]|h|r deals heavy Physical damage.",-1,0,0,1,2165,17991,2,17989,0},
    {17991,"Healer",0,3,0,0,{"wago"},"$bullet;Players afflicted with |cFF2959D3|Hspell:265773|h[Spit Gold]|h|r will take heavy damage.",-1,0,0,4,2165,17992,3,17989,0},
    {17992,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Move away from the Golden Serpent and your group members when afflicted by |cFF2959D3|Hspell:265773|h[Spit Gold]|h|r to better place |cFF2959D3|Hspell:265914|h[Molten Gold]|h|r.\n\n$bullet;Use stuns, roots, and knockback effects to help your group prevent Animated Gold from reaching The Golden Serpent.",-1,0,0,2,2165,0,4,17989,0},
    {17993,"Section 5",0,2,265773,2,{"wago"},nil,2,17994,0,0,2165,17995,5,0,0},
    {17994,"Section 6",0,2,265914,2,{"wago"},nil,2,0,0,0,2165,0,6,17993,0},
    {17995,"Section 7",0,2,265923,2,{"wago"},nil,2,17996,0,0,2165,17998,7,0,0},
    {17996,"Animated Gold",0,1,0,2,{"wago"},"Attempts to move towards The Golden Serpent. If any reach it, The Golden Serpent absorbs them and gains a stack of Luster. When any Animated Gold are killed, they return to pools of Molten Gold.",2,17997,33011,0,2165,0,8,17995,0},
    {17997,"Section 9",0,2,265991,2,{"wago"},nil,2,0,0,0,2165,0,9,17996,0},
