    {18004,"Section 6",0,2,265129,0,{"wago"},nil,-1,18005,0,32,2166,18846,5,0,0},
    {18005,"Section 5",0,2,265127,2,{"wago"},nil,0,18626,0,0,2166,18625,6,18004,0},
    {18006,"Section 7",0,2,265178,0,{"wago"},nil,-1,0,0,1,2166,18054,15,18846,0},
    {18007,"Plague Amalgam",0,1,0,0,{"wago"},nil,-1,18008,50689,0,2166,0,18,18017,0},
    {18008,"Section 9",0,2,265206,0,{"wago"},nil,-1,0,0,0,2166,0,19,18007,0},
    {18009,"Section 10",0,2,265217,0,{"wago"},nil,-1,18010,0,0,2166,18052,21,18847,0},
    {18010,"Section 11",0,2,265370,0,{"wago"},nil,-1,0,0,0,2166,0,22,18009,0},
    {18011,"Overview",0,3,0,0,{"wago"},"Pass through |cFF2959D3|Hspell:267821|h[Defense Grids]|h|r to reach the final chamber of the Hall of Sanitation.\n\n\n\nReaching the third and final chamber cleanses the raid of all corruption, and inflicts MOTHER with |cFF2959D3|Hspell:274205|h[Depleted Energy]|h|r.\n\n\n\nWhen MOTHER is first active in any chamber she will begin a countdown to activate |cFF2959D3|Hspell:268095|h[Cleansing Purge]|h|r within that chamber.",-1,18012,0,0,2167,18133,1,0,0},
    {18012,"Tanks",0,3,0,0,{"wago"},"$bullet;Coordinate with your allies to pass through the |cFF2959D3|Hspell:267821|h[Defense Grids]|h|r.\n\n$bullet;Coordinate with the other tank to maintain as few stacks of |cFF2959D3|Hspell:267787|h[Sanitizing Strike]|h|r as possible.\n\n$bullet;Round up Remnants of Corruption to keep them from attacking your allies.",-1,0,0,1,2167,18013,2,18011,0},
    {18013,"Healers",0,3,0,0,{"wago"},"$bullet;Coordinate with your allies to pass through the |cFF2959D3|Hspell:267821|h[Defense Grids]|h|r.\n\n$bullet;Avoid standing in front of MOTHER so as not to take damage from |cFF2959D3|Hspell:267787|h[Sanitizing Strike]|h|r.\n\n$bullet;Allies will take significant damage when passing through the |cFF2959D3|Hspell:267821|h[Defense Grids]|h|r.",-1,0,0,4,2167,18014,3,18011,0},
    {18014,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Coordinate with your allies to pass through the |cFF2959D3|Hspell:267821|h[Defense Grids]|h|r.\n\n$bullet;Avoid standing in front of MOTHER so as not to take damage from |cFF2959D3|Hspell:267787|h[Sanitizing Strike]|h|r.\n\n$bullet;Interrupt |cFF2959D3|Hspell:268198|h[Clinging Corruption]|h|r cast by Remnants of Corruption.",-1,0,0,2,2167,0,4,18011,0},
    {18017,"Section 14",0,2,265212,0,{"wago"},nil,-1,18007,0,0,2166,0,17,18846,0},
    {18018,"Overview",0,3,0,0,{"wago"},"Taloc's blood-fueled magic will flood the room with |cFF2959D3|Hspell:270290|h[Blood Storms]|h|r. His powerful |cFF2959D3|Hspell:271296|h[Cudgel of Gore]|h|r will absorb nearby |cFF2959D3|Hspell:270290|h[Blood Storms]|h|r.\n\n\n\nAt 35% health, Taloc's fuel spills into the arena causing him to |cFF2959D3|Hspell:271965|h[Power Down]|h|r and spawn Coalesced Blood and Volatile Droplets.\n\n\n\nVolatile Droplets will continue to spawn once Taloc reabsorbs his fuel, canceling |cFF2959D3|Hspell:271965|h[Powered Down]|h|r and engaging the raid once more.",-1,18019,0,0,2168,18434,1,0,0},
    {18019,"Tanks",0,3,0,0,{"wago"},"$bullet;Aim the |cFF2959D3|Hspell:271296|h[Cudgel of Gore]|h|r to clear away |cFF2959D3|Hspell:270290|h[Blood Storms]|h|r.\n\n$bullet;Taunt Coalesced Bloods while Taloc is disabled to keep them away from your allies.",-1,0,0,1,2168,18020,2,18018,0},
    {18020,"Healers",0,3,0,0,{"wago"},"$bullet;Allies will take significant damage when afflicted with |cFF2959D3|Hspell:271222|h[Plasma Discharge]|h|r.\n\n$bullet;Avoid standing close to an ally targeted by |cFF2959D3|Hspell:271296|h[Cudgel of Gore]|h|r.\n\n$bullet;Avoid standing in front of Taloc when he casts |cFF2959D3|Hspell:272582|h[Sanguine Static]|h|r.",-1,0,0,4,2168,18021,3,18018,0},
    {18021,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid standing close to an ally targeted by |cFF2959D3|Hspell:271296|h[Cudgel of Gore]|h|r.\n\n$bullet;Defeat Volatile Droplets before they can reach an ally and inflict |cFF2959D3|Hspell:272584|h[Combustible Fuel]|h|r.\n\n$bullet;Avoid standing in front of Taloc when he casts |cFF2959D3|Hspell:272582|h[Sanguine Static]|h|r.",-1,0,0,2,2168,0,4,18018,0},
    {18023,"Section 5",0,2,267787,0,{"wago"},nil,-1,0,0,1,2167,18128,18,0,0},
    {18024,"Noxious Breath",136182,2,0,0,{"wago"},"The caster exhales a series of toxic missiles that will leave toxic pools wherever they land.",-1,18032,0,0,2143,18025,9,0,0},
