    {18036,"Section 8",0,2,265974,2,{"wago"},"$[!1,2,23\n\n\n\nThe damage of Induction is increased by Galvazzt's level of Capacitance.$]",2,0,0,4,2144,18037,10,0,0},
    {18037,"Chaotic Spark",0,1,0,2,{"wago"},"Chase down a random player for up to 30 seconds and will Short Circuit Galvazzt or any player they get close to.",0,18038,47376,0,2144,18922,11,0,0},
    {18038,"Short Circuit",237587,2,0,2,{"wago"},"Inflicts Nature damage to any player affected by this spell and stuns them for $266031d.\n\n$[!0,1,2,23 If Galvazzt is hit with this, he is Galvanized for $266034s energy instead.$]",0,0,0,32,2144,0,12,18037,0},
    {18039,"Overview",0,3,0,0,{"wago"},"Gorak Tul uses his magics to inflict ever increasing pain against his opponents, both through |cFF2959D3|Hspell:266225|h[Darkened Lightning]|h|r and |cFF2959D3|Hspell:268202|h[Death Lens]|h|r. Additionally, he calls in Deathtouched Slavers from within his realm. Deathtouched Slavers can not be killed by any traditional means, and are resurrected by |cFF2959D3|Hspell:266181|h[Dread Essence]|h|r. |cFF2959D3|Hspell:266198|h[Alchemical Fire]|h|r can be used to destroy them for good.",-1,18866,0,0,2129,18043,1,0,0},
    {18040,"Healers",0,3,0,2,{"wago"},"$bullet; Avoid being hit by |cFF2959D3|Hspell:266225|h[Darkened Lightning]|h|r by staying spread apart.\n\n$bullet; Use |cFF2959D3|Hspell:266198|h[Alchemical Fire]|h|r to destroy Deathtouched Slaver's corpses.\n\n$bullet; |cFF2959D3|Hspell:268202|h[Death Lens]|h|r inflicts a large portion of the player's maximum health in damage.",2,0,0,4,2129,18867,3,18039,0},
    {18041,"Tanks",0,3,0,2,{"wago"},"$bullet; Make sure to pick up any Deathtouched Slavers summoned by Gorak Tul.\n\n$bullet; Use |cFF2959D3|Hspell:266198|h[Alchemical Fire]|h|r to destroy Deathtouched Slaver's corpses.\n\n$bullet; |cFF2959D3|Hspell:268202|h[Death Lens]|h|r inflicts a large portion of the player's maximum health in damage.",2,0,0,1,2129,18868,5,18039,0},
    {18042,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; Avoid being hit by |cFF2959D3|Hspell:266225|h[Darkened Lightning]|h|r by staying spread apart.\n\n$bullet; Use |cFF2959D3|Hspell:266198|h[Alchemical Fire]|h|r to destroy Deathtouched Slaver's corpses.\n\n$bullet; |cFF2959D3|Hspell:268202|h[Death Lens]|h|r inflicts a large portion of the player's maximum health in damage.",2,0,0,2,2129,0,7,18039,0},
