    {18055,"Section 6",0,2,267299,2,{"wago"},nil,2,18056,0,8,2156,18092,9,0,0},
    {18056,"Manifestation of the Deep",0,1,0,0,{"wago"},"Manifestations crawl towards Vol'zith, attempting to power it with deep energy.",-1,18080,68714,2,2156,0,10,18055,0},
    {18057,"Overview",0,3,0,0,{"wago"},"Zek'voz attacks players while the compromised Titan Discs come online, calling forth powerful Old God magics and summoning their lesser servants. As new Titan Discs come online, previously activated Discs will power down.",-1,18058,0,0,2169,18068,1,0,0},
    {18058,"Tanks",0,3,0,0,{"wago"},"$bullet; Avoid being struck by |cFF2959D3|Hspell:265264|h[Void Lash]|h|r multiple times during |cFF2959D3|Hspell:267312|h[Might of the Void]|h|r.\n\n$bullet; Consider the position of your allies when redirecting casts of |cFF2959D3|Hspell:265264|h[Void Lash]|h|r.\n\n$bullet; Interrupt and crowd control allies under the effects of |cFF2959D3|Hspell:265646|h[Will of the Corruptor]|h|r.",-1,0,0,1,2169,18059,2,18057,0},
    {18059,"Healers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:264954|h[Titan Spark]|h|r strikes random targets periodically.\n\n$bullet; |cFF2959D3|Hspell:265451|h[Surging Darkness]|h|r inflicts substantial damage to all party members in addition to the lethal damage within each eruption.\n\n$bullet; |cFF2959D3|Hspell:267334|h[Orb of Corruption]|h|r inflicts significant raid damage to all party members if it lands.",-1,0,0,4,2169,18060,3,18057,0},
    {18060,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Keep a safe distance from your allies when |cFF2959D3|Hspell:264382|h[Eye Beam]|h|r is preparing to fire.\n\n$bullet; Consider your positioning when |cFF2959D3|Hspell:265360|h[Roiling Deceit]|h|r is about to expire.\n\n$bullet; Intercept |cFF2959D3|Hspell:267334|h[Orb of Corruption]|h|r to gain |cFF2959D3|Hspell:265662|h[Corruptor's Pact]|h|r.",-1,0,0,2,2169,0,4,18057,0},
    {18062,"Stage One: Chaos and Deception",0,0,0,2,{"wago"},"Chaos and Deception Protocols activate, summoning projections of C'Thun and Yogg-Saron along with their minions.\n\n\n\n$[!16 In Mythic difficulty, activated Titan Discs remain powered on indefinitely.$]",0,18070,0,0,2169,18069,30,0,0},
    {18063,"Stage Two: Deception",0,0,0,2,{"wago"},"At $267599s1% health remaining Protocol: Deception begins, summoning projections of Yogg-Saron and replicating servants from Azjol-Nerub.",0,18393,0,0,2169,18400,15,0,0},
    {18064,"Incantations of the Void",0,2,267312,0,{"wago"},nil,-1,18065,0,1,2169,18388,7,0,0},
