    {18069,"Stage Two: Corruption",0,0,0,2,{"wago"},"At $267600s1% health remaining Protocol: Corruption begins. The magic released from the damaged Titan Discs appears to be unchecked and more than a mere demonstration of power...",0,18087,0,0,2169,0,44,0,0},
