    {18073,"Section 17",0,2,264210,1,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, Jagged Mandible also reduces movement speed by $264210s3%.$]",-1,0,0,0,2169,0,38,18071,0},
    {18074,"Section 18",0,2,265360,0,{"wago"},nil,-1,18075,0,32,2169,18071,32,18062,0},
    {18075,"Ominous Cloud",0,0,0,0,{"wago"},"Ominous Clouds slowly drift through the area and will boil ominously if an enemy strays too close, summoning a Guardian of Yogg-Saron.",-1,18130,0,0,2169,0,33,18074,0},
    {18078,"Nerubian Voidweaver",0,2,0,0,{"wago"},nil,-1,18346,24130,0,2169,0,39,18062,0},
