    {18081,nil,0,2,267334,0,{"wago"},nil,-1,18342,0,48,2169,18234,46,18069,0},
    {18087,"Overload",1519263,2,0,0,{"wago"},"The damaged disc activates, increasing the frequency of |cFF2959D3|Hspell:264954|h[Titan Spark]|h|r.",-1,0,0,0,2169,18081,45,18069,0},
    {18088,"Section 12",0,2,259205,2,{"wago"},nil,2,0,0,8,2082,0,13,0,0},
    {18090,"Tanks",0,3,0,2,{"wago"},"$bullet;Save damage reducing abilities for |cFF2959D3|Hspell:255579|h[Gilded Claws]|h|r.\n\n$bullet;Stand near a pool of |cFF2959D3|Hspell:255558|h[Tainted Blood]|h|r and step into it just as Priestess Alun'za begins casting |cFF2959D3|Hspell:255577|h[Transfusion]|h|r.\n\n$bullet;The |cFF2959D3|Hspell:259205|h[Spirits of Gold]|h|r will ignore combat unless there are no pools of |cFF2959D3|Hspell:255558|h[Tainted Blood]|h|r nearby.",2,0,0,1,2082,16829,3,16822,0},
    {18091,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Stand near a pool of |cFF2959D3|Hspell:255558|h[Tainted Blood]|h|r and step into it just as Priestess Alun'za begins casting |cFF2959D3|Hspell:255577|h[Transfusion]|h|r.\n\n$bullet;|cFF2959D3|Hspell:258709|h[Corrupted Gold]|h|r will lower the damage you deal in addition to damaging you.\n\n$bullet;|cFF2959D3|Hspell:259205|h[Spirits of Gold]|h|r will absorb |cFF2959D3|Hspell:255558|h[Tainted Blood]|h|r unless they are dispatched.",2,0,0,2,2082,0,6,16822,0},
