    {18220,"Section 17",0,2,263365,0,{"wago"},"$[!1,2,23\n\n\n\nAdderis uses this ability when he has 50 energy.$]",-1,0,0,16,2142,17921,18,18485,0},
    {18221,"Overview",0,3,0,0,{"wago"},"Dread Captain Lockwood continually retreats from players using |cFF2959D3|Hspell:272471|h[Evasive]|h|r and assaults them with |cFF2959D3|Hspell:273470|h[Gut Shot]|h|r.\n\n\n\nUpon reaching 66% and 33% health, Dread Captain Lockwood |cFF2959D3|Hspell:268752|h[Withdraws]|h|r to her ship and her crew assaults the party while the area is constantly bombarded by |cFF2959D3|Hspell:268443|h[Dread Volley]|h|r.\n\n\n\n|cFF2959D3|Hspell:268976|h[Unstable Ordnance]|h|r must be used to bombard Captain Lockwood's ship and return her to the battlefield.",-1,18222,0,0,2173,30256,1,0,0},
    {18222,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Pickup |cFF2959D3|Hspell:268976|h[Unstable Ordnance]|h|r and use it to damage the ship.\n\n$bullet;|cFF2959D3|Hspell:463182|h[Fiery Ricochet]|h|r bounces to 2 additional players and inflicts additional Fire damage.",-1,0,0,2,2173,18223,2,18221,0},
    {18223,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:463182|h[Fiery Ricochet]|h|r bounces to 2 additional players and inflicts additional Fire damage.\n\n$bullet;|cFF2959D3|Hspell:273470|h[Gut Shot]|h|r continually damages random party members.",-1,0,0,4,2173,18224,3,18221,0},
    {18224,"Tanks",0,3,0,0,{"wago"},"$bullet;Face Ashvane Deckhand's |cFF2959D3|Hspell:268230|h[Crimson Swipe]|h|r away from the party.\n\n$bullet;Avoid |cFF2959D3|Hspell:269029|h[Clear the Deck]|h|r.",-1,0,0,1,2173,0,4,18221,0},
