    {18599,"Overview",0,3,0,0,{"wago"},"Azurethos attacks the party with the power of wind in an attempt to force them out of its roost.",-1,18600,0,0,2199,18603,1,0,0},
    {18600,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:274832|h[Wing Buffet]|h|r - and if you are hit by it, quickly re-establish threat.\n\n$bullet;Move away from the boss when he begins casting |cFF2959D3|Hspell:274839|h[Azurethos' Fury]|h|r to make dodging tornados easier.\n\n$bullet;Azurethos will move to a random player when casting |cFF2959D3|Hspell:274822|h[Gale Force]|h|r - be sure you are not standing in front of him when it goes off, or you risk being knocked off of the mountain!",-1,0,0,1,2199,18601,2,18599,0},
    {18601,"Healers",0,3,0,0,{"wago"},"$bullet;Move away from the boss when he begins casting |cFF2959D3|Hspell:274839|h[Azurethos' Fury]|h|r to make dodging tornados easier.\n\n$bullet;Azurethos will move to a random player when casting |cFF2959D3|Hspell:274822|h[Gale Force]|h|r - be sure you are not standing in front of him when it goes off, or you risk being knocked off of the mountain!",-1,0,0,4,2199,18602,3,18599,0},
    {18602,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Move away from the boss when he begins casting |cFF2959D3|Hspell:274839|h[Azurethos' Fury]|h|r to make dodging tornados easier.\n\n$bullet;Azurethos will move to a random player when casting |cFF2959D3|Hspell:274822|h[Gale Force]|h|r - be sure you are not standing in front of him when it goes off, or you risk being knocked off of the mountain!",-1,0,0,2,2199,0,4,18599,0},
