    {18916,"Stage One: Big Guns",0,0,0,1,{"wago"},nil,-1,18927,0,0,2116,17498,5,0,0},
    {18917,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; Deposit |cFF2959D3|Hspell:263372|h[Power Matrices]|h|r to trigger a |cFF2959D3|Hspell:263503|h[Reorigination Blast]|h|r.\n\n$bullet; Be sure to interrupt the Blightspreader Tendril's |cFF2959D3|Hspell:267462|h[Decaying Eruption]|h|r.\n\n$bullet; Remember, |cFF2959D3|Hspell:263236|h[Blood Feast]|h|r can reset your stacks of |cFF2959D3|Hspell:263334|h[Putrid Blood]|h|r.\n\n$bullet; Face away from G'huun when he casts |cFF2959D3|Hspell:267700|h[Gaze of G'huun]|h|r.",0,0,0,2,2147,17873,4,17870,0},
    {18918,"Section 57",0,2,270428,2,{"wago"},nil,0,18919,0,0,2147,18329,47,18161,0},
