    {18991,"Overview",0,3,0,0,{"wago"},"Ivus the Forest Lord often uses abilities to attack several players at random and will retreat to the safety of his |cFF2959D3|Hspell:282615|h[Petrified Bark]|h|r when at low health.",-1,18992,0,0,2329,18995,1,0,0},
    {18992,"Tanks",0,3,0,0,{"wago"},"$bullet;Ivus will cast |cFF2959D3|Hspell:282404|h[Frost Breath]|h|r in your direction, leaving a |cFF2959D3|Hspell:282414|h[Frost Patch]|h|r on the ground beneath you.\n\n$bullet;|cFF2959D3|Hspell:282487|h[Lunar Strike]|h|r will leave a few clear areas on initial impact before spreading.\n\n$bullet;Wisps summoned while Ivus is |cFF2959D3|Hspell:282615|h[Petrified]|h|r fixate on players at random and cannot be controlled through threat generation.",-1,0,0,1,2329,18993,2,18991,0},
    {18993,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:282431|h[Hurl Boulder]|h|r will hit players at random.\n\n$bullet;|cFF2959D3|Hspell:282487|h[Lunar Strike]|h|r will leave a few clear areas on initial impact before spreading.\n\n$bullet;Wisps will channel |cFF2959D3|Hspell:282622|h[Ancient Spark]|h|r on a random player until they are dispatched.",-1,0,0,4,2329,18994,3,18991,0},
    {18994,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:282431|h[Hurl Boulder]|h|r hits players at random.\n\n$bullet;|cFF2959D3|Hspell:282487|h[Lunar Strike]|h|r will leave a few clear areas on initial impact before spreading.\n\n$bullet;Ivus will remain immune to damage while |cFF2959D3|Hspell:282615|h[Petrified]|h|r. Dispatch all active Wisps to make Ivus end the Petrification.",-1,0,0,2,2329,0,4,18991,0},
