    {19069,"Crusader's Seals",0,0,0,0,{"wago"},"At the beginning of the fight, Frida Ironbellows will cast a seal upon herself, giving her additional abilities and causing her to gain Energy. At 100 Energy, she releases the seal, causing an additional effect.",-1,19070,0,32,2333,19077,15,0,0},
    {19070,"Section 16",0,2,283955,0,{"wago"},nil,-1,0,0,0,2333,19071,16,19069,0},
    {19071,"Section 10",0,2,284469,0,{"wago"},"$[\n\n\n\nAt 100 energy, the seal is released, giving an ally Righteous Blessing.",-1,19140,0,0,2333,19137,17,19069,0},
