    {19087,"Stage Three: Hyperdrive!",0,2,0,1,{"wago"},nil,-1,19774,0,0,2334,19787,46,0,0},
    {19095,"Section 9",0,2,284042,0,{"wago"},"Mekkatorque periodically calls in Spark Bot units to seek out his enemies.\n\n$[!15\n\n\n\nIn Heroic difficulty, Hyperdrive causes Mekkatorque to deploy an additional Spark Bot.$]$[!16\n\n\n\nIn Mythic difficulty, Hyperdrive causes Mekkatorque to deploy an additional Spark Bot.$]",-1,19096,0,0,2334,19725,61,19087,0},
    {19096,"Spark Bot",0,2,0,1,{"wago"},"Players affected by |cFF2959D3|Hspell:284168|h[Shrunken]|h|r can tamper with Spark Bots and shut them down from within.",-1,19734,28573,0,2334,0,62,19095,0},
