    {19137,"Section 23",0,2,284436,0,{"wago"},"$[\n\n\n\nAt 100 energy, the seal is released, causing the wearer to cast |cFF2959D3|Hspell:284474|h[Judgment: Reckoning]|h|r.",-1,19138,0,0,2333,0,21,19069,0},
    {19138,"Section 25",0,2,284449,0,{"wago"},nil,-1,0,0,0,2333,19139,22,19137,0},
