    {19250,"Section 15",0,2,284831,2,{"wago"},nil,0,0,0,1,2335,19808,78,19244,0},
    {19252,"Overview",0,3,0,0,{"wago"},"Working to cover the main portion of the Alliance fleet as they fell back, a cadre of Stormsong tidepriests have established a blockade and summoned an overwhelming elemental to wash away Dazar'alor's port area. Re-establish a foothold on the docks, overrun the alliance ships and return the summoned monstrosity back to the deep before they destroy a large portion of the city.",-1,19253,0,0,2337,19425,1,0,0},
    {19253,"Tanks",0,3,0,0,{"wago"},"$bullet; Interrupt Brother Joseph's and Sister Katherine's Empowerments when you can.\n\n$bullet; Use |cFF2959D3|Hspell:285000|h[Kelp-Wrapped Fists]|h|r to slow Energizing Storms.",-1,0,0,1,2337,19254,2,19252,0},
    {19254,"Healers",0,3,0,0,{"wago"},"$bullet; If affected by |cFF2959D3|Hspell:284405|h[Tempting Song]|h|r, try to position yourself as far away from the Siren as possible.\n\n$bullet; Keep moving to avoid being hit by |cFF2959D3|Hspell:284262|h[Voltaic Flash]|h|r.",-1,0,0,4,2337,19255,3,19252,0},
    {19255,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; If affected by |cFF2959D3|Hspell:284405|h[Tempting Song]|h|r, try to position yourself as far away from the Siren as possible.\n\n$bullet; Keep moving to avoid being hit by |cFF2959D3|Hspell:284262|h[Voltaic Flash]|h|r.\n\n$bullet; Use |cFF2959D3|Hspell:285350|h[Storm's Wail]|h|r to remove |cFF2959D3|Hspell:285075|h[Freezing Tidepools]|h|r.",-1,0,0,2,2337,0,4,19252,0},
