    {19362,nil,0,2,286379,0,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, this ability instantly kills the victim.$]",-1,19606,0,80,2323,19289,20,19200,0},
    {19363,"Overview",0,3,0,0,{"wago"},"Grong the Revenant will |cFF2959D3|Hspell:282399|h[Death Knell]|h|r when hit by |cFF2959D3|Hspell:286435|h[Discharge Necrotic Core]|h|r or when his Death Energy reaches 100.",-1,19364,0,0,2340,19367,1,0,0},
    {19364,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Interupt and kill Death Specters as fast as possible to decrease the amount of Death Energy gained.\n\n$bullet;Stay near allies to avoid being feared by |cFF2959D3|Hspell:285994|h[Ferocious Roar]|h|r",-1,0,0,2,2340,19365,2,19363,0},
    {19365,"Healers",0,3,0,0,{"wago"},"$bullet;Stay near allies to avoid being feared by |cFF2959D3|Hspell:285994|h[Ferocious Roar]|h|r.\n\n$bullet; If Grong's Death Energy is above 75, use cooldowns to handle |cFF2959D3|Hspell:282399|h[Death Knell]|h|r.",-1,0,0,4,2340,19366,3,19363,0},
    {19366,"Tanks",0,3,0,0,{"wago"},"$bullet;Stay near allies to avoid being feared by |cFF2959D3|Hspell:285994|h[Ferocious Roar]|h|r.\n\n$bullet;Avoid taking two |cFF2959D3|Hspell:283078|h[Bestial Smash]|h|r in a row.",-1,0,0,1,2340,0,4,19363,0},
    {19367,"Section 5",0,2,282399,0,{"wago"},nil,-1,19368,0,32,2340,19781,5,0,0},
