    {19425,"Empowering the storm",0,0,0,0,{"wago"},"Throughout the course of the fight, Laminaria receives energy from various sources. When Laminaria reaches 100 Energy, |cFF2959D3|Hspell:284760|h[Catastrophic Tides]|h|r is cast.",-1,19322,0,16,2337,19257,5,0,0},
    {19427,"Section 46",0,2,287995,0,{"wago"},"${\n\n\n\nAfter casting |cFF2959D3|Hspell:287995|h[Electric Shroud]|h|r, each tidepriest will cast |cFF2959D3|Hspell:284765|h[Tidal Empowerment]|h|r.",-1,19271,0,32,2337,19428,12,19261,0},
