    {19537,"Section 46",0,2,286558,0,{"wago"},"${\n\n\n\nAfter casting |cFF2959D3|Hspell:286558|h[Tidal Shroud]|h|r, each tidepriest will cast |cFF2959D3|Hspell:287887|h[Storm's Empowerment]|h|r.",-1,19538,0,32,2337,19539,22,19262,0},
