    {19891,"Dormant Polyp",0,2,292205,0,{"wago"},nil,-1,19961,0,32,2347,0,7,19902,0},
    {19892,"Overview",0,3,0,0,{"wago"},"Over the course of the encounter the Head Machinist activates the garden's defenses to stop the intruders.",-1,19893,0,0,2348,19899,1,0,0},
    {19893,"Tanks",0,3,0,0,{"wago"},"$bullet;Avoid touching |cFF2959D3|Hspell:284885|h[Self-Trimming Hedge]|h|r blades.\n\n$bullet;At 100 energy, the Head Machinist activates the |cFF2959D3|Hspell:285443|h[\"Hidden\" Flame Cannon]|h|r.",-1,0,0,1,2348,19894,2,19892,0},
    {19894,"Healers",0,3,0,0,{"wago"},"$bullet;Dispel allies who fail to avoid |cFF2959D3|Hspell:285460|h[Discom-BOMB-ulator]|h|r.\n\n$bullet;Avoid touching |cFF2959D3|Hspell:284885|h[Self-Trimming Hedge]|h|r blades.\n\n$bullet;At 100 energy, the Head Machinist activates the |cFF2959D3|Hspell:285443|h[\"Hidden\" Flame Cannon]|h|r.",-1,0,0,4,2348,19895,3,19892,0},
    {19895,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid touching |cFF2959D3|Hspell:284885|h[Self-Trimming Hedge]|h|r blades.\n\n$bullet;At 100 energy, the Head Machinist activates the |cFF2959D3|Hspell:285443|h[\"Hidden\" Flame Cannon]|h|r.",-1,0,0,2,2348,0,4,19892,0},
    {19896,"Garden Gadgets",0,0,0,0,{"wago"},nil,-1,19897,0,32,2348,0,7,0,0},
