    {19977,"Section 8",0,2,292971,1,{"wago"},"${\n\n$[!15, 16\n\nOn Heroic Difficulty and Mythic Difficulty,|r being affected by |cFF2959D3|Hspell:294652|h[Quivering Claws]|h|r also increases hysteria, $]",-1,0,0,0,2349,19983,8,0,0},
