    {19979,"Stage Two: Grip of Fear",0,0,0,0,{"wago"},"Za'qul pulls players into the Fear Realm at 85% health.",-1,19982,0,0,2349,19980,23,0,0},
    {19980,"Stage Three: Delirium's Descent",0,0,0,0,{"wago"},"Za'qul begins pulling players into the Delirium Realm at 70% health.",-1,20509,0,0,2349,19981,38,0,0},
    {19981,"Stage Four: All Pathways Open",0,0,0,0,{"wago"},"When Za'qul reaches 60% health, Thalyssra returns players to reality.",-1,20296,0,0,2349,0,48,0,0},
    {19982,"Section 13",0,2,295173,0,{"wago"},nil,-1,0,0,0,2349,20467,24,19979,0},
    {19983,"Stage One: The Harbinger",0,0,0,0,{"wago"},nil,-1,20086,0,0,2349,19979,9,0,0},
    {19984,"Horrific Vision",0,1,0,0,{"wago"},"Periodically emerge from Dark Tears as long as they remain open.",-1,19985,84871,0,2349,0,15,20173,0},
