    {20377,"Overview",0,3,0,0,{"wago"},"Ulmath is a powerful Merciless One with ultimate control of two minions, Moon Priestess Liara and Guardian Tannin.",-1,20378,0,0,2362,20386,1,0,0},
    {20378,"Tanks",0,3,0,0,{"wago"},"$bullet;Reposition targets to mitigate incidental damage from |cFF2959D3|Hspell:301840|h[Void Dance]|h|r.\n\n$bullet;Keep Ulmath's minions within $301657s3 yards of Ulmath to avoid |cFF2959D3|Hspell:301657|h[Soul Tether]|h|r.\n\n$bullet;Avoid |cFF2959D3|Hspell:301840|h[Void Dance]|h|r and flee from |cFF2959D3|Hspell:301774|h[Mental Collapse]|h|r.",-1,0,0,1,2362,20379,2,20377,0},
    {20379,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:301840|h[Void Dance]|h|r and |cFF2959D3|Hspell:301774|h[Mental Collapse]|h|r can cause significant, avoidable raid damage.\n\n$bullet;Avoid |cFF2959D3|Hspell:301840|h[Void Dance]|h|r and flee from |cFF2959D3|Hspell:301774|h[Mental Collapse]|h|r.",-1,0,0,4,2362,20380,3,20377,0},
    {20380,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:301653|h[Forlorn Fate]|h|r causes Ulmath and his minions to share damage taken.\n\n$bullet;Avoid |cFF2959D3|Hspell:301840|h[Void Dance]|h|r and flee from |cFF2959D3|Hspell:301774|h[Mental Collapse]|h|r.",-1,0,0,2,2362,0,4,20377,0},
