    {20434,"Section 25",0,2,303206,1,{"wago"},nil,-1,0,0,16,2355,0,16,20040,0},
    {20435,"Overview",0,3,0,0,{"wago"},"Wekemara utilizies bioelectricity to unleash devastating attacks on its enemies.",-1,20436,0,0,2363,20439,1,0,0},
    {20436,"Healers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:303451|h[Electric Discharge]|h|r and |cFF2959D3|Hspell:303488|h[Shock Burst]|h|r inflict substantial damage to all allies.\n\n$bullet; |cFF2959D3|Hspell:303319|h[Bioelectric Blast]|h|r inflicts massive damage to all targets caught in the impact.\n\n$bullet; Move away from allies when affected by |cFF2959D3|Hspell:303488|h[Shock Burst]|h|r.",-1,0,0,4,2363,20437,2,20435,0},
    {20437,"Tanks",0,3,0,0,{"wago"},"$bullet; Prevent Spawn of Wekemara from attacking allies.\n\n$bullet; |cFF2959D3|Hspell:303319|h[Bioelectric Blast]|h|r inflicts massive damage to all targets caught in the impact.\n\n$bullet; Move away from allies when affected by |cFF2959D3|Hspell:303488|h[Shock Burst]|h|r.",-1,0,0,1,2363,20438,3,20435,0},
    {20438,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Defeat Spawn of Wekemara to force Wekemara to emerge.\n\n$bullet; |cFF2959D3|Hspell:303319|h[Bioelectric Blast]|h|r inflicts massive damage to all targets caught in the impact.\n\n$bullet; Move away from allies when affected by |cFF2959D3|Hspell:303488|h[Shock Burst]|h|r.",-1,0,0,2,2363,0,4,20435,0},
