    {20580,"Synthesis Growth",0,1,0,2,{"wago"},"$[!16In Mythic difficulty, Synthesis Growths expel $310739s1 Nightmare Antigens upon death.$]",0,20688,93174,4128,2366,21006,68,20566,0},
