    {20592,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Utilize |cFF2959D3|Hspell:307839|h[Devoured Abyss]|h|r to escape the effects of |cFF2959D3|Hspell:308044|h[Stygian Annihilation]|h|r.\n\n$bullet;Quickly break Maut's |cFF2959D3|Hspell:306005|h[Obsidian Skin]|h|r before it completes its cast of |cFF2959D3|Hspell:305722|h[Obsidian Shatter]|h|r.\n\n$bullet;Destroy Dark Manifestations before they're able to aid Maut.\n\n$bullet;Remove |cFF2959D3|Hspell:314337|h[Ancient Curse]|h|r before the curse becomes deadly.",0,0,0,2,2365,20593,5,20551,0},
    {20593,"Healers",0,3,0,2,{"wago"},"$bullet;Utilize |cFF2959D3|Hspell:307839|h[Devoured Abyss]|h|r to escape the effects of |cFF2959D3|Hspell:308044|h[Stygian Annihilation]|h|r.",0,0,0,4,2365,21348,6,20551,0},
    {20594,"Stage One: Obsidian Destroyer",0,0,0,1,{"wago"},"Maut |cFF2959D3|Hspell:307805|h[Devours Magic]|h|r from players while wielding powerful Shadow magic.\n\n\n\nUpon reaching full mana Maut transforms into an obsidian statue.",-1,20596,0,0,2365,20553,9,0,0},
    {20596,"Section 7",0,2,307805,0,{"wago"},nil,-1,20748,0,32,2365,21137,10,20594,0},
