    {20663,"Fanatical Cultist",0,1,0,0,{"wago"},"A common cultist with weak melee attacks.",-1,20943,93176,0,2370,20674,17,20678,0},
    {20664,"Stygian Destruction",0,2,308158,0,{"wago"},nil,-1,0,0,0,2365,20600,20,20594,0},
    {20665,"Section 8",0,2,307297,0,{"wago"},nil,-1,20689,0,1,2370,20682,8,20661,0},
    {20667,"Stage Two: Death From Above",0,0,0,1,{"wago"},"Upon reaching 100 energy, Vexiona takes off and assaults players from the air.\n\n\n\nAfter casting Twilight Decimator three times, she lands and resumes summoning Cultists.",-1,20668,0,0,2370,20669,27,0,0},
    {20668,"Section 12",0,2,307218,0,{"wago"},nil,-1,21191,0,16,2370,20681,28,20667,0},
    {20669,"Stage Three: The Void Unleashed",0,0,0,1,{"wago"},"When Vexiona reaches $307453s1% health, she stops summoning Cultists and unleashes the full extent of her power.",-1,21224,0,0,2370,0,36,0,0},
    {20672,"Section 7",0,2,307784,0,{"wago"},nil,-1,0,0,0,2369,20673,23,20650,0},
