    {20674,"Spellbound Ritualist",0,1,0,0,{"wago"},"A spell-slinging cultist who prefers to assault players from afar.",-1,20675,93185,0,2370,20676,19,20678,0},
    {20675,"Section 16",0,2,307177,0,{"wago"},nil,-1,0,0,64,2370,0,20,20674,0},
    {20676,"Sinister Soulcarver",0,1,0,2,{"wago"},"An elusive cultist who slips away to attack from unexpected angles.",0,20883,93180,8,2370,21195,21,20678,0},
    {20678,nil,0,2,307057,1,{"wago"},nil,-1,20663,0,0,2370,0,16,20661,0},
