    {20684,"Void Ascendant",0,1,0,0,{"wago"},"At the beginning of the encounter, Vexiona is accompanied by a powerful Void Ascendant.",-1,20687,92689,32,2370,20678,12,20661,0},
    {20685,"Section 21",0,2,307317,0,{"wago"},nil,-1,20686,0,0,2370,20665,6,20661,0},
