    {20722,"Section 11",0,2,313441,0,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, pools of acid seep from Acidic Aqir eggs before hatching.$]",-1,21068,0,0,2372,20734,15,20710,0},
