    {21433,"Stage One: Writhing Onslaught",0,0,0,2,{"wago"},"N'Zoth defends hismelf with a mass of tentacles, while some players brave N'Zoth's most coercive visions to weaken the Corruptor from inside his mind.",0,21468,0,0,2375,21434,82,0,0},
    {21434,"Stage Two: Convergence",0,0,0,2,{"wago"},"N'Zoth bends reality, converging Ny'alotha and the Chamber of Heart on Azeroth. With the Chamber in his grasp, N'Zoth begins to fulfill his ultimate purpose: bringing the Black Empire to fruition on Azeroth.",0,20759,0,0,2375,21435,133,0,0},
    {21435,"Stage Three: Forge of Fate",0,0,0,2,{"wago"},"As N'Zoth the Corruptor's tentacles tighten on the Chamber of Heart, Magni and MOTHER begin unleashing the fury of the Forge of Origination to put an end to the Corruptor's plans.\n\n\n\nOr, so they hope.",0,0,0,0,2375,0,144,0,0},
