    {21618,"Overview",0,3,0,0,{"wago"},"Dealer Xy'Exa uses arcane broker technology to create portals and magical explosions that damage and displace her enemies. Since she considers her cunning unrivaled, there's no way her magic could be used against her.",-1,21619,0,0,2398,21627,1,0,0},
    {21619,"Tank",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:319619|h[Displacement Trap]|h|r teleports the triggering player high up into the air.\n\n$bullet; |cFF2959D3|Hspell:319619|h[Displacement Trap]|h|r targets everyone in the group.",-1,0,0,1,2398,21621,2,21618,0},
    {21620,"Healer",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:319619|h[Displacement Trap]|h|r teleports the triggering player high up into the air.\n\n$bullet; |cFF2959D3|Hspell:321948|h[Localized Explosive Contrivance]|h|r inflicts heavy damage to its target.",-1,0,0,4,2398,0,4,21618,0},
    {21621,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:319619|h[Displacement Trap]|h|r teleports the triggering player high up into the air.",-1,0,0,2,2398,21620,3,21618,0},
