    {21737,"Overview",0,3,0,0,{"wago"},"Stradama sinks beneath the ooze at health thresholds of 66% and 33%, unleashing tentacles that assault the party with |cFF2959D3|Hspell:322473 |h[Plague Crash]|h|r.",-1,21739,0,0,2404,21744,1,0,0},
    {21738,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Defeat Malignant Spawn before they overwhelm the party with |cFF2959D3|Hspell:322236 |h[Touch of Slime]|h|r .\n\n$bullet;Avoid the tentacles during |cFF2959D3|Hspell:322473 |h[Plague Crash]|h|r.",-1,0,0,2,2404,21740,3,21737,0},
    {21739,"Tank",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:322304 |h[Touch of Slime]|h|r inflicts heavy party wide damage upon striking no players.\n\n$bullet;Avoid the tentacles during |cFF2959D3|Hspell:322473 |h[Plague Crash]|h|r.",-1,0,0,1,2404,21738,2,21737,0},
