    {21764,"Overview",0,3,0,0,{"wago"},"General Kaal is agile around the battlefield, working to weaken all of her opponents and removing them from the battlefield entirely. Upon reaching 50% health, General Kaal ends the fight and prepares to drag her opponents back into the depths for eons of imprisonment.",-1,21765,0,0,2407,21770,1,0,0},
    {21765,"Tank",0,3,0,0,{"wago"},"$bullet;Position yourself for |cFF2959D3|Hspell:322895|h[Gloom Squall]|h|r.\n\n$bullet;Avoid |cFF2959D3|Hspell:323810|h[Piercing Blur]|h|r.",-1,0,0,1,2407,21766,2,21764,0},
    {21766,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;Avoid |cFF2959D3|Hspell:323810|h[Piercing Blur]|h|r.\n\n$bullet;Spread out for |cFF2959D3|Hspell:323845|h[Wicked Rush]|h|r.\n\n$bullet;Position yourself for |cFF2959D3|Hspell:322895|h[Gloom Squall]|h|r.",-1,0,0,2,2407,21767,3,21764,0},
    {21767,"Healer",0,3,0,0,{"wago"},"$bullet;Position yourself for |cFF2959D3|Hspell:322895|h[Gloom Squall]|h|r.\n\n$bullet;Avoid |cFF2959D3|Hspell:323810|h[Piercing Blur]|h|r.",-1,0,0,4,2407,0,4,21764,0},
