    {21836,"Stage Two: To the Skies",0,0,0,1,{"wago"},"Devos |cFF2959D3|Hspell:323011|h[Activates]|h|r the Anima Conduit, then takes to the skies until she is hit by the Archon's Spear.",-1,21822,0,0,2412,0,14,0,0},
