    {21897,"Overview",0,3,0,0,{"wago"},"Mordretha wields the forces of Death to overwhelm her opponents, haunting players and tearing open rifts that drag players towards them.",-1,21898,0,0,2417,22486,1,0,0},
    {21898,"Tank",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:324079|h[Reaping Scythe]|h|r inflicts heavy Phsyical and Shadow damage.\n\n$bullet; Avoid inflicting additional damage to allies with |cFF2959D3|Hspell:324449|h[Manifest Death]|h|r.\n\n$bullet; Do not allow yourself to be dragged into a |cFF2959D3|Hspell:323685|h[Grasping Rift]|h|r.",-1,0,0,1,2417,21900,2,21897,0},
    {21899,"Healer",0,3,0,0,{"wago"},"$bullet; Avoid inflicting additional damage to allies with |cFF2959D3|Hspell:324449|h[Manifest Death]|h|r.\n\n$bullet; Do not allow yourself to be dragged into a |cFF2959D3|Hspell:323685|h[Grasping Rift]|h|r.",-1,0,0,4,2417,0,4,21897,0},
