    {21909,"Section 9",0,2,324449,0,{"wago"},"$[!23\n\n\n\nIn Mythic difficulty, each player summons a Deathwalker at their location when Manifest Death expires.$]",-1,21910,0,0,2417,21901,11,0,0},
