    {21968,"Section 26",0,2,325877,0,{"wago"},"$[!14,15,16\n\n\n\nOn Normal difficulty and higher, this also applies $341241s3 applications |cFF2959D3|Hspell:326430|h[Lingering Embers]|h|r, divided among all players hit.$]",-1,22025,0,0,2422,22543,12,21966,0},
