    {21979,"Section 7",0,2,325908,0,{"wago"},nil,-1,0,0,4,2420,21978,22,22576,0},
    {21981,"Bottled Anima",0,2,342281,0,{"wago"},"$[!14,15,16,17\n\n\n\nLady Inerva Darkvein uses this ability when the Container of Bottled Anima surpasses 33% capacity.$]",-1,21982,0,0,2420,22595,27,22592,0},
    {21982,"Section 10",0,2,329618,0,{"wago"},nil,-1,0,0,16,2420,22421,28,21981,0},
    {21983,"Primal Anima Orbs",0,2,342288,0,{"wago"},"$[!14,15,16,17\n\n\n\nLady Inerva Darkvein uses this ability when the Container of Sin surpasses 33% capacity.$]$[!14,15,16\n\n\n\nIf players fail to connect Sins of the Past before they expire, |cFF2959D3|Hspell:331527|h[Indemnification]|h|r occurs.$]",-1,21984,0,0,2420,22604,38,22599,0},
    {21984,"Section 12",0,2,324983,0,{"wago"},"$[!17\n\n\n\nIn Raid Finder difficulty, victims are Silenced until they sever the connection of Shared Suffering by linking the Sins of the Past.$]",-1,0,0,0,2420,22493,39,21983,0},
    {21985,"Section 27",0,2,326455,0,{"wago"},nil,-1,21986,0,1,2422,21968,10,21966,0},
    {21986,"Section 28",0,2,326456,0,{"wago"},nil,-1,0,0,1,2422,0,11,21985,0},
