    {21993,"Bleakwing Assassin",0,1,0,0,{"wago"},nil,-1,21994,96609,0,2422,21952,28,21951,0},
    {21994,"Section 30",0,2,341473,1,{"wago"},nil,-1,0,0,8192,2422,22265,29,21993,0},
    {21995,"Overview",0,3,0,0,{"wago"},"At full energy, Domina orders Brood Assassins concealed in |cFF2959D3|Hspell:332397|h[Shroudweb]|h|r to join the fight. Brood Assassins cast |cFF2959D3|Hspell:333406|h[Assassinate]|h|r until they are revealed from stealth.",-1,21998,0,0,2423,22274,1,0,0},
    {21996,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:332313|h[Brood Assassins]|h|r cast |cFF2959D3|Hspell:333406|h[Assassinate]|h|r until they are revealed.\n\n\n\n$bullet;Beware of nearby allies when targeted by |cFF2959D3|Hspell:325245|h[Shadow Ambush]|h|r.",-1,0,0,2,2423,21997,3,21995,0},
    {21997,"Healer",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:333406|h[Assassinate]|h|r inflicts heavy damage over time.\n\n\n\n$bullet;|cFF2959D3|Hspell:325552|h[Cytotoxic Slash]|h|r greatly increases damage taken by |cFF2959D3|Hspell:333406|h[Assassinate]|h|r and |cFF2959D3|Hspell:325551|h[Venomblades]|h|r.\n\n\n\n$bullet;Beware of your nearby allies when targeted by |cFF2959D3|Hspell:325245|h[Shadow Ambush]|h|r.",-1,0,0,4,2423,0,4,21995,0},
    {21998,"Tank",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:332313|h[Brood Assassins]|h|r cast |cFF2959D3|Hspell:333406|h[Assassinate]|h|r until they are revealed.\n\n\n\n$bullet;|cFF2959D3|Hspell:325552|h[Cytotoxic Slash]|h|r greatly increases damage taken by |cFF2959D3|Hspell:333406|h[Assassinate]|h|r and |cFF2959D3|Hspell:325551|h[Venomblades]|h|r.",-1,0,0,1,2423,21996,2,21995,0},
