    {22442,"Healers",0,3,0,0,{"wago"},"$bullet;Dodge |cFF2959D3|Hspell:327246|h[Anima Charge]|h|r.\n\n$bullet;Stay spread out to avoid chaining |cFF2959D3|Hspell:327262|h[Charged Anima Blast]|h|r.",-1,0,0,4,2430,0,4,22439,0},
