    {22567,"Container of Concentrated Anima",3684827,0,0,0,{"wago"},"The Container of Concentrated Anima governs the power of Lady Inerva Darkvein's Concentrated Anima ability.\n\n\n\nAs the container increases in level, the power of Concentrated Anima increases.\n\n\n\nEach cast of Concentrated Anima results in one Harnessed Specter. Any additional players chosen for this ability cause a Conjured Manifestation to appear.",-1,22608,0,0,2420,0,46,0,0},
    {22571,"Container of Desire",3684826,0,0,0,{"wago"},"The Container of Desire governs the power of Lady Inerva Darkvein's Expose Desires ability.\n\n\n\nAs the container increases in level, the power of Expose Desires increases.\n\n\n\nLady Inerva Darkvein uses these abilities when she reaches 100 energy.",-1,22573,0,0,2420,22592,11,0,0},
