    {22952,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Interrupt Organs of Corruption casting |cFF2959D3|Hspell:310788|h[Pumping Blood]|h|r\n\n$bullet;Defeat Bloods of Ny'alotha when your raid has enough health to survive |cFF2959D3|Hspell:311143|h[Hemorrhage]|h|r\n\n$bullet;Reduce allies to <30% health when they are afflicted with |cFF2959D3|Hspell:311401|h[Touch of the Corruptor]|h|r",0,0,0,2,2374,20752,4,20749,0},
