    {22990,"Stage Two",0,0,0,1,{"wago"},"Once pulled into the arena, Surgeon Stitchflesh joins the fray with his murderous cleaver.",-1,22807,0,0,2392,0,15,0,0},
    {22991,"Stage One",0,0,0,1,{"wago"},"Surgeon Stitchflesh assaults enemies from the safety of his worktable.",-1,21992,0,0,2392,22990,5,0,0},
