    {23057,"Stage One: A Cycle of Hatred",0,0,0,1,{"wago"},"\"We have forgotten what makes us strong.\"\n\n\n\nPlayers battle against Sylvanas atop Torghast while the Jailer remains elusive.",-1,23257,0,0,2441,22891,5,0,0},
