    {24934,"Section 9",0,2,372719,0,{"wago"},nil,-1,0,0,16,2484,27130,7,24935,0},
    {24935,"Section 10",0,2,372716,3,{"wago"},nil,2,24930,0,32,2484,24931,5,0,0},
    {24936,"Overview",0,3,0,0,{"wago"},"Throughout the fight, Kokia alternates between hurling |cFF2959D3|Hspell:372107|h[Molten Boulder]|h|r at players and pummeling her target with |cFF2959D3|Hspell:372859|h[Searing Blows]|h|r.\n\n\n\nUpon reaching 100 energy, Kokia summons a Blazebound Firestorm that casts |cFF2959D3|Hspell:373087|h[Burnout]|h|r when defeated.",-1,24937,0,0,2485,24944,1,0,0},
    {24937,"Tank",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:373017|h[Roaring Blaze]|h|r damages the entire party unless interrupted.\n\n$bullet;|cFF2959D3|Hspell:372859|h[Searing Blows]|h|r applies additional |cFF2959D3|Hspell:372860|h[Searing Wounds]|h|r with each hit.",-1,0,0,1,2485,24938,2,24936,0},
    {24938,"Damage Dealers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:373017|h[Roaring Blaze]|h|r damages the entire party unless interrupted.\n\n$bullet;|cFF2959D3|Hspell:372107|h[Molten Boulder]|h|r inflicts heavy Fire damage and stuns any player it hits.",-1,0,0,2,2485,24939,3,24936,0},
    {24939,"Healer",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:373017|h[Roaring Blaze]|h|r damages the entire party unless interrupted.\n\n$bullet;|cFF2959D3|Hspell:372859|h[Searing Blows]|h|r can inflict significant damage to the tank in a very short time.\n\n$bullet;|cFF2959D3|Hspell:372107|h[Molten Boulder]|h|r inflicts heavy Fire damage and stuns any player it hits.",-1,0,0,4,2485,0,4,24936,0},
    {24940,"Molten Boulder",0,2,372107,0,{"wago"},"$[!23\n\n\n\nOn Mythic difficulty, this ability leaves behind Scorched Earth.$]",-1,24941,0,0,2485,24942,11,0,0},
