    {25026,"Heated Slam",4374708,2,374535,0,{"wago"},nil,-1,25574,0,1,2489,0,12,0,0},
    {25028,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; When broken, |cFF2959D3|Hspell:374482|h[Grounding Chain]|h|r will cause |cFF2959D3|Hspell:389080|h[Fetter]|h|r.\n\n$bullet; |cFF2959D3|Hspell:373424|h[Grounding Spear]|h|r leaves behind |cFF2959D3|Hspell:374854|h[Erupted Ground]|h|r where it strikes the floor.",0,0,0,2,2490,0,7,26041,0},
    {25029,"Healers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:373733|h[Dragon Strike]|h|r inflicts high damage and causes the target to bleed.\n\n$bullet; When broken, |cFF2959D3|Hspell:374482|h[Grounding Chain]|h|r will cause |cFF2959D3|Hspell:395656|h[Slag Eruption]|h|r.",0,0,0,4,2490,26044,5,26041,0},
    {25030,"Tanks",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:375056|h[Fiery Focus]|h|r inflicts heavy damage and can be interrupted with |cFF2959D3|Hspell:389080|h[Fetter]|h|r.\n\n$bullet; |cFF2959D3|Hspell:373767|h[Magma Wave]|h|r travels out in a straight line in front of Chargath.",0,0,0,1,2490,26043,3,26041,0},
    {25032,"Overview",0,3,0,0,{"wago"},"Kurog Grimtotem gains increasing dominance over an element while nearby its altar within The Primal Convergence. Upon reaching 100 energy, Kurog summons two elementals according to his levels of elemental dominance.\n\n\n\nAfter summoning forth an elemental from each altar, Kurog achieves |cFF2959D3|Hspell:396241|h[Primal Attunement]|h|r.",-1,25033,0,0,2491,25036,1,0,0},
    {25033,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Earth Breakers continually cast |cFF2959D3|Hspell:377780|h[Skeletal Fractures]|h|r.\n\n$bullet;The longer Kurog's elementals remain alive, the more damage they do.",0,0,0,2,2491,25994,2,25032,0},
    {25034,"Healers",0,3,0,2,{"wago"},"$bullet;While next to a Primal Altar, Kurog Grimtotem continually inflicts that altar's elemental damage to all players.",0,0,0,4,2491,25996,4,25032,0},
    {25035,"Tanks",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:372158|h[Sundering Strike]|h|r applies stacking Physical damage over time.\n\n$bullet;While not next to an active Primal Altar, Kurog Grimtotem casts |cFF2959D3|Hspell:371971|h[Elemental Surge]|h|r.",0,0,0,1,2491,25995,6,25032,0},
    {25036,"Stage One: Elemental Dominance",0,0,0,1,{"wago"},"Kurog gains new abilities while near an elemental altar in The Primal Convergence.",-1,26083,0,0,2491,25071,8,0,0},
