    {25200,"Generic",0,2,375943,2,{"wago"},"$[!23\n\n\n\nOn Mythic difficulty, Upheaval causes a Quake at each player's location.$]",0,25196,0,4096,2477,25188,9,25185,0},
    {25201,"Generic",0,2,376683,1,{"wago"},nil,-1,0,0,0,2477,0,7,25197,0},
    {25202,"Generic",0,2,376892,2,{"wago"},nil,3,0,0,0,2477,25974,22,25187,0},
    {25203,"Overview",0,3,0,0,{"wago"},"Nesting on the sporting grounds of the old academy, Crawth loudly and violently objects to those that would reclaim the space. Unbeknownst to the massive bird, the goals of the ancient arena still contain some of their original power...",-1,25204,0,0,2495,25210,1,0,0},
    {25204,"Tanks",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:376997|h[Savage Peck]|h|r inflicts high damage over time.\n\n$bullet; Scoring goals during |cFF2959D3|Hspell:377182|h[Play Ball!]|h|r can activate the field's |cFF2959D3|Hspell:376448|h[Firestorm]|h|r or |cFF2959D3|Hspell:376467|h[Gale Force]|h|r.\n\n$bullet; |cFF2959D3|Hspell:377034|h[Overpowering Gust]|h|r knocks away players in front of Crawth.",-1,0,0,1,2495,25205,2,25203,0},
    {25205,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Scoring goals during |cFF2959D3|Hspell:377182|h[Play Ball!]|h|r can activate the field's |cFF2959D3|Hspell:376448|h[Firestorm]|h|r or |cFF2959D3|Hspell:376467|h[Gale Force]|h|r.\n\n$bullet; |cFF2959D3|Hspell:377034|h[Overpowering Gust]|h|r knocks away players in front of Crawth.\n\n$bullet; |cFF2959D3|Hspell:377004|h[Deafening Screech]|h|r interrupts spells and silences targets that are currently casting.",-1,0,0,2,2495,25206,3,25203,0},
    {25206,"Healers",0,3,0,0,{"wago"},"$bullet; Scoring goals during |cFF2959D3|Hspell:377182|h[Play Ball!]|h|r can activate the field's |cFF2959D3|Hspell:376448|h[Firestorm]|h|r or |cFF2959D3|Hspell:376467|h[Gale Force]|h|r.\n\n$bullet; |cFF2959D3|Hspell:377034|h[Overpowering Gust]|h|r knocks away players in front of Crawth.\n\n$bullet; |cFF2959D3|Hspell:377004|h[Deafening Screech]|h|r interrupts spells and silences targets that are currently casting.",-1,0,0,4,2495,0,4,25203,0},
    {25207,nil,0,2,377034,0,{"wago"},nil,-1,0,0,0,2495,25208,13,0,0},
