    {25306,"Section 11",0,2,376933,1,{"wago"},"$[!23,8\n\n\n\nOn Mythic difficulty, all players within 10 yards of Treemouth are consumed. If Treemouth fails to consume a player, it goes into a |cFF2959D3|Hspell:390968|h[Starving Frenzy]|h|r.$]",-1,25307,0,32,2473,25301,5,0,0},
    {25307,"Section 12",0,2,377222,0,{"wago"},"$[!23,8\n\n\n\nOn Mythic difficulty, the consumed player will become |cFF2959D3|Hspell:383875|h[Partially Digested]|h|r after being spit out.$]",-1,25380,0,4,2473,25339,6,25306,0},
