    {25653,"Overview",0,3,0,0,{"wago"},"The Echo of Doragosa assaults her enemies with powerful Arcane attacks, applying |cFF2959D3|Hspell:389011|h[Overwhelming Power]|h|r and creating |cFF2959D3|Hspell:388901|h[Arcane Rifts]|h|r.",-1,25654,0,0,2514,25778,1,0,0},
    {25654,"Tanks",0,3,0,0,{"wago"},"$bullet; Multiple applications of |cFF2959D3|Hspell:389011|h[Overwhelming Power]|h|r will create |cFF2959D3|Hspell:388901|h[Arcane Rifts]|h|r.\n\n$bullet; |cFF2959D3|Hspell:1282251|h[Astral Blast]|h|r inflicts heavy arcane damage and applies an application of |cFF2959D3|Hspell:389011|h[Overwhelming Power]|h|r.",-1,0,0,1,2514,25655,2,25653,0},
    {25655,"Healers",0,3,0,0,{"wago"},"$bullet; Multiple applications of |cFF2959D3|Hspell:389011|h[Overwhelming Power]|h|r will create |cFF2959D3|Hspell:388901|h[Arcane Rifts]|h|r.",-1,0,0,4,2514,25656,3,25653,0},
    {25656,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; Multiple applications of |cFF2959D3|Hspell:389011|h[Overwhelming Power]|h|r will create |cFF2959D3|Hspell:388901|h[Arcane Rifts]|h|r.\n\n$bullet;",-1,0,0,2,2514,0,4,25653,0},
    {25664,"Section 6",0,2,454365,2,{"wago"},nil,1,0,0,0,2514,29861,15,0,0},
