    {26356,"Section 18",0,2,402617,0,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, coming into contact with a player afflicted by Corrupting Shadow will trigger Volatile Shadowflame and apply Lingering Flames.$]",-1,26613,0,0,2529,0,39,26587,0},
