    {26412,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:401794|h[Withering Sandpools]|h|r inflict damage upon forming and then deny ground.\n\n$bullet; |cFF2959D3|Hspell:413105|h[Eon Shatter]|h|r and the resulting |cFF2959D3|Hspell:405970|h[Eon Fragments]|h|r inflict significant damage.",2,0,0,2,2521,27221,3,26415,0},
