    {27220,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:403486|h[Eon Residue]|h|r causes |cFF2959D3|Hspell:417480|h[Residue Blast]|h|r if it fails to hit a player.\n\n$bullet; |cFF2959D3|Hspell:413105|h[Eon Shatter]|h|r and the resulting |cFF2959D3|Hspell:405970|h[Eon Fragments]|h|r inflict significant damage.",0,0,0,2,2521,26412,2,26415,0},
    {27221,"Healers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:413013|h[Chronoshear]|h|r's healing absorption prevents dispelling of |cFF2959D3|Hspell:413041|h[Sheared Lifespan]|h|r.\n\n$bullet; |cFF2959D3|Hspell:403486|h[Eon Residue]|h|r causes |cFF2959D3|Hspell:417480|h[Residue Blast]|h|r if it fails to hit a player.",0,0,0,4,2521,26413,4,26415,0},
    {27222,"Tanks",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:413013|h[Chronoshear]|h|r increases incoming damage with |cFF2959D3|Hspell:413041|h[Sheared Lifespan]|h|r.\n\n$bullet; |cFF2959D3|Hspell:403486|h[Eon Residue]|h|r causes |cFF2959D3|Hspell:417480|h[Residue Blast]|h|r if it fails to hit a player.",0,0,0,1,2521,26414,6,26415,0},
    {27223,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:407406|h[Corrosion]|h|r causes |cFF2959D3|Hspell:418348|h[Corrupted Mind]|h|r upon expiration.\n\n$bullet; |cFF2959D3|Hspell:408029|h[Necrofrost]|h|r is vulnerable to damage.",0,0,0,2,2535,26543,2,26542,0},
    {27224,"Healers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:407406|h[Corrosion]|h|r causes |cFF2959D3|Hspell:418348|h[Corrupted Mind]|h|r upon expiration.\n\n$bullet; |cFF2959D3|Hspell:407978|h[Necrotic Winds]|h|r inflicts significant damage to all players.",0,0,0,4,2535,26544,4,26542,0},
    {27226,"Section 12",0,2,407406,2,{"wago"},nil,0,27295,0,32,2535,26563,9,26561,0},
    {27231,"Section 10",0,2,409456,2,{"wago"},nil,0,27232,0,6,2537,26646,16,0,0},
    {27232,"Section 14",0,2,409287,0,{"wago"},nil,-1,27233,0,0,2537,0,17,27231,0},
    {27233,"Section 21",0,2,414376,0,{"wago"},nil,-1,0,0,0,2537,0,18,27232,0},
    {27234,"Damage Dealers",0,3,0,2,{"wago"},"$bullet; |cFF2959D3|Hspell:409456|h[Earthsurge]|h|r inflicts increasing damage over time.\n\n$bullet; |cFF2959D3|Hspell:409261|h[Extinction Blast]|h|r inflicts lethal damage without Chromie's |cFF2959D3|Hspell:414330|h[Timeline Protection]|h|r.\n\n$bullet; |cFF2959D3|Hspell:414535|h[Stonecracker Barrage]|h|r inflicts lethal damage to Chromie unless players reduce its force.",0,0,0,2,2537,26578,2,26577,0},
    {27235,"Healers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:414535|h[Stonecracker Barrage]|h|r injures Chromie.\n\n$bullet; |cFF2959D3|Hspell:409456|h[Earthsurge]|h|r and |cFF2959D3|Hspell:414184|h[Cataclysmic Obliteration]|h|r radiate damaging energy waves.\n\n$bullet; |cFF2959D3|Hspell:409261|h[Extinction Blast]|h|r inflicts lethal damage without Chromie's |cFF2959D3|Hspell:414330|h[Timeline Protection]|h|r.",-1,0,0,4,2537,27236,4,26577,0},
    {27236,"Tanks",0,3,0,2,{"wago"},"$bullet; Intercepting |cFF2959D3|Hspell:414535|h[Stonecracker Barrage]|h|r saves allies from |cFF2959D3|Hspell:414604|h[Stonecrack]|h|r.\n\n$bullet; |cFF2959D3|Hspell:414075|h[Crushing Onslaught]|h|r rapidly increases the damage taken by Iridikron's target.\n\n$bullet; |cFF2959D3|Hspell:409635|h[Pulverizing Exhalation]|h|r causes creations of stone to erupt from the earth.",0,0,0,1,2537,26580,5,26577,0},
    {27237,"Overview",0,3,0,0,{"wago"},"Larodar summons |cFF2959D3|Hspell:417666|h[Fiery Treants]|h|r and |cFF2959D3|Hspell:418654|h[Scorching Roots]|h|r to spread |cFF2959D3|Hspell:417610|h[Burning Ground]|h|r. Upon reaching 100 energy, Larodar envelops the arena in flame with |cFF2959D3|Hspell:417634|h[Raging Inferno]|h|r.\n\n\n\nAfter 3 casts of |cFF2959D3|Hspell:417634|h[Raging Inferno]|h|r, Larodar channels |cFF2959D3|Hspell:421316|h[Consuming Flame]|h|r and transforms into the |cFF2959D3|Hspell:421998|h[Avatar of Ash]|h|r. |cFF2959D3|Hspell:427252|h[Falling Embers]|h|r fall from above as Larodar attempts to cleanse his enemies with |cFF2959D3|Hspell:421326|h[Flash Fire]|h|r.",-1,27238,0,0,2553,27241,1,0,0},
    {27238,"Tanks",0,0,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:418637|h[Furious Charge]|h|r applies |cFF2959D3|Hspell:423719|h[Nature's Fury]|h|r and inflicts less damage the further his target is.\n\n$bullet;|cFF2959D3|Hspell:421594|h[Smoldering Suffocation]|h|r prevents all healing received but drains health from nearby allies.\n\n$bullet;|cFF2959D3|Hspell:418653|h[Renewed Bramble Barriers]|h|r drastically reduce damage taken from |cFF2959D3|Hspell:417634|h[Raging Inferno]|h|r.",-1,0,0,1,2553,27240,2,27237,0},
    {27239,"Healers",0,0,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:417667|h[Charred Treants]|h|r transform into |cFF2959D3|Hspell:417668|h[Renewed Treants]|h|r and |cFF2959D3|Hspell:418655|h[Charred Brambles]|h|r transform into |cFF2959D3|Hspell:418653|h[Renewed Bramble Barriers]|h|r when healed to full.\n\n$bullet;|cFF2959D3|Hspell:418653|h[Renewed Bramble Barriers]|h|r drastically reduce damage taken from |cFF2959D3|Hspell:417634|h[Raging Inferno]|h|r.\n\n$bullet;|cFF2959D3|Hspell:425249|h[Dream Blossom]|h|r douses |cFF2959D3|Hspell:417610|h[Burning Ground]|h|r.\n\n$bullet;|cFF2959D3|Hspell:421326|h[Flash Fire]|h|r-afflicted players become |cFF2959D3|Hspell:427306|h[Encased in Ash]|h|r if the absorb expires.",0,0,0,4,2553,28233,5,27237,0},
    {27240,"Damage Dealers",0,0,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:417666|h[Fiery Treants]|h|r transform into |cFF2959D3|Hspell:417667|h[Charred Treants]|h|r and |cFF2959D3|Hspell:418657|h[Scorching Brambles]|h|r transform into |cFF2959D3|Hspell:418655|h[Charred Brambles]|h|r when killed.\n\n$bullet;|cFF2959D3|Hspell:418653|h[Renewed Bramble Barriers]|h|r drastically reduce damage taken from |cFF2959D3|Hspell:417634|h[Raging Inferno]|h|r.\n\n$bullet;|cFF2959D3|Hspell:425249|h[Dream Blossom]|h|r douses |cFF2959D3|Hspell:417610|h[Burning Ground]|h|r.",0,0,0,2,2553,28232,3,27237,0},
