    {28132,"Overview",0,3,0,0,{"wago"},"Angered by the Order of Night's failure to capture the Dawnbreaker, Speaker Shadowcrown joins the fray wielding powerful shadow magic. \n\n\n\nAt 50% and 1% health remaining Shadowcrown unleashes |cFF2959D3|Hspell:451026|h[Darkness Comes]|h|r in an attempt to destroy any players left aboard the Dawnbreaker.",-1,28133,0,0,2580,29724,1,0,0},
    {28133,"Healers",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:426734|h[Burning Shadows]|h|r applies |cFF2959D3|Hspell:426736|h[Shadow Shroud]|h|r when removed.\n\n$bullet;|cFF2959D3|Hspell:451026|h[Darkness Comes]|h|r kills any players left aboard the Dawnbreaker.\n\n$bullet;|cFF2959D3|Hspell:449042|h[Radiant Light]|h|r allows skyriding and mounting in combat.",3,0,0,4,2580,30214,2,28132,0},
    {28134,"Tanks",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:453212|h[Obsidian Beam]|h|r inflict high damage and rotates over its duration.\n\n$bullet;|cFF2959D3|Hspell:451026|h[Darkness Comes]|h|r kills any players left aboard the Dawnbreaker.\n\n$bullet;|cFF2959D3|Hspell:449042|h[Radiant Light]|h|r allows skyriding and mounting in combat.",0,0,0,1,2580,30216,5,28132,0},
    {28135,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:453212|h[Obsidian Beam]|h|r inflict high damage and rotates over its duration.\n\n$bullet;|cFF2959D3|Hspell:451026|h[Darkness Comes]|h|r kills any players left aboard the Dawnbreaker.\n\n$bullet;|cFF2959D3|Hspell:449042|h[Radiant Light]|h|r allows skyriding and mounting in combat.",0,0,0,2,2580,0,7,28132,0},
