    {28709,"Section 9",0,2,434926,0,{"wago"},nil,-1,0,0,0,2594,0,10,28708,0},
    {28710,"Overview",0,3,0,0,{"wago"},"Sikran's |cFF2959D3|Hspell:433475|h[Phase Blade]|h|r rips through the cosmos, and leaves behind a |cFF2959D3|Hspell:458272|h[Cosmic Simulacrum]|h|r which can then be destroyed by |cFF2959D3|Hspell:442428|h[Decimate]|h|r. \n\n\n\nUpon reaching 100 energy, Sikran casts |cFF2959D3|Hspell:456420|h[Shattering Sweep]|h|r, destroying all remaining |cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r",-1,28711,0,0,2599,28721,1,0,0},
    {28711,"Healers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r inflict light damage to all players while active.\n\n\n\n$bullet; Upon destruction,|cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r apply |cFF2959D3|Hspell:459273|h[Cosmic Shards]|h|r to all players.\n\n\n\n$bullet; |cFF2959D3|Hspell:433475|h[Phase Blades]|h|r inflicts heavy damage over time to all players hit and reduces healing taken.",-1,0,0,4,2599,28712,2,28710,0},
    {28712,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:433475|h[Phase Blades]|h|r leave behind |cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r for every player hit. \n\n\n\n$bullet; |cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r are destroyed after being hit by |cFF2959D3|Hspell:442428|h[Decimate]|h|r and |cFF2959D3|Hspell:456420|h[Shattering Sweep]|h|r.",-1,0,0,2,2599,28713,3,28710,0},
    {28713,"Tanks",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:439511|h[Captain's Flourish]|h|r inflicts light damage with |cFF2959D3|Hspell:435401|h[Expose]|h|r then finishes with |cFF2959D3|Hspell:432969|h[Phase Lunge]|h|r.\n\n\n\n$bullet; |cFF2959D3|Hspell:432969|h[Phase Lunge]|h|r inflcts heavy Physical and Shadow damage, and increases damage taken by |cFF2959D3|Hspell:432969|h[Phase Lunge]|h|r. \n\n\n\n$bullet; |cFF2959D3|Hspell:442428|h[Decimate]|h|r expels cosmic spears from the boss location and breaks all |cFF2959D3|Hspell:458272|h[Cosmic Simulacrums]|h|r hit.",-1,0,0,1,2599,0,4,28710,0},
    {28719,"Section 13",0,2,439559,0,{"wago"},nil,-1,0,0,0,2599,0,15,0,0},
    {28721,"Section 5",0,2,433475,1,{"wago"},"$[!15,16 \n\n \n\nOn Heroic and Mythic difficulties all players hit with Phase Blades will leave behind a Cosmic Simulacrum. $]",-1,30060,0,32,2599,28967,5,0,0},
    {28723,"Section 16",0,2,439511,0,{"wago"},nil,-1,28859,0,1,2599,28719,12,0,0},
