    {28790,"Tanks",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:435622|h[Let It Hail]|h|r detonates any remaining Cinderbrew Bombs.\n\n$bullet;|cFF2959D3|Hspell:436592|h[Cash Cannon]|h|r ignites nearby Cinderbrew Bombs, causing them to explode.",3,0,0,1,2589,28436,2,28435,0},
    {28791,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:435622|h[Let It Hail]|h|r detonates any remaining Cinderbrew Bombs.\n\n$bullet;|cFF2959D3|Hspell:436640|h[Burning Ricochet]|h|r bounces to nearby players and Cinderbrew Bombs.",3,0,0,2,2589,28437,4,28435,0},
    {28792,"Healers",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:435622|h[Let It Hail]|h|r detonates any remaining Cinderbrew Bombs and inflicts heavy Physical damage to all players.\n\n$bullet;|cFF2959D3|Hspell:436640|h[Burning Ricochet]|h|r inflicts heavy Fire damage over time to afflicted players.",3,0,0,4,2589,28438,6,28435,0},
