    {30360,"Section 83",0,2,440179,0,{"wago"},"$[!15\n\n\n\nOn Heroic difficulty, Anub'arash needs to charge through 2 Binding Web strands to be entangled.$]\n\n$[!16\n\n\n\nOn Mythic difficulty, Anub'arash needs to charge through 3 Binding Web strands to be entangled.$]",-1,0,0,32,2608,0,29,30359,0},
