    {31737,"Healers",0,0,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:468663|h[Elemental Calamity]|h|r and |cFF2959D3|Hspell:469715|h[Uncontrolled Burn]|h|r inflict persistent damage over time each time Mug'zee swaps which head is the |cFF2959D3|Hspell:466376|h[Head Honcho]|h|r.\n\n$bullet;Mug'Zee gains |cFF2959D3|Hspell:466385|h[Moxie]|h|r the longer each head is in command.",0,0,0,4,2645,30508,5,30505,0},
