    {31793,"Section 8",0,2,1218103,2,{"wago"},"$[!16\n\n\n\nIn Mythic difficulty, |cFF2959D3|Hspell:1221490|h[Fel-Singed]|h|r also increases the damage taken from |cFF2959D3|Hspell:1225127|h[Felblade]|h|r.$]",0,31794,0,4097,2688,33418,24,31792,0},
    {31794,"Section 9",0,2,1221490,2,{"wago"},nil,0,0,0,4096,2688,32361,25,31793,0},
    {31795,"Overview",0,3,0,0,{"wago"},"Rotmire catalyzes the growth of new fungal minions with |cFF2959D3|Hspell:1221622|h[Awaken Fungi]|h|r. \n\n\n\nUpon reaching 100 energy, Rotmire creates a |cFF2959D3|Hspell:1221637|h[Fungal Bloom]|h|r that grows |cFF2959D3|Hspell:1221965|h[Bursting Shrooms]|h|r from minions' corpses.",-1,31796,0,0,2711,31838,1,0,0},
    {31796,"Tanks",0,3,0,0,{"wago"},"$bullet; Rotmire inflicts heavy damage to his current target with |cFF2959D3|Hspell:1221781|h[Putrid Fist]|h|r.\n\n$bullet; |cFF2959D3|Hspell:1221637|h[Fungal Bloom]|h|r grows deadly |cFF2959D3|Hspell:1221965|h[Bursting Shrooms]|h|r from minions' corpses.",-1,0,0,1,2711,31797,2,31795,0},
    {31797,"Damage Dealers",0,3,0,0,{"wago"},"$bullet; |cFF2959D3|Hspell:1221622|h[Awaken Fungi]|h|r grows fungal minions from the earth.\n\n$bullet; |cFF2959D3|Hspell:1221637|h[Fungal Bloom]|h|r grows deadly |cFF2959D3|Hspell:1221965|h[Bursting Shrooms]|h|r from minions' corpses.",-1,0,0,2,2711,31798,3,31795,0},
    {31798,"Healers",0,3,0,0,{"wago"},"$bullet; Rotmire inflicts massive damage to all players with |cFF2959D3|Hspell:1221637|h[Fungal Bloom]|h|r.\n\n$bullet; |cFF2959D3|Hspell:1222088|h[Festering Vines]|h|r inflict heavy damage to several players.\n\n$bullet; The |cFF2959D3|Hspell:1222176|h[Rotting Pustules]|h|r leftover from |cFF2959D3|Hspell:1221787|h[Bursting Pustules]|h|r inflict steadily increasing damage over time.",-1,0,0,4,2711,0,4,31795,0},
