    {32337,"Section 25",0,2,1227809,2,{"wago"},"$[!15,16\n\n\n\nIn Heroic and Mythic difficulty, |cFF2959D3|Hspell:1227809|h[The Hunt]|h|r inflicts damage in an area around players along the path to her prey.$]",0,0,0,40,2688,33299,17,31792,0},
