    {32613,"Overview",0,3,0,0,{"wago"},"Cragpine calls upon the treants of Zul'Aman with |cFF2959D3|Hspell:1235131|h[Rootquake]|h|r as he shakes the earth beneath his feet.\n\n\n\nThe forest itself answers his call as he awakens |cFF2959D3|Hspell:1257906|h[Ancient Seeds]|h|r slumbering in the soil.",-1,32614,0,0,2782,34051,1,0,0},
    {32614,"Healers",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:1235131|h[Rootquake]|h|r inflicts heavy damage to all players.\n\n$bullet;Floating |cFF2959D3|Hspell:1257906|h[Ancient Seeds]|h|r inflict damage to nearby players.",-1,0,0,4,2782,32615,2,32613,0},
