    {32939,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;Players designated as |cFF2959D3|Hspell:1216508|h[Screw Ups]|h|r periodically drop drills at their location.\n\n$bullet;|cFF2959D3|Hspell:466235|h[Wire Transfer]|h|r inflicts significant damage to players standing within the effect",0,0,0,2,2653,30423,5,30421,0},
