    {32952,"Tanks",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:1228502|h[Overwhelming Power]|h|r continously stacks on Araz's current target.\n\n$bullet;|cFF2959D3|Hspell:1226260|h[Arcane Convergence]|h|r inflicts damage to the raid on completion.",0,0,0,1,2687,32367,5,32366,0},
    {32954,"Section 60",0,2,1240705,0,{"wago"},nil,-1,0,0,0,2687,32513,42,32397,0},
