    {34716,nil,0,3,0,1,{"wago"},nil,-1,35334,0,0,2870,35353,1,0,0},
    {34717,"Mythic Level 10",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:1271523|h[Fortified]|h|r or |cFF2959D3|Hspell:1271524|h[Tyrannical]|h|r becomes active. Rotates weekly.",-1,0,0,0,2870,34719,5,34716,0},
    {34718,"Mythic Level 12",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:1271525|h[Xal'atath's Guile]|h|r becomes active and |cFF2959D3|Hspell:461870|h[Xal'atath's Bargain]|h|r is removed.",-1,0,0,0,2870,35335,3,34716,0},
    {34719,"Mythic Level 7",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:1271523|h[Fortified]|h|r or |cFF2959D3|Hspell:1271524|h[Tyrannical]|h|r becomes active. Rotates weekly.",-1,0,0,0,2870,34720,6,34716,0},
    {34720,"Mythic Level 6",0,3,0,0,{"wago"},"$bullet;|cFF2959D3|Hspell:1284818|h[Lindormi's Guidance]|h|r is removed.\n\n\n\nCharacters with a tank specialization can speak with Lindormi near the The Timeways portal or at the end of a Keystone Dungeon to gain |cFF2959D3|Hspell:1295986|h[Lindormi's Glow]|h|r, which will continue to highlight enemy forces.",-1,0,0,0,2870,0,7,34716,0},
    {34722,"Xal'atath's Bargain: Pulsar",4914667,2,1272894,0,{"wago"},nil,-1,0,141206,0,2870,34725,12,34729,0},
    {34725,"Xal'atath's Bargain: Voidbound",4913234,2,1272895,0,{"wago"},nil,-1,0,141116,0,2870,34727,13,34729,0},
    {34727,"Xal'atath's Bargain: Devour",7137506,2,1272896,0,{"wago"},nil,-1,0,140398,0,2870,0,14,34729,0},
    {34729,"Xal'atath's Bargains",1728724,2,0,1,{"wago"},"Starting at Mythic Level 5, Xal'atath periodically offers bargains during a Mythic Keystone dungeon that empower enemies. Players can intercept these effects and harness the power for themselves. These affixes rotate weekly.",-1,34751,0,0,2870,34730,10,0,0},
    {34730,"Tyrannical and Fortified",135901,2,0,1,{"wago"},"These affixes further empower enemies in Mythic Keystone dungeons. One becomes active at Mythic Level 7 and the other at Mythic Level 10, rotating each week.",-1,34731,0,0,2870,34733,15,0,0},
    {34731,"Tyrannical",236401,2,0,0,{"wago"},"Bosses have 25% more health. Bosses and their minions inflict up to 15% increased damage.",-1,0,0,0,2870,34732,16,34730,0},
    {34732,"Fortified",463829,2,0,0,{"wago"},"Non-boss enemies have 20% more health and inflict up to 20% increased damage.",-1,0,0,0,2870,0,17,34730,0},
    {34733,"Xal'atath's Guile",1723989,2,0,1,{"wago"},"Xal'atath betrays players, revoking her bargains while making deaths subtract 15 seconds from time remaining.",-1,0,0,0,2870,0,18,0,0},
    {34734,"Fractured Image",0,1,0,1,{"wago"},nil,-1,33997,137185,0,2736,0,33,33446,0},
