    {35168,"Damage Dealers",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:1253977|h[Turbulent Arrows]|h|r knock players into the air when touched, removing |cFF2959D3|Hspell:1216042|h[Squall Leap]|h|r.\n\n$bullet;|cFF2959D3|Hspell:468429|h[Bullseye Windblast]|h|r creates an expanding ring of |cFF2959D3|Hspell:468442|h[Billowing Wind]|h|r.\n\n$bullet;|cFF2959D3|Hspell:1253986|h[Gust Shot]|h|r destroys any |cFF2959D3|Hspell:1282932|h[Storming Soulfonts]|h|r struck.",0,0,0,2,2658,30470,2,30469,0},
    {35169,"Healer",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:474528|h[Bolt Gale]|h|r inflicts heavy damage to the targeted player.\n\n$bullet;|cFF2959D3|Hspell:1253977|h[Turbulent Arrows]|h|r knock players into the air when touched, removing |cFF2959D3|Hspell:1216042|h[Squall Leap]|h|r.\n\n$bullet;|cFF2959D3|Hspell:1253986|h[Gust Shot]|h|r destroys any |cFF2959D3|Hspell:1282932|h[Storming Soulfonts]|h|r struck.",0,0,0,4,2658,30471,4,30469,0},
    {35170,"Tank",0,3,0,2,{"wago"},"$bullet;|cFF2959D3|Hspell:472662|h[Tempest Slash]|h|r knocks The Restless Heart's primary target away and briefly increases their Physical damage taken.\n\n$bullet;|cFF2959D3|Hspell:1253977|h[Turbulent Arrows]|h|r knock players into the air when touched, removing |cFF2959D3|Hspell:1216042|h[Squall Leap]|h|r.\n\n$bullet;|cFF2959D3|Hspell:1253986|h[Gust Shot]|h|r destroys any |cFF2959D3|Hspell:1282932|h[Storming Soulfonts]|h|r struck.",0,0,0,1,2658,30472,6,30469,0},
